-- Poems batch 311
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('5b9b56f2-931b-4db6-85bf-b46b0df75463','途中寄縣齋諸士子','韋驤','宋','宋诗','song-poetry','','[]','花發蒙亭畫景舒，浩歌應嘆食無魚。',32,'全唐诗/poet.song.41000.json','["花發蒙亭畫景舒，浩歌應嘆食無魚。", "靈巖恨不同真賞，且把新詩慰子居。"]'),
('21beb098-d3cc-480e-be96-d9b2e10e1084','離石室','韋驤','宋','宋诗','song-poetry','','[]','九十陽春興已酬，登山穿谷盡清幽。',32,'全唐诗/poet.song.41000.json','["九十陽春興已酬，登山穿谷盡清幽。", "閒田不是無多讓，故遣塵勞作勝遊。"]'),
('2decac49-da0b-48eb-8f42-77b2e1e571d9','離邑寄顔長道','韋驤','宋','宋诗','song-poetry','','[]','縣城不出已逾月，出愛秀野浮青春。',64,'全唐诗/poet.song.41000.json','["縣城不出已逾月，出愛秀野浮青春。", "前時枯株變深翠，對我意氣如欣欣。", "肩輿漸入南康道，溪山清曠交吾鄰。", "簿書撥置固可喜，又况雅誼還相親。"]'),
('3ebef4da-efd4-4b11-8c5a-d6ed52b6e7d5','聞詔士呈同僚朱伯英','韋驤','宋','宋诗','song-poetry','','[]','聖神慮遺士，豪傑思致身。',48,'全唐诗/poet.song.41000.json','["聖神慮遺士，豪傑思致身。", "詔書一飛傳，上下交歡忻。", "吾儕職山邑，步局志未伸。", "緬想風雲會，廓然忘我勤。"]'),
('116eaa08-f380-4fa0-9719-fea2eab5664a','和亭','韋驤','宋','宋诗','song-poetry','','[]','前賢重交際，世俗競將迎。',48,'全唐诗/poet.song.41000.json','["前賢重交際，世俗競將迎。", "用禮皆由正，知和始可行。", "候亭增舊構，題榜易先名。", "訓徼非存遠，還當鍳鄙情。"]'),
('6163c89e-8eeb-4701-aaff-dad94292ed2d','和伯英初霽','韋驤','宋','宋诗','song-poetry','','[]','日出乾坤靜，陰霖革累旬。',48,'全唐诗/poet.song.41000.json','["日出乾坤靜，陰霖革累旬。", "前溪聲未减，綠野秀如新。", "人意猶祛病，物心疑再春。", "此情誰解賦，先手屬東鄰。"]'),
('e737e9c5-e0bf-4e19-86dc-357dfaf11ac7','和顔令見寄  其一','韋驤','宋','宋诗','song-poetry','','[]','孤城四面插羣峰，雲翳經旬雨氣雄。',64,'全唐诗/poet.song.41000.json','["孤城四面插羣峰，雲翳經旬雨氣雄。", "自愧不才爲縣令，近来無事若山翁。", "幾思羽翼飛騰去，幸有英豪咫尺中。", "獨上高楼方引脰，喜逢嘉句載清風。"]'),
('0e2b7a54-1818-4051-bacd-c477e0de0d24','和顔令見寄  其二','韋驤','宋','宋诗','song-poetry','','[]','洗出郊原物象明，積陰祛盡喜天晴。',32,'全唐诗/poet.song.41000.json','["洗出郊原物象明，積陰祛盡喜天晴。", "東鄰長道詩新寄，增我溪山一倍清。"]'),
('1222a122-174c-458a-9e89-1bba976497d2','權東陽既久求歸武川上守倅 章守','韋驤','宋','宋诗','song-poetry','','[]','劇邑虛官偶承乏，字民何術慰林林。',64,'全唐诗/poet.song.41000.json','["劇邑虛官偶承乏，字民何術慰林林。", "文翁化被雖無事，巫馬才慳懼不任。", "樽俎弗踰宗祝計，牛羊自守乘田心。", "願歸山邑逃瘝曠，養拙寒儒荷賜深。"]'),
('6fac92e5-c5da-4970-9eaa-4652f28fa188','權東陽既久求歸武川上守倅 沈倅','韋驤','宋','宋诗','song-poetry','','[]','星火州符氣勢豪，敢辭承乏賦賢勞。',64,'全唐诗/poet.song.41000.json','["星火州符氣勢豪，敢辭承乏賦賢勞。", "設施每恐無能及，曠責還憂不可逃。", "捕鼠孰淹睎驥足，解牛難任割雞刀。", "願令樗散歸閒邑，更使潛心緣飾高。"]'),
('22960b46-7d0d-4660-ae76-781c5fd59e04','衢梁試院呈同事','韋驤','宋','宋诗','song-poetry','','[]','秋風動林葉，山國早寒輕。',48,'全唐诗/poet.song.41000.json','["秋風動林葉，山國早寒輕。", "較藝精神暇，持杯語論清。", "勿辭淹鎖院，未用尅歸程。", "留意如求舉，終當不誤評。"]'),
('827cd614-7c9b-4390-9920-5b5fa5e9c0af','依前韻酬張屯田和詩','韋驤','宋','宋诗','song-poetry','','[]','落筆流星緩，酬言白璧輕。',48,'全唐诗/poet.song.41000.json','["落筆流星緩，酬言白璧輕。", "鄙辭翻可媿，老格有餘清。", "擇士無精鍳，糊名况舊程。", "更煩爲大句，使我壯文評。"]'),
('ae7f4abf-e45f-499a-935c-5178a3fdd8a2','試士畢同長道東歸','韋驤','宋','宋诗','song-poetry','','[]','相将冒曉出郊原，但值佳山即駐軒。',64,'全唐诗/poet.song.41000.json','["相将冒曉出郊原，但值佳山即駐軒。", "投午未行三十里，和詩已及半千言。", "黄雲被野田禾熟，白雪翻空溪浪奔。", "高曠襟懷共爲樂，此情難與俗人論。"]'),
('70ff7e9e-f1dc-49ef-a91f-336d783697fd','上睦州劉工部  其一','韋驤','宋','宋诗','song-poetry','','[]','政行荆楚百蠻懷，却擁旌旄向此来。',64,'全唐诗/poet.song.41000.json','["政行荆楚百蠻懷，却擁旌旄向此来。", "自喜平生無枉道，豈論千里復淹才。", "恩蘇疲瘵精神返，威懾姦憸胆氣摧。", "秋晚子陵溪上好，樽罍風雅許誰陪。"]'),
('b30d8f3f-08a0-481d-bea0-6e366f6b7e8d','上睦州劉工部  其二','韋驤','宋','宋诗','song-poetry','','[]','桐廬古郡壓烏龍，瀟灑佳名信不空。',64,'全唐诗/poet.song.41000.json','["桐廬古郡壓烏龍，瀟灑佳名信不空。", "傲世曾栖隱君子，謫官多屬鉅賢公。", "連雲城郭殘秋外，近水楼臺返照中。", "太守公餘登覧勝，始知天意飬其衷。"]'),
('26154a6f-d64c-4ace-aa0e-96da972ab6d7','和朱尉見招','韋驤','宋','宋诗','song-poetry','','[]','作尉由来本仙局，况能投隙會僚朋。',64,'全唐诗/poet.song.41000.json','["作尉由来本仙局，况能投隙會僚朋。", "開懷自適人須美，治具雖疏客不憎。", "雨意初收天爽快，田工将畢歲豐登。", "高吟大飲無羞澀，祗恐秋風苦不勝。"]'),
('08cc0fe4-28e1-4d11-b6e0-3c3acc52393e','和顔令見寄','韋驤','宋','宋诗','song-poetry','','[]','别後經宵各到家，别時岐路兩縈斜。',64,'全唐诗/poet.song.41000.json','["别後經宵各到家，别時岐路兩縈斜。", "相期巵酒重何日，獨對秋林浪有花。", "攻墨卻思同整具，擇金猶記共澄沙。", "語言彷彿如朝暮，但悵暌離似海涯。"]'),
('1d3a9bc3-f31c-4190-9e5b-c3daf6f09e0a','觀穡','韋驤','宋','宋诗','song-poetry','','[]','霜風卷葉度高楼，楼上蕭然對晚秋。',64,'全唐诗/poet.song.41000.json','["霜風卷葉度高楼，楼上蕭然對晚秋。", "坐看野人收𥝧稏，相将盡室在田疇。", "赴晴汲汲如防寇，望歲區區已見酬。", "遺秉多忘歌笑去，乃心應亦傲輕裘。"]'),
('2a5aa62c-3255-4694-b80b-dfde4316b3dd','寄長道','韋驤','宋','宋诗','song-poetry','','[]','詩筒寂寞過殘秋，望斷前山暮靄收。',64,'全唐诗/poet.song.41000.json','["詩筒寂寞過殘秋，望斷前山暮靄收。", "共簡猶思石巖句，連鑣悔失爛柯遊。", "晴溪激淺聲還細，栖鳥争深閙未休。", "野興與君當不異，不知今日在層楼。"]'),
('141dc51c-afba-463f-9e32-84bbc3faf092','縣齋即事','韋驤','宋','宋诗','song-poetry','','[]','比来庭訟少，拙令稱幽潛。',144,'全唐诗/poet.song.41000.json','["比来庭訟少，拙令稱幽潛。", "愛日開朝幌，看雲捲畫簾。", "澄神烹茗粥，憶古檢書籤。", "菽水清多樂，溪山意自恬。", "韜光異耕釣，苦志念漁鹽。", "驥足空思展，牛刀敢謂淹。", "民心久當信，佐局美相兼。", "笑傲言祛隘，賡酬韻鬭嚴。", "囊錢如未乏，樽酒尚能添。", "園笋新成綠，池荷半露尖。", "共謀懷坦坦，毋恤遠炎炎。", "此興歡無敵，逢人語必箝。"]'),
('bbbf8549-c4d2-4f75-8810-43e433047bc5','永康徐尉次寄顔令詩韻見寄因以前韻酬答','韋驤','宋','宋诗','song-poetry','','[]','柅車爲别始中秋，遽見霜朝愛景浮。',64,'全唐诗/poet.song.41000.json','["柅車爲别始中秋，遽見霜朝愛景浮。", "自愧馬期無少暇，祗應梅福有清遊。", "殷勤好句能相寄，哦咏幽齋豈便休。", "此段情懷何所似，月明更上庾公楼。"]'),
('c090d3ef-db61-490c-94c5-b47bddb4b738','和朱伯英後圃見招','韋驤','宋','宋诗','song-poetry','','[]','愛君邀客以清詩，會我公庭缿訟稀。',32,'全唐诗/poet.song.41000.json','["愛君邀客以清詩，會我公庭缿訟稀。", "卷白到時須自勉，亂紅飛處是春歸。"]'),
('59c07ff0-1dc9-487b-962d-b9a76c529767','初夏公餘','韋驤','宋','宋诗','song-poetry','','[]','公庭日無事，民伍正蠶耕。',48,'全唐诗/poet.song.41000.json','["公庭日無事，民伍正蠶耕。", "夏淺寒猶在，雲濃雨易成。", "圖書存遠古，詩酒有餘情。", "傲吏居幽僻，其誰誚近名。"]'),
('8b3e0d01-7094-47a6-97bc-90ca8b76f315','和朱伯英迓送還示','韋驤','宋','宋诗','song-poetry','','[]','憐君迍蹇從初仕，慰我蕭條典一同。',32,'全唐诗/poet.song.41000.json','["憐君迍蹇從初仕，慰我蕭條典一同。", "莫爲塵勞便興歎，所施無負即爲功。"]'),
('1e391fc0-b597-4d7a-9f75-e11ae3fbb1df','和太守郡閣望羣山有雪','韋驤','宋','宋诗','song-poetry','','[]','郊原霽後晚寒清，殘雪籠山望處明。',64,'全唐诗/poet.song.41000.json','["郊原霽後晚寒清，殘雪籠山望處明。", "盡道凝留因地冷，當知粉飾藉天成。", "崑岡玉聚微雲斂，滄海潮横返照清。", "解賦屬誰詩格老，賢侯登覧在層城。"]'),
('a94326ff-3b9a-4c02-af41-118fd90f953a','自郡還寄長道','韋驤','宋','宋诗','song-poetry','','[]','故歲跼重城，填然思不清。',48,'全唐诗/poet.song.41000.json','["故歲跼重城，填然思不清。", "歸来見春老，何處慰詩情。", "顧我幾茅塞，知君已帙盈。", "社壇當未廢，舊約可尋盟。"]'),
('3b29d513-c04b-4123-af27-9b429bfd5266','和顔長道見寄','韋驤','宋','宋诗','song-poetry','','[]','宛轉溪山邑落深，春歸雲物易成陰。',64,'全唐诗/poet.song.41000.json','["宛轉溪山邑落深，春歸雲物易成陰。", "鶯穿别塢遺新子，花謝前村失舊林。", "自厭簿書爲滯跡，未應軒冕足關心。", "東鄰幸有顔明府，清曠襟懷且共吟。"]'),
('e47d5d57-4576-4ac6-95e1-13a44fab92cc','謝朱伯英遺詩','韋驤','宋','宋诗','song-poetry','','[]','我輩清懷書自将，不須才與古人當。',64,'全唐诗/poet.song.41000.json','["我輩清懷書自将，不須才與古人當。", "佳辰美概無窮盡，險語高詞爾轉相。", "吏隱未能離擾擾，詩情猶得慰皇皇。", "如君逸格誰忘羡，騕褭終難困服箱。"]'),
('a82aa32e-24ae-4971-b6f4-b5859a3f9c42','和顔長道寄三首 首夏','韋驤','宋','宋诗','song-poetry','','[]','秀邑發叢萱，清陰泛新竹。',36,'全唐诗/poet.song.41000.json','["秀邑發叢萱，清陰泛新竹。", "園林足幽思，揚揚曲池曲。", "奚獨念春歸，愛此未炎燠。"]'),
('01b6a53a-77d4-467c-a66a-9f421f94e4a3','和顔長道寄三首 縣齋肆筆','韋驤','宋','宋诗','song-poetry','','[]','簿領區區豈惬情，塵紛安得眼長青。',64,'全唐诗/poet.song.41000.json','["簿領區區豈惬情，塵紛安得眼長青。", "且希五柳先生醉，莫似清江使者靈。", "臨政每慚非善治，随時尤愧有勞形。", "誰能與我同幽曠，隴上耦耕還带經。"]'),
('a5744ae5-7bf5-4e95-868d-fe8c8b8e7e4e','和顔長道寄三首 閲武川倡酬','韋驤','宋','宋诗','song-poetry','','[]','往還賡唱百餘篇，草草編聯後或前。',64,'全唐诗/poet.song.41000.json','["往還賡唱百餘篇，草草編聯後或前。", "語氣有時凌夜月，辭源何啻瀉春泉。", "須知吏隱能遺俗，不獨山溪解樂天。", "屈指代期秋信逼，封人莫厭屡馳牋。"]'),
('82bd72ca-923c-4671-80fb-1a2908bf7c74','掃蒙亭','韋驤','宋','宋诗','song-poetry','','[]','蕪亭一掃媿陳蕃，松柏陰森翠竹環。',64,'全唐诗/poet.song.41000.json','["蕪亭一掃媿陳蕃，松柏陰森翠竹環。", "閙蟈盡敺澄曲水，横柯旋斫望青山。", "人歸畎畝醇風在，我近圖書白日閒。", "樗散自知成獨樂，慚無善效及民間。"]'),
('794273c1-4265-49c3-b2b1-8489537e05eb','次韻和顔令見寄','韋驤','宋','宋诗','song-poetry','','[]','再來東白日無休，剸割唯憂或滯留。',32,'全唐诗/poet.song.41000.json','["再來東白日無休，剸割唯憂或滯留。", "滿眼煙塵真可厭，幸而涵碧見清秋。"]'),
('0987e45a-8bef-4343-ab7b-d697f0d5e7cb','伯瞻郎中生日','韋驤','宋','宋诗','song-poetry','','[]','瑞氣飄飄貫斗牛，當時貽慶在南州。',64,'全唐诗/poet.song.41000.json','["瑞氣飄飄貫斗牛，當時貽慶在南州。", "太平勢盛高賢出，造化功成萬物秋。", "侯國幾年凝課最，相門今日足風流。", "祝公壽與靈椿等，庶得胸中盡壯猶。"]'),
('97772e72-59f5-47ce-b503-1d6526604eb8','中秋南康夜會得天字','韋驤','宋','宋诗','song-poetry','','[]','宿陰初卷盡，萬狀正蕭然。',48,'全唐诗/poet.song.41000.json','["宿陰初卷盡，萬狀正蕭然。", "夜色兼秋半，人情愛月圓。", "褫巾灑濁酒，露坐幕青天。", "佳節還相遇，陽陽憶去年。"]'),
('876cc470-274c-42d7-b4b7-bb9399659c62','假道南康長道語今夕中秋正故歲聚并喜樂時也遂留以夜飲飲半和所示詩','韋驤','宋','宋诗','song-poetry','','[]','月華乘顥氣，人競此宵明。',48,'全唐诗/poet.song.41000.json','["月華乘顥氣，人競此宵明。", "舊會嗟經歲，修途爲輟程。", "凉飄襟袖爽，秋入管弦清。", "莫誚紅裙飲，新詩亦間成。"]'),
('4029a315-e18d-41ae-b696-6c420e3760bc','睦州千峰榭二首  其一','韋驤','宋','宋诗','song-poetry','','[]','千峰圍繞自蒼然，古榭凄凉不記年。',64,'全唐诗/poet.song.41000.json','["千峰圍繞自蒼然，古榭凄凉不記年。", "搜索舊名逢雅尚，主張佳境有豪篇。", "坐凌翠靄羣囂隔，眼入清秋萬狀全。", "蕪廢不唯興此地，當知民物盡陶甄。"]'),
('4da2c258-8330-4001-8a58-580bb64d4fd4','睦州千峰榭二首  其二','韋驤','宋','宋诗','song-poetry','','[]','層基突兀倚晴空，碧嶂回環勢複重。',64,'全唐诗/poet.song.41000.json','["層基突兀倚晴空，碧嶂回環勢複重。", "秀色有時侵畫隼，蒼煙盡日臥烏龍。", "嚴公灘近增幽概，方叟詩存得舊蹤。", "賢守葺遺殊衆好，政閒把酒看千峰。"]'),
('803494ea-408b-4888-96ce-6e395d5546de','宿廣嚴靖閣','韋驤','宋','宋诗','song-poetry','','[]','久爲簿領廢登臨，一宿禪扃萬慮沉。',32,'全唐诗/poet.song.41000.json','["久爲簿領廢登臨，一宿禪扃萬慮沉。", "半夜松聲驚夢枕，琴書幡起故園心。"]'),
('c4e55fba-6ec2-4e92-98f7-e8f7bee5fc63','過法寧僧舍','韋驤','宋','宋诗','song-poetry','','[]','積陰卷盡見朝陽，更入雲林古道場。',32,'全唐诗/poet.song.41000.json','["積陰卷盡見朝陽，更入雲林古道場。", "疏曠襟懷終久在，暫離簿領已清狂。"]'),
('9a8b51f3-12b6-46d7-8531-7922a09daa4d','題虎峰真師壁','韋驤','宋','宋诗','song-poetry','','[]','虎踞山形路屈盤，烟雲過盡到禪關。',32,'全唐诗/poet.song.41000.json','["虎踞山形路屈盤，烟雲過盡到禪關。", "老僧得地真安穩，不向人間趁往還。"]'),
('87d379db-cf5b-4c60-90ad-df667b6f7853','檢覆雞啼源還虎峰','韋驤','宋','宋诗','song-poetry','','[]','到此崎嶇力已疲，肩舁西去更乘危。',32,'全唐诗/poet.song.41000.json','["到此崎嶇力已疲，肩舁西去更乘危。", "始知不及閒人好，避險從安任所之。"]'),
('bf62ba5b-38f5-43fe-aa5b-b8ec75daafb8','寒雨夜會得歌字','韋驤','宋','宋诗','song-poetry','','[]','佳客來相遇，銜杯語論和。',72,'全唐诗/poet.song.41000.json','["佳客來相遇，銜杯語論和。", "夜寒兼雨甚，酒色向人多。", "淚燭搖紅蕚，風帷動翠波。", "漏聲催舉白，簷溜混微歌。", "朋契淡閒合，詩鋒闇裏磨。", "十年方一笑，不醉奈情何。"]'),
('95e75d48-f9ef-44d2-be90-9020389fa80e','呈范子鎮同年','韋驤','宋','宋诗','song-poetry','','[]','白日當時共得仙，清樽未倒且留連。',32,'全唐诗/poet.song.41000.json','["白日當時共得仙，清樽未倒且留連。", "間關益部君今去，後會輕論又幾年。"]'),
('27f9c13d-02c5-4f07-bdc1-d5b829e856ab','勸元功飲','韋驤','宋','宋诗','song-poetry','','[]','昔時同閈今同郡，氣義相懽此最親。',32,'全唐诗/poet.song.41000.json','["昔時同閈今同郡，氣義相懽此最親。", "莫向酒杯成偃蹇，醉來詩格合清新。"]'),
('594b15d9-ad10-4b68-b07d-a172078c89ed','再和范同年得廳字','韋驤','宋','宋诗','song-poetry','','[]','人生難計擬，并合若漂萍。',72,'全唐诗/poet.song.41000.json','["人生難計擬，并合若漂萍。", "稀闊同年會，蕭條古縣廳。", "冒寒欺雨勢，卜夜託龜靈。", "漏轉歌聲促，風餘燭燼零。", "主樽慚北海，客量過滄溟。", "願且留車馬，離弦未可聽。"]'),
('05786e4d-a79b-482d-87bc-c96887636e12','涵碧池','韋驤','宋','宋诗','song-poetry','','[]','原泉有本養淵渟，更似端人見底清。',32,'全唐诗/poet.song.41000.json','["原泉有本養淵渟，更似端人見底清。", "竹色山光朝暮在，當知涵碧不虛名。"]'),
('13d3fe48-4f5c-4c29-a60b-a0a8b45fc2cf','涵碧亭','韋驤','宋','宋诗','song-poetry','','[]','座隅平地是雲山，爽氣無窮六月寒。',32,'全唐诗/poet.song.41000.json','["座隅平地是雲山，爽氣無窮六月寒。", "夢得祗知圖未善，不知能畫不能完。"]'),
('911edc0b-98b5-4ed4-a2d1-4f648dcb962a','瀑泉','韋驤','宋','宋诗','song-poetry','','[]','堂堂一道出山腰，色似垂縑響似潮。',32,'全唐诗/poet.song.41000.json','["堂堂一道出山腰，色似垂縑響似潮。", "何必枕流圖洗耳，坐觀已覺俗塵消。"]'),
('56a74939-f1fe-4261-a5e9-6b41bc693da8','雙石魚','韋驤','宋','宋诗','song-poetry','','[]','誰磨紫石作雙魚，繞以清流泛酒觚。',32,'全唐诗/poet.song.41000.json','["誰磨紫石作雙魚，繞以清流泛酒觚。", "祗使幽人添醉逸，山林未快憶江湖。"]'),
('f18f15c1-5c51-4a65-8f79-05ed6058ba7a','傲亭','韋驤','宋','宋诗','song-poetry','','[]','峨然危構冠山巔，以傲名亭傲可賢。',32,'全唐诗/poet.song.41000.json','["峨然危構冠山巔，以傲名亭傲可賢。", "不與世人論是否，誰能来此臥雲煙。"]'),
('33b7c4bb-11e6-4c73-b28c-9f08dfd25aa9','雙峰','韋驤','宋','宋诗','song-poetry','','[]','我愛雙峰若並趨，鈞然蒼翠傲榮枯。',32,'全唐诗/poet.song.41000.json','["我愛雙峰若並趨，鈞然蒼翠傲榮枯。", "定應天意成真概，磊落相依道不孤。"]'),
('ff65c30e-f758-45f7-9a0a-f50c7933a48c','擊甌','韋驤','宋','宋诗','song-poetry','','[]','簫鼓厭喧豗，甌聲可薦杯。',48,'全唐诗/poet.song.41000.json','["簫鼓厭喧豗，甌聲可薦杯。", "鳴珂秋獵駿，鏘佩曉朝迴。", "挹注雖爲助，甄陶别有胚。", "玉纖敲擊鋭，驚起玉山頽。"]'),
('6a21bd5d-6cf9-4d99-9ba0-d284fa4325e1','和朱尉示親老生日','韋驤','宋','宋诗','song-poetry','','[]','臘殘朝夕是新春，秀入溪山碧萬尋。',64,'全唐诗/poet.song.41000.json','["臘殘朝夕是新春，秀入溪山碧萬尋。", "白髪親逢蓬矢慶，綵衣人奉玉杯深。", "風迴庭砌弦簧脆，日上簾旌插珥森。", "敢謂小官無足慰，盡懽菽水亦甘任。"]'),
('a7cced92-2e58-4021-ae6f-6cf13b411364','和朱伯英元夕','韋驤','宋','宋诗','song-poetry','','[]','燃燈結綵學春山，佳節還逢邑事閒。',64,'全唐诗/poet.song.41000.json','["燃燈結綵學春山，佳節還逢邑事閒。", "僚佐相從真我侶，旄齯共樂在其間。", "月中風味當無比，醉裏塵勞似不關。", "祗以清罇期漏盡，明朝應悔主才慳。"]'),
('1e792b56-9a84-4247-ba98-7f0104da07ba','席間和向闢之元夜  其一','韋驤','宋','宋诗','song-poetry','','[]','令節伸眉且自寛，與民同樂是民官。',64,'全唐诗/poet.song.41000.json','["令節伸眉且自寛，與民同樂是民官。", "宴酣豈爲殘更促，醉兀何妨萬目觀。", "舞袖飄飄凌夜月，燈山閃閃戰春寒。", "孤城誰謂蕭疏甚，無愧途人即可懽。"]'),
('84387454-7eb2-45a0-935a-4e47e153fc94','席間和向闢之元夜  其二','韋驤','宋','宋诗','song-poetry','','[]','無愧塗人即可歡，□□□□□□□。',64,'全唐诗/poet.song.41000.json','["無愧塗人即可歡，□□□□□□□。", "月華瑩澈通春夕，民氣融和却暮寒。", "捃摭餚蔬成曲會，扶携老稚任環觀。", "邑儂他日逢今日，往往應能話舊官。"]'),
('badd4666-33b4-425a-b7a3-e3b1948cd384','回長道中論','韋驤','宋','宋诗','song-poetry','','[]','□□□□□□紛，吾子文章有本根。',64,'全唐诗/poet.song.41000.json','["□□□□□□紛，吾子文章有本根。", "此說獨能通正道，□□□□□專門。", "剖開先聖難明旨，羞殺拘儒既□□。", "□□□才何足議，但憑餘燄發冥昏。"]'),
('d29d2ca5-c469-49fc-8c8a-5b3c0e2da592','和長道候使者宿龍窟見寄','韋驤','宋','宋诗','song-poetry','','[]','幽寺傍□□，□□昂藏頂翠螺。',62,'全唐诗/poet.song.41000.json','["幽寺傍□□，□□昂藏頂翠螺。", "縣尹候迎車暫□，田甿觀□□□□。", "潭間水黑應龍臥，松表風清獨鶴過。", "□□□□□□我，蕭齋倚柱祗長歌。"]'),
('4a03dfa9-aeac-470b-a197-a0e1121f99a6','長道将罷邑借前韻以寄','韋驤','宋','宋诗','song-poetry','','[]','山□□□□□□，□對春風把酒螺。',64,'全唐诗/poet.song.41000.json','["山□□□□□□，□對春風把酒螺。", "况是安甿囂訟少，何□□□□懷多。", "眼看野色煙雲秀，指數瓜期日月過。", "聞說賢侯將解印，追攀無計且酣歌。"]'),
('2b372620-28a3-4de2-87da-84c71b900b39','和見貽','韋驤','宋','宋诗','song-poetry','','[]','拘攣山邑四□□，□滯徒嗟薄宦身。',64,'全唐诗/poet.song.41000.json','["拘攣山邑四□□，□滯徒嗟薄宦身。", "憶昨同時來視事，羡君先我作閒人。", "傾心雖記多佳議，寒齒還憂失舊鄰。", "安得追攀如素約，舳艫銜尾倚江濱。"]'),
('b177147e-fcbb-4732-8dd5-43d9c2368199','送章郎中赴闕  其一','韋驤','宋','宋诗','song-poetry','','[]','□□□□治已成，還臺榮望本崢嶸。',64,'全唐诗/poet.song.41000.json','["□□□□治已成，還臺榮望本崢嶸。", "朝廷不許淹賢□，□□□□借守情。", "曉日旌旗動行色，春風笳鼓作邊聲。", "□□□閼城西道，祗恐朱轓欲迅征。"]'),
('3ddd484b-5e70-4e1c-9825-2439d5102b9c','送章郎中赴闕  其二','韋驤','宋','宋诗','song-poetry','','[]','□□□□孰可儔，弟兄麾節占三州。',64,'全唐诗/poet.song.41000.json','["□□□□孰可儔，弟兄麾節占三州。", "疲甿救盡方爲□，□□□還豈自由。", "仁似周侯小棠在，清嫌漢守大□留。", "祇應靜夜雙溪月，遠挂公心未得休。"]'),
('a425ea4c-6818-4d3f-88c2-3e5dd4215d37','探得海棠送章仲成','韋驤','宋','宋诗','song-poetry','','[]','高低海棠枝，交結離人思。',48,'全唐诗/poet.song.41000.json','["高低海棠枝，交結離人思。", "離披海棠花，爛熳離人醉。", "醉來離思輕，看花自有情。", "一片随春風，悠悠逐君行。"]'),
('559214ae-4a18-47da-8e51-1be0309e408e','和長道交道驛見招同趨府','韋驤','宋','宋诗','song-poetry','','[]','北出城闉天未明，待驅款段趁君行。',32,'全唐诗/poet.song.41000.json','["北出城闉天未明，待驅款段趁君行。", "歸時亦欲偕吟醉，寄語林間有落英。"]'),
('6f5070c0-c1da-4154-a228-459db8564073','同長道遊惠僧翠樾堂','韋驤','宋','宋诗','song-poetry','','[]','覃覃潔宇枕城阿，車馬知名始見過。',64,'全唐诗/poet.song.41000.json','["覃覃潔宇枕城阿，車馬知名始見過。", "邃密莫嫌春態淺，牢籠不礙翠陰多。", "玩心爽概真偏得，冺跡空山去幾何。", "今日□□□褫带，暫将塵擾就消磨。"]'),
('dc133784-a67b-43de-9634-86d9f84767fc','清明雨','韋驤','宋','宋诗','song-poetry','','[]','陰雲散漫與山平，草暗花昏匝古城。',64,'全唐诗/poet.song.41000.json','["陰雲散漫與山平，草暗花昏匝古城。", "定是天心惡遊放，故将雨脚鎖清明。", "誰知静圃無窮極，獨有幽禽不住鳴。", "况值清明歸去客，共樽談笑有餘情。"]'),
('6c4909a3-c960-47f4-9313-c7553795ef75','四月一日西池作','韋驤','宋','宋诗','song-poetry','','[]','田田荷葉大如錢，拙令無功又一年。',32,'全唐诗/poet.song.41000.json','["田田荷葉大如錢，拙令無功又一年。", "六月京塵傳流口，不嫌池上更遷延。"]'),
('fa4a7f19-1b34-4a3a-8b3e-8650c71528e6','林沼春歸後','韋驤','宋','宋诗','song-poetry','','[]','林沼春歸後，幽芳日益添。',48,'全唐诗/poet.song.41000.json','["林沼春歸後，幽芳日益添。", "芭蕉翠羽扇，蘆筍碧牙籤。", "薄靄籠夷逕，微波蕩曲簷。", "主人山野性，杖屨此無厭。"]'),
('798c07e7-d791-4556-83b5-f29e04810ac9','和朱尉首夏偶書見寄','韋驤','宋','宋诗','song-poetry','','[]','蹭蹬瓜期失，山城獨滯留。',240,'全唐诗/poet.song.41000.json','["蹭蹬瓜期失，山城獨滯留。", "馳驅更萬態，寒暑過三周。", "底裏繇前固，隄崖懶外修。", "僅能違吐茹，豈謂足陽秋。", "所幸偷安佚，兹心在討求。", "門闌方事隙，園落見春休。", "秀色孤花載，晴光隘葉浮。", "池魚行有隊，林鳥語多羞。", "蘆笋青簪短，丁香翠幄稠。", "藏身咍野繭，努角笑蝸牛。", "庭擁芭蕉扇，墻披薜荔裘。", "清風如遠俗，危坐自忘憂。", "目極山兼水，雲飛越與甌。", "官曹雖鞅掌，野興易牽鉤。", "缿絕侵疆訟，閽無覆刺投。", "優閒爲佐局，邂逅得吾流。", "酒薄猶思共，詩成罔不酬。", "肺懷非異致，議論詎相矛。", "受代何辭晚，謀懽且自由。", "他時遂暌阻，徒爾念英遊。"]'),
('bb63b27c-5eba-436d-ab4e-f02c8e6eed4a','遊金柱觀瀑泉','韋驤','宋','宋诗','song-poetry','','[]','源高雲表許誰窮，飛出巖前百丈雄。',32,'全唐诗/poet.song.41000.json','["源高雲表許誰窮，飛出巖前百丈雄。", "豈是山神作靈怪，解将煙雨變晴空。"]'),
('721b6190-75e1-4704-af31-242b5cdf1adc','和伯英再賦','韋驤','宋','宋诗','song-poetry','','[]','行蹤隱怪少人知，非是山僧别有機。',32,'全唐诗/poet.song.41000.json','["行蹤隱怪少人知，非是山僧别有機。", "漏泄一朝逢地主，逢迎終不似前稀。"]'),
('31fa661b-506f-4413-80f6-2ec57fa89e57','同朱尉遊普寧僧舍','韋驤','宋','宋诗','song-poetry','','[]','名區日事出南城，來扣禪關萬慮平。',64,'全唐诗/poet.song.41000.json','["名區日事出南城，來扣禪關萬慮平。", "強作優閒羞宓子，自成清淡愛梅生。", "棋敲玉局林鶯竄，詩落苔牋山鬼驚。", "却說去年違此約，老僧應解管宫營。"]'),
('b0f85c54-3fd6-4573-ac00-20269c5c34ee','和初夏雨中','韋驤','宋','宋诗','song-poetry','','[]','撇然春去浹旬餘，積雨乘陰氣節殊。',64,'全唐诗/poet.song.41000.json','["撇然春去浹旬餘，積雨乘陰氣節殊。", "曠野石泉飛白練，虛庭簷溜激明珠。", "繭因寒晚羣情病，麥候晴收萬室須。", "空解登楼伺雲色，愛民拙令愧偷儒。"]'),
('a67ac3b0-d9c4-4878-9d42-1bed38cf117f','端午雨飲伯英池館','韋驤','宋','宋诗','song-poetry','','[]','山城重午遭陰晦，謝氏池亭亦自堪。',64,'全唐诗/poet.song.41000.json','["山城重午遭陰晦，謝氏池亭亦自堪。", "野色映來歌舞好，炎威消去酒餚甘。", "手中菖屑隨杯泛，頭上榴花带雨篸。", "且盡主人留客興，明年誰北復誰南。"]'),
('d09448d7-c077-4767-a228-c453c956b03b','送王學士赴京東漕','韋驤','宋','宋诗','song-poetry','','[]','重寄屬名卿，除書拜寵榮。',240,'全唐诗/poet.song.41000.json','["重寄屬名卿，除書拜寵榮。", "山東移使節，天上動星明。", "經畫幾三載，恩威盡列城。", "詢求皆疾苦，課入自豐盈。", "酣宴咍無取，焦心憫未宏。", "孟陽魂已愧，劉晏譽還輕。", "報國胸襟壯，紓民術學精。", "休風鼓羣吏，高論滿諸生。", "詎奮身干進，難排翼傳聲。", "褒功形聖詔，易地近王京。", "持節將新命，遮車見衆誠。", "拳拳思遠託，冉冉即修程。", "風颺旌旗活，雲收鼓吹清。", "山川開爽氣，草木有餘情。", "行健途疑促，吟豪思欲傾。", "越吳鈞慕戀，齊魯樂奔迎。", "萬里宣材力，中朝倚辦營。", "僉諧猶有待，輿議豈能平。", "器尚虛兼濟，謀終贊仰成。", "宸衷方外藉，安可憶登瀛。"]'),
('b0965765-0693-440d-b756-984bf3fbc588','曉出候按察','韋驤','宋','宋诗','song-poetry','','[]','未曉驅車出，炎蒸畏日高。',48,'全唐诗/poet.song.41000.json','["未曉驅車出，炎蒸畏日高。", "蒼茫侵霧氣，隱約聽雞號。", "流滯還尸祿，奔馳敢嘆勞。", "苦吟随處有，未始廢陶陶。"]'),
('10bfc123-55bf-46fd-8c07-b4f41c0facf8','自和','韋驤','宋','宋诗','song-poetry','','[]','將旦雲天慘，前瞻使旆高。',48,'全唐诗/poet.song.41000.json','["將旦雲天慘，前瞻使旆高。", "田翁持火走，山鳥向人號。", "自哂折腰久，誰憐負弩勞。", "解從歸去樂，空愧不如陶。"]'),
('15d67eeb-aacf-43b9-b8cb-8a7fe36b72b0','偶作','韋驤','宋','宋诗','song-poetry','','[]','紗巾疏爽葛衣寛，簿領無多笑傲間。',64,'全唐诗/poet.song.41000.json','["紗巾疏爽葛衣寛，簿領無多笑傲間。", "黄卷仰持眠晝榻，白雲斜斂見晴山。", "風荷瀉露池聲激，煙柳藏蟬野趣閒。", "日月淹留非不幸，柅車休嘆未西還。"]'),
('ff932687-2771-4753-9d1d-6e5370e9fa43','予莅製濟民藥朱尉掌糶常平粟因以記','韋驤','宋','宋诗','song-poetry','','[]','火日炎炎五月天，邑中分事力相完。',64,'全唐诗/poet.song.41000.json','["火日炎炎五月天，邑中分事力相完。", "君當庾廩司平糶，我近方書輯衆丹。", "共識朝廷欲爲惠，豈圖居處自偷安。", "誰言忠誼須謀大，未合謀時且恪官。"]'),
('f3900c31-a8bd-46a9-97a2-f0275ac6d94b','和新竹','韋驤','宋','宋诗','song-poetry','','[]','根本堅深豈費培，龍蛇蛻盡見天材。',64,'全唐诗/poet.song.41000.json','["根本堅深豈費培，龍蛇蛻盡見天材。", "斜穿似愛幽人到，疏列還容小徑開。", "凉月驟添新影密，清風不减舊枝来。", "歲窮自有凌霜節，寧比秋衰惡草莱。"]'),
('19fe7275-b67e-4367-b463-2b050dc3609e','和獨釣  其一','韋驤','宋','宋诗','song-poetry','','[]','蒼葭欺綠鬢，白水照朱顔。',48,'全唐诗/poet.song.41000.json','["蒼葭欺綠鬢，白水照朱顔。", "擲餌淵渟處，牽鈎蕩漾間。", "亦知魚呴沬，肯學雀銜環。", "且欲資清曠，消磨永日閒。"]'),
('c95736b8-f17a-4d5d-9d71-05f3c1f45717','和獨釣  其二','韋驤','宋','宋诗','song-poetry','','[]','古人多隱釣，意不在徵求。',48,'全唐诗/poet.song.41000.json','["古人多隱釣，意不在徵求。", "稽海曾垂犗，磻溪舊直鉤。", "聲名當日晦，德業後來收。", "莫笑臨流者，持竿跡更幽。"]'),
('7504bc33-06d0-4d2a-a23c-f9fe011d522e','送劉睦州移京西漕','韋驤','宋','宋诗','song-poetry','','[]','賢傑恬榮進，朝廷睠舊材。',288,'全唐诗/poet.song.41000.json','["賢傑恬榮進，朝廷睠舊材。", "優閒輟爲郡，按舉復行臺。", "憶昨巡荆北，于時會歲菑。", "轉輸憂國計，假易緩民財。", "吏議烏能避，邦條不可裁。", "謫遷知咎戾，忠信即基胎。", "解印離江滸，分麾泝浙洄。", "列城遺厚愛，千里沛餘才。", "火玉堅難變，霜松翠弗摧。", "壯行心所勇，膠祿素嘗咍。", "履道期終固，謀身絕外猜。", "子文忘愠色，嚴助樂歸來。", "撫俗專求瘼，提綱獨整頹。", "察幽窮蔕芥，屏惡自渠魁。", "犴獄春多草，賓階雨不苔。", "溪山圍几席，風月侑樽罍。", "毫痩清吟苦，弦高雅曲哀。", "黄堂成臥治，青律再飛灰。", "況味安符竹，胸襟傲面槐。", "桐廬聲績遠，蓂陛寵光催。", "近部勞經畫，兼資藉瑋瑰。", "使旌蜺夭矯，宸詔鳳毰毸。", "肅肅途将戒，元元慕若孩。", "車攀朝柅軸，舟遁夜張桅。"]'),
('4d617e11-abfe-4a37-bce2-2e5135c0b466','雙蓮二首  其一','韋驤','宋','宋诗','song-poetry','','[]','池間𩉾鞢紅，特爾不雷同。',48,'全唐诗/poet.song.41000.json','["池間𩉾鞢紅，特爾不雷同。", "共本青跗痩，駢頭秀色充。", "湘娥心並恨，江女珮雙空。", "忍負流觴樂，虛教逐暮風。"]'),
('f87d5d77-b4c2-4794-b5d4-025868688c71','雙蓮二首  其二','韋驤','宋','宋诗','song-poetry','','[]','臨風皆獨媚，同蒂忽相親。',48,'全唐诗/poet.song.41000.json','["臨風皆獨媚，同蒂忽相親。", "擢秀材宜合，飄香勢自鈞。", "雖慚兩岐瑞，已掩百花春。", "定是憐濡滯，殷勤悦主人。"]'),
('d2a0e70f-d35f-47b2-9f71-15a35cd44eea','和朱伯英以詩慶将代','韋驤','宋','宋诗','song-poetry','','[]','非材安敢嘆淹留，吏外尤忻共雅游。',64,'全唐诗/poet.song.41000.json','["非材安敢嘆淹留，吏外尤忻共雅游。", "欲代雖知歸去樂，相看還動解携愁。", "襟期豈逐炎凉變，談笑應随簿領休。", "來歲黄花何處好，懷思把琖對霜秋。"]'),
('3fb8fcfb-7720-45df-a9c7-9262f841c7d6','再和','韋驤','宋','宋诗','song-poetry','','[]','區區邑落四逢秋，敢詫歸期占上游。',64,'全唐诗/poet.song.41000.json','["區區邑落四逢秋，敢詫歸期占上游。", "似得葵丘瓜代信，如銷都護玉關愁。", "琴彈夜月聲還變，詩寫溪山興未休。", "幸有臺池且同醉，别離到後更何由。"]'),
('d9525dc8-72e8-4cb5-95aa-34baf676831d','將歸','韋驤','宋','宋诗','song-poetry','','[]','代期漸可數光陰，掉鞅歸時秋已深。',64,'全唐诗/poet.song.41000.json','["代期漸可數光陰，掉鞅歸時秋已深。", "籬菊正牽元亮眼，江鱸還動季鷹心。", "迎新送故人徒擾，興利除殘我不任。", "唯有溪山不辜方，未嘗曠日廢清吟。"]'),
('6a373aed-c6ff-4b6b-8f98-91f0f2b2486f','效謝宣城體呈同事','韋驤','宋','宋诗','song-poetry','','[]','秋風鼓長松，聲来何颼颼。',48,'全唐诗/poet.song.41000.json','["秋風鼓長松，聲来何颼颼。", "衆鳥相與還，山椒落景收。", "吏冗得所隙，笑傲偕優游。", "雖無杯中物，亦足忘余憂。"]'),
('d451290d-25cf-4d54-a33f-f75aa28898e9','呈孫東美','韋驤','宋','宋诗','song-poetry','','[]','露氣侵簾幕，蕭然夜已分。',48,'全唐诗/poet.song.41000.json','["露氣侵簾幕，蕭然夜已分。", "括囊停較藝，倚几重論文。", "邂逅成相際，從容慰所聞。", "溪船行各去，回首只秋雲。"]'),
('a3499fc1-8c17-4d2e-923b-e6d145a0cf10','試罷','韋驤','宋','宋诗','song-poetry','','[]','沓沓紛袍去，寥寥鎖院中。',48,'全唐诗/poet.song.41000.json','["沓沓紛袍去，寥寥鎖院中。", "雲收晴野曠，潮卷夜江空。", "難盡文章鍳，終輸議論公。", "敢辭淹旦暮，歸翼尚覊籠。"]'),
('60c7dcbe-739e-49b5-8558-2778ad1941e3','和東美示內樂亭詩','韋驤','宋','宋诗','song-poetry','','[]','養恬真有得，逐俗固無心。',48,'全唐诗/poet.song.41000.json','["養恬真有得，逐俗固無心。", "月沼秋如鑑，風松夜當琴。", "公餘偏坐晚，客至不談今。", "張我名亭意，慚君寄好音。"]'),
('6b83d795-57dc-4b8e-bc48-e1e106e5ac37','和東美見寄','韋驤','宋','宋诗','song-poetry','','[]','子陵溪上各危檣，心逐君歸到故鄉。',64,'全唐诗/poet.song.41000.json','["子陵溪上各危檣，心逐君歸到故鄉。", "回首蒼茫空鶴望，亂山縈繞似羊腸。", "評文酷愛胸襟遠，坐邑還憂事業荒。", "忽得新篇開鄙塞，甚於濰水決沙囊。"]'),
('e499f4bf-fbc6-4aa6-8a0e-b03f4fbd51ac','鈞愛亭','韋驤','宋','宋诗','song-poetry','','[]','簿領支離每競辰，退思當亦在吾民。',64,'全唐诗/poet.song.41000.json','["簿領支離每競辰，退思當亦在吾民。", "抑扶爲術如偏取，字養存心固一均。", "杖履數來消逕蘚，笙歌久闋聚梁塵。", "天公豈復遺疏拙，風月隨時不負人。"]'),
('db8fadd7-879a-4089-ab70-2d860f2de817','內樂亭','韋驤','宋','宋诗','song-poetry','','[]','誰謂茲亭浪得名，寥寥氣象副深誠。',64,'全唐诗/poet.song.41000.json','["誰謂茲亭浪得名，寥寥氣象副深誠。", "地饒松竹千年色，天與雲山四合清。", "靖節固嘗爲傲吏，子真元不勢名卿。", "伊余竊慕恬然樂，肯以紛華戰性情。"]'),
('f1377cfa-b589-4c35-92ba-d30149efb4f4','凌翠閣  其一','韋驤','宋','宋诗','song-poetry','','[]','凌翠閣，翠光寒不落。',26,'全唐诗/poet.song.41000.json','["凌翠閣，翠光寒不落。", "公事餘閒日日來，簷前好鳥無驚作。"]'),
('568b278b-389d-4079-9f50-6100c3abaaee','凌翠閣  其二','韋驤','宋','宋诗','song-poetry','','[]','凌翠閣，突兀撐寥廓。',26,'全唐诗/poet.song.41000.json','["凌翠閣，突兀撐寥廓。", "滿眼蒼煙萬里春，忍負十分金鑿落。"]'),
('4f1160af-6513-4d2f-a9e8-abde807b9a6d','凌翠閣  其三','韋驤','宋','宋诗','song-poetry','','[]','凌翠閣，四面祛櫺箔。',26,'全唐诗/poet.song.41000.json','["凌翠閣，四面祛櫺箔。", "千里無雲看月明，何必庾家樓上樂。"]'),
('85bed66b-f0c7-4b03-abf1-f49ffa4685ab','凌翠閣  其四','韋驤','宋','宋诗','song-poetry','','[]','凌翠閣，山繞如城郭。',26,'全唐诗/poet.song.41000.json','["凌翠閣，山繞如城郭。", "風味都侔陶令居，所慚猶被青綸縳。"]'),
('5c92967f-9061-4d49-bec9-39e1e758c445','木芙蓉詞','韋驤','宋','宋诗','song-poetry','','[]','木芙蓉，墻頭淺淺紅。',70,'全唐诗/poet.song.41000.json','["木芙蓉，墻頭淺淺紅。", "秋林枝葉十九空，獨此蓶扈當秋風。", "秋風無意開俗眼，俗眼不開須在儂。", "接䍦斜欹勿嫌重，滿篸何恤驚兒童。", "豈必黄金菊，難辜白玉鐘。"]'),
('2282f899-d1fa-42ec-b110-daed5b1dc749','國哀','韋驤','宋','宋诗','song-poetry','','[]','天地有大故，朝庭凶訃來。',48,'全唐诗/poet.song.41000.json','["天地有大故，朝庭凶訃來。", "五年再罹苦，臣民若爲哀。", "鉅賢荷遺託，夢澤滂九垓。", "衣冠又新命，收淚心悠哉。"]'),
('d2740001-3964-4ab9-adb5-7ccf5650b290','離鄉','韋驤','宋','宋诗','song-poetry','','[]','奔走京塵已十年，治任西去興悠然。',64,'全唐诗/poet.song.41000.json','["奔走京塵已十年，治任西去興悠然。", "功名欲立非人致，才宦未伸還自憐。", "路柳得春多意思，野禽批水共連翩。", "孤舟獨載無人語，唯把空書考聖賢。"]'),
('2a864a02-3ffb-40a3-8323-de5d08b5ad46','過千金懷陸剛叔許顧道','韋驤','宋','宋诗','song-poetry','','[]','記得當年泛小舟，相将隨計冒殘秋。',64,'全唐诗/poet.song.41000.json','["記得當年泛小舟，相将隨計冒殘秋。", "故人笑語無緣合，今日煙波獨此由。", "老木戰風春尚淺，斷雲籠日雨方收。", "自惟我輩襟期在，碌碌誰甘便白頭。"]'),
('d38d09d8-882f-4783-a254-f1056279bc80','平望阻風','韋驤','宋','宋诗','song-poetry','','[]','大風嗥空聲烈烈，小舸逆牽饒卼臲。',64,'全唐诗/poet.song.41000.json','["大風嗥空聲烈烈，小舸逆牽饒卼臲。", "交跗擁鼻坐其中，蚤暮恍然難以别。", "利名無繩人自縈，山林無扃人自絕。", "區區冷官何足頼，奔走勤勞可嗟咄。"]'),
('e031b143-f5c3-4d2c-a2dc-4fac0214ccc4','題周開祖叢翠軒','韋驤','宋','宋诗','song-poetry','','[]','所居知所向，種竹接前簷。',48,'全唐诗/poet.song.41000.json','["所居知所向，種竹接前簷。", "翠色無時减，清風引日添。", "蕭疏共談麈，輝映祗書籤。", "碌碌夏畦病，輸君此養恬。"]'),
('43b310d2-1fba-4daf-9f81-5f66651486dd','汴上遇孫楚材','韋驤','宋','宋诗','song-poetry','','[]','春陰蔽日多飄風，二月凛冽猶窮冬。',64,'全唐诗/poet.song.41000.json','["春陰蔽日多飄風，二月凛冽猶窮冬。", "馭夫凌兢踏泥凍，旅况索莫填心胸。", "淑人邂逅獲交馬，語言浹洽欣相從。", "夜投孤驛共清飲，安得復訴瑠璃鍾。"]'),
('75373739-fb60-4075-b0f8-484c2a18482d','再和所酬','韋驤','宋','宋诗','song-poetry','','[]','萇弘滅跡已綿久，誰于二月爲隆冬。',64,'全唐诗/poet.song.41000.json','["萇弘滅跡已綿久，誰于二月爲隆冬。", "相逢詩酒得賢侣，遽使炎燠生吾胸。", "飲酣真趣不可壞，詩狂險韻皆能從。", "殷勤鄙句復叩激，自喜牙琴還遇鍾。"]'),
('8cfaca19-87fc-473b-ab2c-7df6f683e878','早行','韋驤','宋','宋诗','song-poetry','','[]','曉雞三唱已，戒馭復長郊。',48,'全唐诗/poet.song.41000.json','["曉雞三唱已，戒馭復長郊。", "殘雪籠河岸，初陽射柳梢。", "野人猶閉戶，宿鳥或依巢。", "而我何爲者，區區足自嘲。"]'),
('8ccdc9ce-5b6e-4985-9605-09291984d92c','宿零壁驛','韋驤','宋','宋诗','song-poetry','','[]','凄寒動春夕，覆被益重袍。',48,'全唐诗/poet.song.41000.json','["凄寒動春夕，覆被益重袍。", "鄉夢驚還遠，征途久覺勞。", "破窗留月影，古木任風號。", "聞戒無兵餽，剛腸獨佩刀。"]'),
('01ffb58e-15bf-4e0b-aff8-ce6ee0be705e','予枕屏書叔夜養生論而孫楚材觀之有詩相示遂次来韻以答','韋驤','宋','宋诗','song-poetry','','[]','枕外霜屏手自書，數千微指慰焦枯。',64,'全唐诗/poet.song.41000.json','["枕外霜屏手自書，數千微指慰焦枯。", "乘時豈羡鵬飛海，悖理須譏馬守閭。", "治氣飬心予所慕，長生久視古非無。", "喜君與我同兹好，免蠧當終學戶樞。"]'),
('b8692191-3360-47f7-b5bf-3384e4f36617','和黄彦文示詩','韋驤','宋','宋诗','song-poetry','','[]','執經今日再相從，快若鴻毛翼疾風。',64,'全唐诗/poet.song.41000.json','["執經今日再相從，快若鴻毛翼疾風。", "持己已憐仍舊好，力文還喜後来充。", "平蹊安肯容茅塞，美玉寧辭以石礱。", "顧我空空當考擊，愧無術學似河東。"]'),
('8265d4e0-e7fd-441e-af40-8377e7e98848','巖齋曉起','韋驤','宋','宋诗','song-poetry','','[]','曉起郊原寂，清風盥櫛傍。',48,'全唐诗/poet.song.41000.json','["曉起郊原寂，清風盥櫛傍。", "松梢泫微露，巖頂泛初陽。", "彷彿山禽語，飄零古殿香。", "携書寓疏拙，三伏化寒凉。"]'),
('308ffbf7-f18e-4e07-9007-bd2042511db0','寄陳安道','韋驤','宋','宋诗','song-poetry','','[]','同年同第復同門，計治同爲待次人。',64,'全唐诗/poet.song.41000.json','["同年同第復同門，計治同爲待次人。", "一紀清時共濡滯，兩身孤宦各艱辛。", "不要鐘鼎須耕道，未遂山林爲食貧。", "吾黨襟期當自信，且隨天意養輪囷。"]'),
('34003c6b-3903-46f6-9a1f-39434429a2cd','又和所示','韋驤','宋','宋诗','song-poetry','','[]','布鼓微聲強自信，兩篇響答語驚人。',64,'全唐诗/poet.song.41000.json','["布鼓微聲強自信，兩篇響答語驚人。", "連城自我忻懷寶，八字憑誰歎受辛。", "豈爲儻來輕有動，但能恬守即安貧。", "相期厚養忘多欲，莫似豚蹄祝滿囷。"]'),
('a184e73d-a207-4fd0-8a95-9b713bdcc681','七夕','韋驤','宋','宋诗','song-poetry','','[]','此夕流傳久不磨，相逢樽酒且酣歌。',64,'全唐诗/poet.song.41000.json','["此夕流傳久不磨，相逢樽酒且酣歌。", "竿垂阮服終成強，腹曬隆書顧幾何。", "漫道銀潢能限隔，未聞河鼓畏風波。", "樓間安用穿鍼乞，世上紛紛巧已多。"]'),
('f4dfe6d2-3877-4578-a879-65f015d4b1a5','七夕寄安道','韋驤','宋','宋诗','song-poetry','','[]','去年此夕我拘官，君挾魚軒到此安。',64,'全唐诗/poet.song.41000.json','["去年此夕我拘官，君挾魚軒到此安。", "自爾分馳數千里，豈圖今日一交懽。", "風萍離合光陰速，月桂交遊契分完。", "不倒玉壺終未已，待将河漢夜深看。"]'),
('7b9e77e4-388f-4447-b4eb-5f0bee53500a','附郭照鄰舟還鄉一首','韋驤','宋','宋诗','song-poetry','','[]','國門迴首氣葱葱，拜了君恩去意濃。',64,'全唐诗/poet.song.41000.json','["國門迴首氣葱葱，拜了君恩去意濃。", "故里華舟幸同載，鄰邦嘉士喜相從。", "高談浹洽情無畛，新句縱横筆有鋒。", "往往旁人多羡慕，主人况是郭林宗。"]'),
('f9b32c8f-6f23-41af-84ed-fd5d24e46c65','送郭照鄰赴南雄簽幕','韋驤','宋','宋诗','song-poetry','','[]','淺汴縈迴减迅流，綠榆疏薄弄殘秋。',64,'全唐诗/poet.song.41000.json','["淺汴縈迴减迅流，綠榆疏薄弄殘秋。", "蘭舟去指三千里，梅嶺前頭第一州。", "幕府久須賢者畫，朝廷最重遠民憂。", "近來選擢多超邁，竚聽君才不次酬。"]'),
('79dcfb8e-e6b1-4787-94cb-4959457c283d','汴舟早行二首  其一','韋驤','宋','宋诗','song-poetry','','[]','隱約短窗明，嘔啞兩櫓聲。',48,'全唐诗/poet.song.41000.json','["隱約短窗明，嘔啞兩櫓聲。", "曉寒衾外覺，鄉夢枕中驚。", "心喜親闈近，身從宦路輕。", "男兒棺未蓋，安可嘆虛生。"]'),
('f9863a56-d276-4a5b-af84-82475fa7e4b3','汴舟早行二首  其二','韋驤','宋','宋诗','song-poetry','','[]','容足豈無處，浮名浪自牽。',48,'全唐诗/poet.song.41000.json','["容足豈無處，浮名浪自牽。", "通宵不安寢，湍水正鳴船。", "旅况情何賴，家音遠未傳。", "凌晨飛棹急，聊以慰遷延。"]'),
('884d4cc3-3c51-4a89-852d-7a78f2113a31','延和引對','韋驤','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','昔年便殿拜恩光，今日重來慘肺腸。',64,'全唐诗/poet.song.41000.json','["昔年便殿拜恩光，今日重來慘肺腸。", "螭陛載瞻新侍從，龍顔如仰舊君王。", "星霜一紀逡巡過，膏澤三朝次第當。", "埃壒尚能禆泰嶽，豈無忠誼報明昌。"]'),
('0d4dc405-288a-450d-9449-832b128ab6ca','至泗即天長獨歸叙别照鄰','韋驤','宋','宋诗','song-poetry','','[]','長淮十月北風高，判袂臨津首屡搔。',64,'全唐诗/poet.song.41000.json','["長淮十月北風高，判袂臨津首屡搔。", "草草旅裝方攬轡，勤勤别酒更持螯。", "扁舟君去良多况，間道子歸豈憚勞。", "行矣餘杭期會在，早来江上看寒濤。"]'),
('4ff821d6-d316-46d6-b9f8-72049ba46299','再回前韻','韋驤','宋','宋诗','song-poetry','','[]','畫船東下櫓聲高，閃見旁舟堕玉搔。',64,'全唐诗/poet.song.41000.json','["畫船東下櫓聲高，閃見旁舟堕玉搔。", "張翰歸心鱸滿箸，畢公狂興蟹雙螯。", "朝餐餖飣唯論飽，夜語詼諧豈厭勞。", "乍聚乍離當不怪，夫君多可似山濤。"]'),
('79423c68-5fe7-4170-a3ec-a3fe5de39d04','無脚橋','韋驤','宋','宋诗','song-poetry','','[]','枘鑿關連壯，横空不可搖。',48,'全唐诗/poet.song.41000.json','["枘鑿關連壯，横空不可搖。", "激波無雁齒，跨岸只虹腰。", "改制千年取，傾舟衆患消。", "乘輿濟人者，爲惠固相遼。"]'),
('5313fede-a1cf-4054-b251-59e44e015e2d','離泗上','韋驤','宋','宋诗','song-poetry','','[]','曉霧鎖長淮，初陽熨未開。',48,'全唐诗/poet.song.41000.json','["曉霧鎖長淮，初陽熨未開。", "造舟行險滑，舁竹勢遲徊。", "迴野蒼茫合，嚴風浩蕩來。", "歸耕如有地，勞苦曷爲哉。"]'),
('5e0f16a6-0bc2-403c-9650-a247e7d6b399','避雨大明寺','韋驤','宋','宋诗','song-poetry','','[]','去時驟雨忽兼風，歇馬曾留此寺中。',32,'全唐诗/poet.song.41000.json','["去時驟雨忽兼風，歇馬曾留此寺中。", "今日來歸復如此，始知事有偶然同。"]'),
('68f80e18-befc-46c3-ab65-eb95e706e17a','和簡夫遊鼓山','韋驤','宋','宋诗','song-poetry','','[]','氣肅乾坤萬物秋，久違真概喜重遊。',64,'全唐诗/poet.song.41000.json','["氣肅乾坤萬物秋，久違真概喜重遊。", "高閒况奉挂冠樂，曠逸慚非蠟屐流。", "狂飲何羞吹帽落，時鮮豈必置船頭。", "鵬摶鷃集逍遥等，醉眼冥冥百事休。"]'),
('a0eca269-98a9-42af-b50a-1fff773ab208','申園席上口占','韋驤','宋','宋诗','song-poetry','','[]','涼秋池館燕閒身，密席榮驩主與賓。',64,'全唐诗/poet.song.41000.json','["涼秋池館燕閒身，密席榮驩主與賓。", "白日神仙分兩榜，青雲兄弟占三人。", "東籬瀟灑黄花好，北海風流淥酒醇。", "投轄更須防壤坐，夜深共醉月精神。"]'),
('b984c793-025d-4e02-b410-548ed6910a96','和李信臣遊南巖','韋驤','宋','宋诗','song-poetry','','[]','秋雲沓沓鎖秋巖，怪木森森蔭碧潭。',64,'全唐诗/poet.song.41000.json','["秋雲沓沓鎖秋巖，怪木森森蔭碧潭。", "遊騎去時平野曉，老僧迎處滿衣嵐。", "何人自塑臨泓水，近古遺棺撼石龕。", "我憶昔年曾此醉，却嗟今日輟陪參。"]'),
('2fbd56ee-4d84-4741-81dc-9171d519eff3','答信臣遺詩以失南巖約','韋驤','宋','宋诗','song-poetry','','[]','閒裏縈仍不自由，馳心空想碧巖秋。',64,'全唐诗/poet.song.41000.json','["閒裏縈仍不自由，馳心空想碧巖秋。", "連鑣獨遠朱蹄駿，釃酒還辜綠螘浮。", "嗟我數年遺覧歷，屬君一尺更遲留。", "定知清興難窮盡，莫便輕迴訪戴舟。"]'),
('14208cf8-a83e-44d3-af06-68be4ba56395','和南巖迴','韋驤','宋','宋诗','song-poetry','','[]','心舒還愛日，境勝欲忘歸。',48,'全唐诗/poet.song.41000.json','["心舒還愛日，境勝欲忘歸。", "茶戰弱一水，棋兵尚十圍。", "秋山終易冷，暮坐祇添衣。", "上馬迴首數，霜蟾逐蓋飛。"]'),
('6b2f73b3-ad68-4d7a-9723-5f22c2dfbd3c','簡夫丈約遊南巖時以婦翁室會遂渝爽依韻和其來篇','韋驤','宋','宋诗','song-poetry','','[]','巨源常少怪，第五豈無私。',48,'全唐诗/poet.song.41000.json','["巨源常少怪，第五豈無私。", "酒食先爲困，溪山輙負期。", "七年思舊賞，隔日誦新詩。", "康樂清遊在，隨軒别有時。"]'),
('6bc0f044-cf1a-428d-b2d0-60f5e4c26f2c','和信臣遊簡夫太丞申園','韋驤','宋','宋诗','song-poetry','','[]','洞門流水地仙家，棄祿歸來餌曉霞。',64,'全唐诗/poet.song.41000.json','["洞門流水地仙家，棄祿歸來餌曉霞。", "不比鍾山多怨語，未饒金谷足名花。", "風弦静舞千齡鶴，夜枕閒聽一部蛙。", "此樂人間無覓處，只應天畔有靈槎。"]'),
('00b6992b-65fa-4eb1-b574-95f27b6dec5e','又和','韋驤','宋','宋诗','song-poetry','','[]','一門清訓黄金賤，三葉榮名翠琰題。',64,'全唐诗/poet.song.41000.json','["一門清訓黄金賤，三葉榮名翠琰題。", "揚雀語言先世得，荀龍頭角後來齊。", "聯姻君喜重交好，高閈予慚早獨躋。", "試聽野人歌盛事，滿床牙笏當公圭。"]'),
('ce485772-730e-47b1-a85c-cea122c234db','和簡夫送信臣同年','韋驤','宋','宋诗','song-poetry','','[]','龍鳳當年共力攀，參辰異跡十年間。',64,'全唐诗/poet.song.41000.json','["龍鳳當年共力攀，參辰異跡十年間。", "相逢邂逅身爲客，叙别躊躇色動顔。", "北冀馬羣先駿逸，南山豹隱舊文斑。", "而今百里還淹止，行聽佳聲似魯山。"]'),
('40627a30-df13-4dbd-a546-e28023e0b31f','廬陵待試士呈伯升郎中','韋驤','宋','宋诗','song-poetry','','[]','重門晝鎖碧梧陰，秋氣凌虛日向深。',64,'全唐诗/poet.song.41000.json','["重門晝鎖碧梧陰，秋氣凌虛日向深。", "耳目暫清抛吏局，情懷終樂近書林。", "安排一月拘攣計，酬酢千人進取心。", "未榜試期饒暇逸，倚罇尤喜聽高吟。"]'),
('00fc124f-9d59-41ab-8c92-f882cee3518c','中秋夜','韋驤','宋','宋诗','song-poetry','','[]','人間此節號佳辰，鎖宿文場意自伸。',64,'全唐诗/poet.song.41000.json','["人間此節號佳辰，鎖宿文場意自伸。", "雨脚灑開秋氣象，雲頭放出月精神。", "坐無紅袖何妨樂，琖有芳醪不計巡。", "數句願歌今夕事，主人才力似陽春。"]'),
('7cde5e60-3120-4440-bd51-5aa7ac451fbc','贈别伯升','韋驤','宋','宋诗','song-poetry','','[]','士林佳譽久飛揚，脱跡初筵本異常。',64,'全唐诗/poet.song.41000.json','["士林佳譽久飛揚，脱跡初筵本異常。", "盡道清朝隱方朔，不知白髪困馮唐。", "古今議論千端勝，南北風情萬里長。", "乍會乍離勞景向，萍江樓上獨相望。"]'),
('019ff761-798c-47b9-8e17-48242edda066','又和來篇','韋驤','宋','宋诗','song-poetry','','[]','貢闈将畢意揚揚，日夕炎凉亦未嘗。',64,'全唐诗/poet.song.41000.json','["貢闈将畢意揚揚，日夕炎凉亦未嘗。", "幾聽秋聲廢高枕，屡乘月色坐中唐。", "雲牋寫句慚非敵，玉麈揮談服所長。", "款段匪朝歸冷僻，未知何以慰鄰望。"]'),
('c43ed64e-95a3-428c-a102-6f92d47160e7','陪吉守范淳元觀玉虛觀靈芝席上口占','韋驤','宋','宋诗','song-poetry','','[]','廬陵盛事照明昌，浩蕩西風八月凉。',64,'全唐诗/poet.song.41000.json','["廬陵盛事照明昌，浩蕩西風八月凉。", "賓履共隨紅旆去，仙宫新報紫芝芳。", "成非雨露寧無感，出近星辰别有祥。", "誰謂古書難盡信，眼看珍異答龔黄。"]'),
('1e89d518-e46a-4d41-a99e-f70cf3574806','寄題吉州三瑞堂','韋驤','宋','宋诗','song-poetry','','[]','珍祥疊疊遺廬陵，芝秀蓮雙瑞露清。',64,'全唐诗/poet.song.41000.json','["珍祥疊疊遺廬陵，芝秀蓮雙瑞露清。", "天意獨偏三物應，人心胥慶一堂成。", "壁間篇詠辭多實，席上樽罍勢自榮。", "早晚璽書褒治行，潁川遺美爲銷聲。"]'),
('ad7ccca0-684b-4f18-a21c-bb926322749e','送章少卿赴闕','韋驤','宋','宋诗','song-poetry','','[]','老成風跡藹中朝，威惠南邊久已勞。',64,'全唐诗/poet.song.41000.json','["老成風跡藹中朝，威惠南邊久已勞。", "三節召歸方汲汲，列城懷戀尚嗷嗷。", "郊原雨止車塵少，霄漢雲空旆影高。", "太上定嗟相見晚，佇聞秋覲拜恩褒。"]'),
('5dbc5aa3-66fe-4a2a-8144-8427fcd1fe77','和龔簿同辨金劍源','韋驤','宋','宋诗','song-poetry','','[]','兩源溪水弄清音，百丈山峰削翠琳。',64,'全唐诗/poet.song.41000.json','["兩源溪水弄清音，百丈山峰削翠琳。", "不顧衣冠當赤日，共看沙礫辨黄金。", "自緣世態嫌遺利，豈是吾儕枉用心。", "却憶去年并會樂，相逢又得叙離襟。"]'),
('bb2d8e07-d0f2-446b-9a4b-c71935392216','劉仲誠以武夷記見借','韋驤','宋','宋诗','song-poetry','','[]','自從見借武夷編，每一開編思渺然。',65,'全唐诗/poet.song.41000.json','["自從見借武夷編，每一開編思渺然。", "使我胸懷厭塵滓，羡君家世樂神仙。", "幔亭曾會千餘客，石洞元居十六天。", "何日訪靈尋翠壁，待将名字謾同雕鎸。"]'),
('4ef1603e-4d68-4a7e-bf3b-94a87eaca310','寄上高宰孫世則','韋驤','宋','宋诗','song-poetry','','[]','鄉間遊處景醇全，忽忽光陰二十年。',64,'全唐诗/poet.song.41000.json','["鄉間遊處景醇全，忽忽光陰二十年。", "官局舊嗟蹤跡遠，封人今喜信音傳。", "才驅繁劇君應易，事奪清閒我獨然。", "畏簡未能成會合，且持詩句寫拳拳。"]'),
('223f2059-f7fd-4b48-9a0e-b956819821dd','道中寄景升仲誠二同官','韋驤','宋','宋诗','song-poetry','','[]','兩道幾千里，殘炎七月天。',48,'全唐诗/poet.song.41000.json','["兩道幾千里，殘炎七月天。", "纍囚念濡滯，匹馬重遷延。", "夜宿荆榛際，朝行虎豹前。", "幡思竹軒好，擁事亦神仙。"]'),
('100cf4de-6426-4ec3-87ef-90ed1473c346','巴陵訊囚所居附岳陽樓前  其一','韋驤','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','雙扉晝鎖夜傳呼，訊鞫勞心跡也拘。',32,'全唐诗/poet.song.41000.json','["雙扉晝鎖夜傳呼，訊鞫勞心跡也拘。", "祗有清虛慰懷抱，開軒即是洞庭湖。"]'),
('bdfa8d35-e4a5-4f48-83a8-be5b0ed4d8a8','巴陵訊囚所居附岳陽樓前  其二','韋驤','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','洞庭湖上岳陽樓，舊走聲名徧九州。',32,'全唐诗/poet.song.41000.json','["洞庭湖上岳陽樓，舊走聲名徧九州。", "今日偶來猶吏事，幸當風月近中秋。"]'),
('f7282195-e9ce-4a74-abd2-8e478df649f9','洞庭秋四首  其一','韋驤','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭秋旦好，餘霧尚懷山。',48,'全唐诗/poet.song.41000.json','["洞庭秋旦好，餘霧尚懷山。", "日色一竿際，波光萬頃間。", "宿商鳴櫓去，夜網得魚還。", "佳趣知多少，濡毫恨思慳。"]'),
('cc54c9ce-923f-43a3-b87d-9d08eacab67d','洞庭秋四首  其二','韋驤','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭秋晝永，氣象坐中分。',48,'全唐诗/poet.song.41000.json','["洞庭秋晝永，氣象坐中分。", "浩蕩三江水，蒼茫萬里雲。", "君山壓波面，民舍傍城根。", "自昔看圖畫，今焉過所聞。"]'),
('51226151-c3cc-4c2e-91dd-79cf2bf7c118','洞庭秋四首  其三','韋驤','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭秋薄暮，日脚返滄溟。',48,'全唐诗/poet.song.41000.json','["洞庭秋薄暮，日脚返滄溟。", "雲氣天涯赤，峰巒水上青。", "歸舟來隱隱，夕鳥去冥冥。", "鼓瑟音何在，空聞帝子靈。"]'),
('67b03a38-239a-4f55-9b84-67d9ed36356c','洞庭秋四首  其四','韋驤','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭秋夕爽，皎月瑩長空。',48,'全唐诗/poet.song.41000.json','["洞庭秋夕爽，皎月瑩長空。", "顥氣重湖接，清光四望通。", "樓開雲母扇，人在水晶宫。", "勝絕無窮景，蕭條萬古同。"]'),
('ad8939b7-db6d-44ba-87e7-4e7e63b3418a','寄示二小子','韋驤','宋','宋诗','song-poetry','','[]','學自辛勤富，名從曠怠休。',48,'全唐诗/poet.song.41000.json','["學自辛勤富，名從曠怠休。", "癡慵迴爾意，扞格慰吾憂。", "股刺難須著，鄰光豈用偷。", "當知漢唐世，家緒有公侯。"]'),
('f0bae006-ff42-48f3-bd93-dee68c721fca','洞庭即事  其一','韋驤','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','日車閃閃下山椒，風陣蕭蕭掠柳條。',64,'全唐诗/poet.song.41000.json','["日車閃閃下山椒，風陣蕭蕭掠柳條。", "湖上晚秋天氣爽，樓間極目客魂銷。", "湘妃哀怨馮誰聽，楚屈英靈何處招。", "竊祿無田歸未得，浪吟當此愧漁樵。"]'),
('787136fc-4d4d-4350-8f47-ca7f2df462a1','洞庭即事  其二','韋驤','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','浪頭卷白去無垠，山面鋪青一色勻。',64,'全唐诗/poet.song.41000.json','["浪頭卷白去無垠，山面鋪青一色勻。", "氣象清雄無處比，情懷跼促此中伸。", "欹危釣艇唯堪望，倉猝商帆不用嗔。", "顧我遽來非自任，也知牽制爲官身。"]'),
('ca61eb0b-6f1c-4adb-9547-bdda321c7847','君山','韋驤','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭波上崪高峰，翠色難将别岫同。',64,'全唐诗/poet.song.41000.json','["洞庭波上崪高峰，翠色難将别岫同。", "真籍從來標福地，大鈞于此費神功。", "蛟龍拗怒深深避，星月流光面面通。", "塵跡未能乘興往，據鞍迴首正秋風。"]'),
('30cad606-9f74-4de6-93cb-496ef9b713bc','岳陽樓','韋驤','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','岳陽樓句舊空傳，今日登臨一慨然。',64,'全唐诗/poet.song.41000.json','["岳陽樓句舊空傳，今日登臨一慨然。", "不是洪鈞有偏黨，豈容勝概獨完全。", "山川形勢三千里，基構聲華五百年。", "襟带西南太平世，收羅風月屬私權。"]'),
('8d153087-3104-47e2-9efb-264283bbc2a4','曉起','韋驤','宋','宋诗','song-poetry','','[]','落月光微暝靄收，一軒瀟灑旅懷幽。',64,'全唐诗/poet.song.41000.json','["落月光微暝靄收，一軒瀟灑旅懷幽。", "湘君山外波濤曉，麋子城邊草木秋。", "俗吏區區易情倦，古人皦皦志空求。", "且希月廩從官給，仰事孤親潔膳羞。"]'),
('e1acb92c-30f7-435c-ab1f-9fcb85deba09','閲金科','韋驤','宋','宋诗','song-poetry','','[]','得情猶勿喜，聖訓所宜欽。',48,'全唐诗/poet.song.41000.json','["得情猶勿喜，聖訓所宜欽。", "取正存三尺，持平在一心。", "摭文唯恨密，麗罪莫求深。", "豈必于虞輩，源流定可尋。"]'),
('8257eaa1-c1ce-4730-b669-44cfcad0576b','和朱伯英新州詩見寄二首  其一','韋驤','宋','宋诗','song-poetry','','[]','武川當日一分襟，會合乖期向武林。',64,'全唐诗/poet.song.41000.json','["武川當日一分襟，會合乖期向武林。", "從此參辰不相比，由來歲月漸加深。", "書郵遠道煩新寄，詩社前盟約再尋。", "何以報君雙白璧，南樓高處獨縈心。"]'),
('fd8219c3-9007-4e58-908e-6dbb906e31d6','和朱伯英新州詩見寄二首  其二','韋驤','宋','宋诗','song-poetry','','[]','吏冗拘人好思慳，憐君遠遠發昏頑。',64,'全唐诗/poet.song.41000.json','["吏冗拘人好思慳，憐君遠遠發昏頑。", "梅花嶺外題詩寄，萍實江邊繼韵還。", "數幅密緘迢遞去，寸誠都寫别離間。", "翻思舊日賡酬樂，鼓譟當時更有顔。"]'),
('0f2be9f7-5bfe-4f96-822e-9aaad50c5cd6','送潘簿還侍下','韋驤','宋','宋诗','song-poetry','','[]','四見霜花始解官，綵衣還侍肯盤桓。',64,'全唐诗/poet.song.41000.json','["四見霜花始解官，綵衣還侍肯盤桓。", "胸中事業仍加益，篋裏經書不廢看。", "立馬仙山風帽側，移舟秀水露帆寒。", "銓衡論奏恩輝近，早寄佳聲遺我懽。"]'),
('a7fe7f6e-e74a-4636-91ca-6904b15bf1f1','送周廣之令桂陽','韋驤','宋','宋诗','song-poetry','','[]','猶餘殘雪凝山椒，已見新春上柳條。',64,'全唐诗/poet.song.41000.json','["猶餘殘雪凝山椒，已見新春上柳條。", "引領不能成面别，寄詩空欲减魂消。", "爲言民社遷官重，莫嘆湖湘去路遥。", "早向縣廷舒所欲，如君風跡定翹翹。"]'),
('7b97eda4-3e99-419a-93df-3e3b8bd5725b','安遠道中','韋驤','宋','宋诗','song-poetry','','[]','晚穿亂水踏欹危，曉度空山瘴霧飛。',64,'全唐诗/poet.song.41000.json','["晚穿亂水踏欹危，曉度空山瘴霧飛。", "今日戒途甘險阻，古來謀事重依違。", "行詢野叟觀其欲，静究州圖記所非。", "走徧封疆收定議，黄花時節合東歸。"]'),
('049c021c-b3ea-4541-a797-c9919c33261e','金精巖','韋驤','宋','宋诗','song-poetry','','[]','回巖萬仞透青冥，造化功偏竅鑿精。',64,'全唐诗/poet.song.41000.json','["回巖萬仞透青冥，造化功偏竅鑿精。", "自是神仙乘福地，豈因諼詐誘愚兵。", "金牀舊跡知何在，石鼓遺歌僅可評。", "塵淟暫来心已悟，靈場千古爲蒼生。"]'),
('20a5411d-e295-487f-8974-0783656ef68c','遊金精迴書朝陽巖觀壁','韋驤','宋','宋诗','song-poetry','','[]','秋入羣峰氣象清，朝陽才過到金精。',32,'全唐诗/poet.song.41000.json','["秋入羣峰氣象清，朝陽才過到金精。", "勝遊却向塵勞得，此日清懷慰此行。"]'),
('d7cfdd15-40d1-4c94-aeb8-2a5d7bbe5a23','板石驛','韋驤','宋','宋诗','song-poetry','','[]','童山皆戴石，淺水屢縈村。',48,'全唐诗/poet.song.41000.json','["童山皆戴石，淺水屢縈村。", "路接猿猱險，雲兼瘴霧昏。", "披榛投舍館，藉草展行樽。", "吏役身無定，天涯一斷魂。"]'),
('2e7f1281-a001-4f99-b596-455f14684e70','中秋午夜和溪看月','韋驤','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','去歲中秋别岳陽，洞庭湖外望清光。',64,'全唐诗/poet.song.41000.json','["去歲中秋别岳陽，洞庭湖外望清光。", "今年衮衮仍行役，此日蕭蕭復異鄉。", "林葉泛輝兼玉露，水波搖影接銀潢。", "出船聊踞胡床坐，遠負高樓列酒觴。"]'),
('e1da70e8-4b85-4323-b457-7d87bd2f30c9','登欎孤臺  其一','韋驤','宋','宋诗','song-poetry','','[]','區區倦翼傍旌旄，獨上名臺滯思逃。',64,'全唐诗/poet.song.41000.json','["區區倦翼傍旌旄，獨上名臺滯思逃。", "章水背流餘派合，崆山前隱獨峰高。", "萬家井落氛埃絕，千里喉襟氣象豪。", "一見荆川勝侯印，况将佳趣慰塵勞。"]'),
('1afaff5b-e353-424f-b0a8-473c7e89503b','登欎孤臺  其二','韋驤','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','去年秋宿洞庭湖，今日登臨在欎孤。',64,'全唐诗/poet.song.41000.json','["去年秋宿洞庭湖，今日登臨在欎孤。", "兩處風流皆勝絕，一身奔走亦崎嶇。", "光搖二水看雲斷，翠滴千山愛日晡。", "吏役不容清興足，放船回首望城隅。"]'),
('b3ec7328-c94c-4b4b-9109-e96b49a0e919','過贛石','韋驤','宋','宋诗','song-poetry','','[]','乘危趨疾固輕身，却羡操舟妙入神。',32,'全唐诗/poet.song.41000.json','["乘危趨疾固輕身，却羡操舟妙入神。", "石罅安船石頭立，漁人謾笑往來人。"]'),
('84d60c5c-8ad0-46e0-acff-b76c7e584a2e','天柱灘','韋驤','宋','宋诗','song-poetry','','[]','密密贛灘三百里，此灘崛起最峥嶸。',32,'全唐诗/poet.song.41000.json','["密密贛灘三百里，此灘崛起最峥嶸。", "中原柱石知多少，安用江心濫得名。"]'),
('358b4ed1-cfc2-4498-b8e2-b6b87e2cab32','九月八日離虔','韋驤','宋','宋诗','song-poetry','','[]','明日重陽日，章江獨放船。',48,'全唐诗/poet.song.41000.json','["明日重陽日，章江獨放船。", "豈無時節興，固有簡書牽。", "殘暑猶争際，餘雷忽霈然。", "詰朝晴氣爽，忍負菊花天。"]'),
('0bcfd909-4d5a-4950-ab7a-f9b9da3166ca','九月八日薄晚離贛城十餘里而雷雨作遂倚舟以宿九日曉行又十餘里而逆風暴甚乃泊於白鷴灘側虔之史君相留不可屢以亟行見謔今日會賓席間當語及濡滯以爲笑矣因書以自戲云','韋驤','宋','宋诗','song-poetry','','[]','佳辰來可喜，久客去難論。',48,'全唐诗/poet.song.41000.json','["佳辰來可喜，久客去難論。", "爲憶東籬菊，因辭北海罇。", "逆風吹急浪，單舸泊孤村。", "緬想茱萸宴，盧胡有後言。"]'),
('1779acdb-215a-48c5-998f-29f555c90b14','至萬安','韋驤','宋','宋诗','song-poetry','','[]','西風蕭瑟作秋聲，遠客歸心信水程。',64,'全唐诗/poet.song.41000.json','["西風蕭瑟作秋聲，遠客歸心信水程。", "雙石尖尖雙鷺立，一灘渺渺一舟行。", "酒杯無侣難成飲，詩句非奇謾寫情。", "晚泊沙頭從杖履，故鄉何在眼空明。"]'),
('3a21e0ca-e662-4801-9f35-e70bb8546740','和孫世則著作新年見寄  其一','韋驤','宋','宋诗','song-poetry','','[]','不奉清譚一紀餘，相期情分愈於初。',64,'全唐诗/poet.song.41000.json','["不奉清譚一紀餘，相期情分愈於初。", "數篇秀句鋒誰敵，累幅華牋手自書。", "芸省聯曹雖喜共，萍江製邑獨慚疏。", "如君才術當超卓，安見飛黄困守閭。"]'),
('57dc3a7d-c08d-4b0d-9f3b-e86e32521d20','和孫世則著作新年見寄  其二','韋驤','宋','宋诗','song-poetry','','[]','剸繁芟弊力無餘，行學存心負厥初。',64,'全唐诗/poet.song.41000.json','["剸繁芟弊力無餘，行學存心負厥初。", "凍筆方驅囂訟牒，解頤忽得故人書。", "分襟固久情還密，領邑雖鄰跡也疏。", "安得同時俱代去，相從山水樂吾閭。"]'),
('3aabfc52-4a5a-426f-a98b-60539c835ba9','行年','韋驤','宋','宋诗','song-poetry','','[]','行年四十志方剛，一任蓬鬆兩鬢蒼。',64,'全唐诗/poet.song.41000.json','["行年四十志方剛，一任蓬鬆兩鬢蒼。", "道在忽愁施設地，心恬寧感利名場。", "本無畎畝爲私計，只有詩書可自強。", "努力終非素餐輩，未堪回首顧滄浪。"]'),
('60b3c990-7e9f-4cf1-84eb-95315414f58e','宿新樂驛','韋驤','宋','宋诗','song-poetry','','[]','去秋村北宿僧床，今夕村南寓驛堂。',64,'全唐诗/poet.song.41000.json','["去秋村北宿僧床，今夕村南寓驛堂。", "官僕頗諳蹊逕熟，野人應笑往來忙。", "敝裘不耐春寒甚，老馬猶堪山路長。", "獨酌獨詩還獨寐，此中清况亦難忘。"]'),
('1c5dead0-bdd8-41e5-a2e6-752815eba194','之虔推劾道遠雨甚念從隸之勞','韋驤','宋','宋诗','song-poetry','','[]','山雨淋頭急，岡泥沒骭深。',48,'全唐诗/poet.song.41000.json','["山雨淋頭急，岡泥沒骭深。", "從驅爾何罪，行役我甘心。", "抑鞚憂難趁，分裝恐不任。", "蘇樵復稀遇，寒氣少相侵。"]'),
('9d62e5ea-9153-4192-b385-2c8ddd8ae865','安福驛','韋驤','宋','宋诗','song-poetry','','[]','作邑多離邑，去家如去鄉。',48,'全唐诗/poet.song.41000.json','["作邑多離邑，去家如去鄉。", "三年三過驛，一别一迴腸。", "治績安能勝，征途逎備嘗。", "何時腰解印，長嘯入餘杭。"]'),
('6efeb089-9b5b-44bd-b992-8479e4dff4f4','喜晴','韋驤','宋','宋诗','song-poetry','','[]','今年未見日，指數兩經旬。',48,'全唐诗/poet.song.41000.json','["今年未見日，指數兩經旬。", "清旦初開霽，元功始布新。", "溪流徐變綠，林囀便知春。", "吏役方長道，油雲莫更瞋。"]'),
('64a87a11-c8ef-483b-bd20-4d07c2c181d3','南昌鐡柱','韋驤','宋','宋诗','song-poetry','','[]','南昌昔謂水浮州，鐡柱支持事更幽。',64,'全唐诗/poet.song.41000.json','["南昌昔謂水浮州，鐡柱支持事更幽。", "天地有爐勞一鑄，蛟螭無穴解羣憂。", "槎牙露處幾三尺，搖撼徒然踣萬牛。", "人頼旌陽恩力大，此功何愧禹功優。"]'),
('d46dca74-568f-4db2-80dd-1549f468cc08','寒食','韋驤','宋','宋诗','song-poetry','','[]','春來二十日，寒氣尚稜稜。',48,'全唐诗/poet.song.41000.json','["春來二十日，寒氣尚稜稜。", "萬甲殊未坼，新雷徒已曾。", "山禽鳴瑟縮，道馬足凌兢。", "節候無驚異，江南舊所稱。"]'),
('dbf4f2a4-70da-49bd-bf1d-e018923e9e8a','贛州鞫劾呈同事鄧宰德夫','韋驤','宋','宋诗','song-poetry','','[]','二月春寒倍覺深，雙扉晝鎖柏庭陰。',64,'全唐诗/poet.song.41000.json','["二月春寒倍覺深，雙扉晝鎖柏庭陰。", "修途遠至勞雖甚，雅誼相親喜不任。", "窮覈須繄顓用智，哀矜當亦共存心。", "纍囚未引猶紓暇，濁酒那辭細細斟。"]'),
('cef06f1b-4408-48a8-90fc-2f20a2e27e2c','次韻和同時到院','韋驤','宋','宋诗','song-poetry','','[]','各沿臺檄會平番，萍水金谿隔萬山。',64,'全唐诗/poet.song.41000.json','["各沿臺檄會平番，萍水金谿隔萬山。", "兩處相期仗官驛，一時交際到江關。", "如何遠趾符同甚，豈是誠心吻合間。", "案牘牽仍毋易視，囚情未得莫優閒。"]'),
('4e5b5412-2d10-448a-ad50-e7f05a8f83a4','鎖院深寂夭桃獨芳有可憐之色爲詩要德夫共賦以賞之','韋驤','宋','宋诗','song-poetry','','[]','静院深扃霽雨新，小桃牆側弄精神。',64,'全唐诗/poet.song.41000.json','["静院深扃霽雨新，小桃牆側弄精神。", "祇知春色歸吾眼，不悟他鄉寄此身。", "露蕊妖韶真自得，胭脂濃淡屬誰勻。", "共将短句酬幽艷，奚獨東風是主人。"]'),
('696b6ea4-c083-444a-8603-86b5e0605d31','二月十六日感雨示同事','韋驤','宋','宋诗','song-poetry','','[]','燭燼遺朝几，爐烟出晝簾。',48,'全唐诗/poet.song.41000.json','["燭燼遺朝几，爐烟出晝簾。", "時春驚一半，山雨悵相兼。", "吏局如巢寄，家音以鵲占。", "敢思遊觀樂，同患滯囚淹。"]'),
('9d328793-d9d3-42a8-a116-46c54458adae','訊鞫有閒呈德夫','韋驤','宋','宋诗','song-poetry','','[]','同時鎖深院，輪日直寒廳。',96,'全唐诗/poet.song.41000.json','["同時鎖深院，輪日直寒廳。", "所得期無喜，忘情在不經。", "桃心隨雨碎，柳眼向人青。", "早晚連鑣去，春郊約罄瓶。", "案積雲堆影，庭虚谷應聲。", "榜笞非所事，杖履有餘清。", "静逕牽情數，芳林照眼明。", "相逢得佳侣，尤足慰營營。"]'),
('11e75ca5-4254-4b42-aaf9-234961c5881f','次韻德夫推院有感','韋驤','宋','宋诗','song-poetry','','[]','薄宦予嗟少定蹤，賢勞君歎久西東。',64,'全唐诗/poet.song.41000.json','["薄宦予嗟少定蹤，賢勞君歎久西東。", "相從山國春多雨，共憶公園花已叢。", "酒約倒杯忻有伴，詩尋險韻懼無功。", "勤乘閒隙酬清興，便與分襟櫂短篷。"]'),
('643fdbb4-e801-44e3-a115-56201c74f83b','惜春  其一','韋驤','宋','宋诗','song-poetry','','[]','皦皦春陽上柳尖，輕輕朝霧亦相兼。',64,'全唐诗/poet.song.41000.json','["皦皦春陽上柳尖，輕輕朝霧亦相兼。", "教雛老雀穿雕栱，失伴狂蜂入翠簾。", "深院難将飛絮鎖，空階且任落花黏。", "惜春情味從來甚，今日江城興倍添。"]'),
('5da9c8d0-130e-45f0-9a47-eeaa4c71acb2','惜春  其二','韋驤','宋','宋诗','song-poetry','','[]','二月已破三月來，吟詩空憶少陵才。',64,'全唐诗/poet.song.41000.json','["二月已破三月來，吟詩空憶少陵才。", "簷前有意殘花堕，雲裏無情旅雁迴。", "何處輪蹄蹂芳草，誰家絲管上高臺。", "吾儕局外添嬰繞，此段襟懷強自開。"]'),
('0f343a14-a3f3-4764-9322-6a98af30a0e3','次韻社日且以善謔','韋驤','宋','宋诗','song-poetry','','[]','社日江南眼屢經，春天嶠北寄春城。',64,'全唐诗/poet.song.41000.json','["社日江南眼屢經，春天嶠北寄春城。", "雙飛海燕知時節，半醉田翁舞泰平。", "謾把杯盤爲小飲，頻催案牘况垂成。", "却思廉割東方朔，歸遺那無動旅情。"]'),
('62659f26-0133-44d8-8466-b19023ad1736','復假前韻爲即事二詩且言别于卒章  其一','韋驤','宋','宋诗','song-poetry','','[]','煙花苒苒裹江亭，雲靄紛紛接暮城。',64,'全唐诗/poet.song.41000.json','["煙花苒苒裹江亭，雲靄紛紛接暮城。", "物態除非詩可寫，旅懷唯藉酒能平。", "燕知社節來何早，鶯怯春寒語未成。", "非晚與君分袂去，他時當記此時情。"]'),
('230b6bd7-9d63-4c6b-96cb-acf1d7d3282f','復假前韻爲即事二詩且言别于卒章  其二','韋驤','宋','宋诗','song-poetry','','[]','浩如潮水出東溟，勇似雲梯破鐡城。',64,'全唐诗/poet.song.41000.json','["浩如潮水出東溟，勇似雲梯破鐡城。", "談柄交揮逾月久，吟毫相抗幾時平。", "清驩返向塵勞得，佳集元非計構成。", "還守邑疆相望遠，隴煙江月若爲情。"]'),
('3e303931-2439-4893-9738-d15f8c960885','上巳日贛川憶東湖  其一','韋驤','宋','宋诗','song-poetry','','[]','韶光強半已消除，嶠北芳華眼不辜。',64,'全唐诗/poet.song.41000.json','["韶光強半已消除，嶠北芳華眼不辜。", "黄鳥穿林金閃鑠，紫荆鋪地錦糢糊。", "持循畏簡催胥吏，整頓歸鞍戒僕夫。", "傳語東風爲加意，少留花卉在東湖。"]'),
('7d9c69e1-1ad0-407c-b62a-b12bb7747d09','上巳日贛川憶東湖  其二','韋驤','宋','宋诗','song-poetry','','[]','曉風吹雨過溪南，春色晴光三月三。',64,'全唐诗/poet.song.41000.json','["曉風吹雨過溪南，春色晴光三月三。", "燕觜啄泥方汲汲，杏梢欹水正酣酣。", "樽庖冷落俱能耐，刀筆縈仍豈自甘。", "珠閣簾堂應好在，待教門外繫歸驂。"]'),
('29ffc922-9903-4ca3-877a-c6ce8c6fff04','再用前韻爲感春喜會二首酬德夫  其一','韋驤','宋','宋诗','song-poetry','','[]','五侯門館映交衢，點檢春光肯暫辜。',64,'全唐诗/poet.song.41000.json','["五侯門館映交衢，點檢春光肯暫辜。", "教舞庭除紅錦藉，看花窗牗碧紗糊。", "侈心忘理雖兒女，樂事乘時亦丈夫。", "而我拘攣過佳節，豈無船在賀家湖。"]'),
('b4fe3818-daa9-4c1c-9144-01c5d4c4cc36','再用前韻爲感春喜會二首酬德夫  其二','韋驤','宋','宋诗','song-poetry','','[]','東風爛漫巨江南，林薄餘花十二三。',64,'全唐诗/poet.song.41000.json','["東風爛漫巨江南，林薄餘花十二三。", "隱隱游絲飛日影，娟娟戲蝶舞春酣。", "獨旗共愛茶芽嫰，佳境俱憐芋蔗甘。", "談屑不宜虛永晝，長岐分背謾停驂。"]'),
('0f6ef622-a586-4517-a955-00abb4e52efa','春杪書懷三十韻呈同事鄧令','韋驤','宋','宋诗','song-poetry','','[]','覆囚将訖事，春杪興蹉跎。',288,'全唐诗/poet.song.41000.json','["覆囚将訖事，春杪興蹉跎。", "亭館依游好，雲天氣候和。", "江山秀色遠，桃李綠陰多。", "燕熟巢仍補，鶯新語尚訛。", "逕深無過轍，門閴可張羅。", "雨漬苔錢積，風旋柳絮渦。", "落花衝蟻陣，側葉露蜂窠。", "朝霧開如掃，晴絲蕩不梭。", "鳴禽多了了，舞蝶並傞傞。", "物意良俱得，人情亦自阿。", "軒窗資坐嘯，杖履起行歌。", "屋角鶱飛翼，簾旌動翠波。", "畫圖連璧带，香穗接庭蘿。", "筆穎牽詩癖，茶槍戰睡魔。", "清談屢揮麈，酣飲必空螺。", "語射憐當鵠，論書憶換鵝。", "九霄明日月，萬國富山河。", "輕减中原役，韜藏絕塞戈。", "壯猶攄闊略，嵬論闢么麽。", "束帛丘園走，封軺驛傳過。", "拔才方迅疾，飬拙且婆娑。", "鳬鶴形難壹，鷦鵬好自頗。", "痔醫榮足賤，墦乞詐宜訶。", "投步安夷坦，存心謝揣摩。"]'),
('2b71a2d9-480d-41ae-b503-1ae1e409b7f3','次韻和鄧德夫再和書懷别用三十韻','韋驤','宋','宋诗','song-poetry','','[]','飛文侔羽檄，執議有金科。',288,'全唐诗/poet.song.41000.json','["飛文侔羽檄，執議有金科。", "于役同之贛，夫君僅自鄱。", "相逢多所樂，末禮去其苛。", "魚詠蒸然罩，材忻茂者莪。", "窮姦摧狡穴，辨枉愈綿痾。", "日食餚幾變，宵憂寐欲吪。", "恤冤防夏旱，驅害逐春儺。", "覈實當由已，指蹤奚自他。", "囚衣應足蝨，吏案已勝駝。", "居似蛇存蟄，歸如繭化蛾。", "險途須屢叱，行旅勿輕呵。", "白雪風中絮，青錢水上荷。", "佳辰憐爽曠，秀句好彫瑳。", "束卷儒風舊，嚴裝武貎番。", "分岐茲泮渙，迴首則猗那。", "蟻酒慵爲酌，藜羮糝不鹺。", "輕遺逸士帽，倒踏謫仙靴。", "恍忽東西驛，躊躇上下波。", "嚶鳴忻得侣，妖艷况方瘥。", "引脰鄰于鶴，離腸迥若沱。", "版徒猶相武，筆吏解封酇。", "易失時兼勢，難淹軸與薖。", "莘耕方釋耒，磻釣亦收蓑。", "勉力攀翔鳳，何心躍遁騾。"]'),
('ce5c7d1f-0bb9-4251-93d2-154bf4e80530','紫荆花','韋驤','宋','宋诗','song-poetry','','[]','紫艷暮春庭，少陵詩思清。',48,'全唐诗/poet.song.41000.json','["紫艷暮春庭，少陵詩思清。", "老蛟蟠曲幹，丹礦綴繁英。", "花譜元無品，春工别有情。", "不隨桃李色，俗眼莫相輕。"]'),
('c2db503d-31ef-420a-9daf-71b93eb6d230','寄元真州','韋驤','宋','宋诗','song-poetry','','[]','春陰蕩盡見春妍，立馬長坡思渺然。',64,'全唐诗/poet.song.41000.json','["春陰蕩盡見春妍，立馬長坡思渺然。", "望斷雙旌已難見，聲聞五袴只空傳。", "遥知裁割常虛刃，應賞風光蚤布筵。", "不省玉人歌闋處，紅梅多少落樽前。"]'),
('69352958-e47b-4022-91a2-36e5460b94dd','荆林道中示孫張二君','韋驤','宋','宋诗','song-poetry','','[]','西風掠雨作朝寒，聯馬相将入亂山。',64,'全唐诗/poet.song.41000.json','["西風掠雨作朝寒，聯馬相将入亂山。", "愧從使車無補助，敢辭征馭歷間關。", "日邊帝闕瞻猶遠，雲下親闈念未還。", "旅思紛紛何以慰，間求佳論一開顔。"]'),
('e87f1174-0a12-4be5-b9fb-74faa6bcd274','再用前韻和孫正甫所示','韋驤','宋','宋诗','song-poetry','','[]','畫船同出汴渠灣，天末雲收數點山。',64,'全唐诗/poet.song.41000.json','["畫船同出汴渠灣，天末雲收數點山。", "共應辟書離魏闕，誰持别酒唱陽關。", "閒論浙右經年事，此去膠東幾日還。", "男子有爲須遠趾，誰能轅下久低顔。"]'),
('f7e7d00f-6247-4f84-b0b6-74de25d939ec','膠水道中逢九日呈温伯舍人','韋驤','宋','宋诗','song-poetry','','[]','繡衣膚使出東州，九日旌軒不暫留。',64,'全唐诗/poet.song.41000.json','["繡衣膚使出東州，九日旌軒不暫留。", "固有誠心當倚注，肯緣佳節廢詢求。", "馬蹄遠踐天涯路，雁翼横飛海角秋。", "安得一樽黄菊酒，代公冰飲過宵休。"]'),
('b57b4f9c-05d1-41ed-95eb-7063c8fc711a','再用前韻謝和詩二首','韋驤','宋','宋诗','song-poetry','','[]','雖知自古有言酬，倍獲佳篇却重留。',64,'全唐诗/poet.song.41000.json','["雖知自古有言酬，倍獲佳篇却重留。", "襲璞固宜資一笑，報瑶何意足多求。", "詞源浩若江河注，筆力成如造化秋。", "詢度餘閒吟詠作，豈非夫子德公休。"]'),
('6a5288eb-fbee-425d-9e35-8220ee77652e','九月十八夜宿萊州海廟夜分登亭望月觀海呈伯温舍人','韋驤','宋','宋诗','song-poetry','','[]','晝從旌旗過碧山，夜陪巾履望漫漫。',64,'全唐诗/poet.song.41000.json','["晝從旌旗過碧山，夜陪巾履望漫漫。", "蛟龍睡著風波静，鴻雁影低星月寒。", "不極清光分島嶼，無邊爽氣接欄干。", "此時此興真夷曠，莫作塵遊一等看。"]'),
('40b30368-db6d-478c-b127-c5fb5c5d0c81','出東萊城示海傍觀者','韋驤','宋','宋诗','song-poetry','','[]','老稚相携出翳林，玉沙堤上聽車音。',64,'全唐诗/poet.song.41000.json','["老稚相携出翳林，玉沙堤上聽車音。", "便安赤子朝廷意，補助清時使者心。", "畎畝均休無一役，歲時賑乏有千金。", "東人祇見東溟闊，不識君恩似海深。"]'),
('fc0c4463-7bdb-474e-ab5a-b8c2b7ca3aa7','再和孫正甫音字韻呈舍人','韋驤','宋','宋诗','song-poetry','','[]','峨峨氣格冠書林，落落文章叩玉音。',64,'全唐诗/poet.song.41000.json','["峨峨氣格冠書林，落落文章叩玉音。", "暫别諫垣虛讜論，聊持使節慰焦心。", "紅塵翠靄飄衣繡，紫幅黄油護印金。", "采盡輿情将入告，謀謨誰得見精深。"]'),
('526c1a23-8435-4e61-a1f2-3ebc1c59de23','九月二十二日黄縣道中遇雪','韋驤','宋','宋诗','song-poetry','','[]','九日登州路，西風暴作威。',48,'全唐诗/poet.song.41000.json','["九日登州路，西風暴作威。", "黄桑猶半在，白雪已交飛。", "慣見邦人眼，難當旅客衣。", "來思尚稽詠，遽此對霏霏。"]'),
('efff84a4-0f7b-43fa-abd6-8feff809130e','将至登州','韋驤','宋','宋诗','song-poetry','','[]','長途冉冉馬蕭蕭，風勢横來带雪飄。',64,'全唐诗/poet.song.41000.json','["長途冉冉馬蕭蕭，風勢横來带雪飄。", "雁隊去成鏵觜陣，螘樽行向劍頭挑。", "氣清肝膈詩還健，寒切肌膚酒易消。", "顧我不才無寸補，徒瞻使騎旆旌搖。"]'),
('d5e3a1bb-2738-4245-a044-f3e5e495840e','聞潮','韋驤','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','錢塘江上吾家近，慣聽秋潮動地鳴。',32,'全唐诗/poet.song.41000.json','["錢塘江上吾家近，慣聽秋潮動地鳴。", "今日蓬莱于役處，却疑身在故鄉行。"]'),
('0d0f69b7-4ed9-4051-9dd5-dd7c27efbfb6','和淮陽顔長道見寄','韋驤','宋','宋诗','song-poetry','','[]','冉冉征途似夢間，相從未幾又先還。',64,'全唐诗/poet.song.41000.json','["冉冉征途似夢間，相從未幾又先還。", "却思前日同清會，不若當年醉碧山。", "别去載懷眉宇舊，書來重說鬢毛斑。", "吾儕固有襟期遠，肯向明時容易閒。"]'),
('b146c934-1294-4c7a-be42-2177a90303b6','登蓬萊閣','韋驤','宋','宋诗','song-poetry','','[]','行盡東州到此州，登臨更盡北山頭。',64,'全唐诗/poet.song.41000.json','["行盡東州到此州，登臨更盡北山頭。", "孤城突兀連滄海，三島參差聳暮秋。", "廣座下疑鼇負石，危簷遠學蜃爲樓。", "蓬萊方丈雖冥邈，高閣今朝亦勝遊。"]'),
('187e1fc9-d9ba-4f47-8ec7-c019831ef3de','和孫正甫二首  其一','韋驤','宋','宋诗','song-poetry','','[]','馬頭今日向西行，不比來時道路生。',64,'全唐诗/poet.song.41000.json','["馬頭今日向西行，不比來時道路生。", "與子聯鑣下長阪，無人迴首望高城。", "疏林積葉牛閒卧，衰草牽風兔自驚。", "詩思過于歸思好，征鴻斜襯落霞明。"]'),
('08917125-e158-4136-8648-6e9c174ab95b','和孫正甫二首  其二','韋驤','宋','宋诗','song-poetry','','[]','馬頭今日向西行，僕馭欣欣脚力生。',64,'全唐诗/poet.song.41000.json','["馬頭今日向西行，僕馭欣欣脚力生。", "白雪波濤離海國，黄金宫闕想京城。", "墻間笑語羣兒集，木末衝飛獨鳥驚。", "從此歸程宜倍道，解鞍須到衆星明。"]'),
('ea51b322-42a4-4efc-9576-99dd8b465b61','路疑  其一','韋驤','宋','宋诗','song-poetry','','[]','曉起仍行邁，征途一夢新。',48,'全唐诗/poet.song.41000.json','["曉起仍行邁，征途一夢新。", "雁低如有信，馬急似無塵。", "青訝山長雨，黄疑柳自春。", "此身從衮衮，奔走豈由人。"]'),
('7fdb030b-5a62-44ea-b815-e278bc3652f5','路疑  其二','韋驤','宋','宋诗','song-poetry','','[]','莫夜仍投宿，郵亭葺半新。',48,'全唐诗/poet.song.41000.json','["莫夜仍投宿，郵亭葺半新。", "風帷如漲海，煙蠟似征塵。", "白訝窗催曉，紅疑爐變春。", "歸期尚淹晚，鞅絆可尤人。"]'),
('1eba6d91-58ce-46ad-bcc5-e4b43d575d0c','遊齊州靈巖四首  其一','韋驤','宋','宋诗','song-poetry','','[]','征塵洶洶頓消磨，路入靈巖好趣多。',64,'全唐诗/poet.song.41000.json','["征塵洶洶頓消磨，路入靈巖好趣多。", "崖穴透空疑晝月，泉池凝淥似春波。", "錦帷香細薫千佛，金殿燈明覺衆魔。", "一宿禪房幸安穩，明朝騎馬又長坡。"]'),
('7bd8ec0c-a66b-4f5d-908d-ac1752cf1d2f','遊齊州靈巖四首  其二','韋驤','宋','宋诗','song-poetry','','[]','東國名高獨此巖，羣峰環抱自韜鈐。',64,'全唐诗/poet.song.41000.json','["東國名高獨此巖，羣峰環抱自韜鈐。", "道場岑寂規風古，禪室空疏杖喝嚴。", "木落有時飄殿角，雲寒終日蔽山尖。", "不知雙鶴歸何處，留得靈泉與衆甜。"]'),
('b96c1416-4be3-4429-b88c-5c1f4cecbb33','遊齊州靈巖四首  其三','韋驤','宋','宋诗','song-poetry','','[]','區區不覺路岐難，塵土衣冠喜動顔。',64,'全唐诗/poet.song.41000.json','["區區不覺路岐難，塵土衣冠喜動顔。", "已見成書歸上國，更逢便道覧名山。", "隨軒幸涉三時久，弭節仍陪半日閒。", "却與禪翁自相悦，繡衣雲步共追攀。"]'),
('2d119bf3-527c-4764-9b83-f635842c6413','遊齊州靈巖四首  其四','韋驤','宋','宋诗','song-poetry','','[]','雞鳴峰外日曈曨，欲去躊躇興未窮。',64,'全唐诗/poet.song.41000.json','["雞鳴峰外日曈曨，欲去躊躇興未窮。", "索筆請題青石柱，留名願附碧紗籠。", "重裘迥觸千山霧，迴轡輕隨一徑風。", "跋馬頻頻望蒼翠，他時應與夢魂通。"]'),
('f22e71a9-98c6-4b6e-a50a-8720d35d1a4a','再和顔長道見寄','韋驤','宋','宋诗','song-poetry','','[]','行役牽攣好思慳，詩筒旬浹未能還。',66,'全唐诗/poet.song.41000.json','["行役牽攣好思慳，詩筒旬浹未能還。", "驅馳東國黄塵路，夢想南鄉碧玉山。", "顧我俗情方充分衮衮，愛君佳句獨班班。", "再吟再和都緘寄，幸有冥鴻羽翼閒。"]'),
('2d823b42-7319-4fad-b79b-bce421605a4f','小雪後牡丹號朝天紅者開于縣宅西圃','韋驤','宋','宋诗','song-poetry','','[]','西林枯枿著繁霜，一品仙葩獨自芳。',64,'全唐诗/poet.song.41000.json','["西林枯枿著繁霜，一品仙葩獨自芳。", "天意似教驚世俗，歲寒方信屬花王。", "才迎曉日仍添色，不得春風也倍香。", "修竹茂松應內愧，後凋從此是尋常。"]'),
('84048f86-97eb-4f6d-87a0-9d7376b00b22','八月二十四日州牡丹','韋驤','宋','宋诗','song-poetry','','[]','八月西風動地來，枯株衰卉慘池臺。',64,'全唐诗/poet.song.41000.json','["八月西風動地來，枯株衰卉慘池臺。", "如何春色花王品，獨對霜威御史開。", "冷艷自然欺竹柏，清香足以薦樽罍。", "豈非千里寛羸俗，召得陽和暗裏迴。"]'),
('4a2c1b05-9137-4170-8aca-98633d65a329','寄橙與孫叔康','韋驤','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','金包磊落冒朝陽，煇映秋林氣燄長。',64,'全唐诗/poet.song.41000.json','["金包磊落冒朝陽，煇映秋林氣燄長。", "带露摘來盈翠籠，披雲擎去薦黄堂。", "野芹謾欲分微意，盃菊應嫌奪異香。", "沙上木奴還可貢，題書須待洞庭霜。"]'),
('065289ec-0524-4474-8466-6a8fda73f141','按水旱之灾将畢呈叔康太守','韋驤','宋','宋诗','song-poetry','','[]','使符星火急，騎馬徧郊原。',120,'全唐诗/poet.song.41000.json','["使符星火急，騎馬徧郊原。", "水旱生靈瘁，朝廷惠澤存。", "縱横来履畝，高下必分村。", "訴牒秋雲積，批毫墨電奔。", "豈無憂歲計，何敢隘君恩。", "不許胥徒欬，寧從僕馭繁。", "恐驚民室困，愁蹴路塵翻。", "縣令非能此，邦侯預戒言。", "流離烏忍去，愷悌莫輕論。", "輙代疲甿手，爲詩謝戟門。"]'),
('7f5cd489-b499-4251-99c7-00524c41400f','喜潘通甫迴郡','韋驤','宋','宋诗','song-poetry','','[]','傳道前騶入郡城，白狼山外一馳情。',64,'全唐诗/poet.song.41000.json','["傳道前騶入郡城，白狼山外一馳情。", "談鋒暌遠踰三月，使指間關涉幾程。", "我獨賢勞肯嗟嘆，國之武備藉經營。", "公餘未省詩多少，願借滄浪許濯纓。"]'),
('8b5ac88b-319c-4965-a0f3-9f7c3fc78f96','和潘通甫芍藥十韻','韋驤','宋','宋诗','song-poetry','','[]','衆卉已蕭索，朱欄始盛開。',120,'全唐诗/poet.song.41000.json','["衆卉已蕭索，朱欄始盛開。", "尚先秋後菊，肯羡臘前梅。", "秀出絲頭軟，紅深膾縷堆。", "疏明憐點襭，巧麗愛重臺。", "倍得花神力，偏當吏部才。", "雨枝成堕髻，風葉自扶腮。", "彩筆真難寫，金刀未易裁。", "狂香晴轉暴，醒態曉方迴。", "議品須推貴，論功鄙接栽。", "仙宫疑彷彿，安得不徘徊。"]'),
('18dfe0b3-f786-4f15-b048-22a7fa018ef6','暑雨言懷和潘倅十八韻','韋驤','宋','宋诗','song-poetry','','[]','暑雨應時至，年來民氣和。',216,'全唐诗/poet.song.41000.json','["暑雨應時至，年來民氣和。", "池塘假灔澦，畎畝小滹沱。", "跧縮栖梁燕，淋浪貼水荷。", "一番新滌垢，何處不盈科。", "旦市猶無蹟，寒門愈可羅。", "庭柯均見濯，簷溜獨成波。", "獵子愁收弋，田翁喜荷蓑。", "蜂衙忘刻候，蛙吹恣吟哦。", "篋恨書生蠧，場憂麥化蛾。", "凉風颯以度，清興迥然多。", "公退書帷寂，詩餘道服拖。", "雖非侔擊玉，僅可比鳴鼉。", "屢促低弦軫，頻傾濁酒蠡。", "自存惟浩氣，兼養類菁莪。", "衣葛疏仍補，羮藜淡不鹺。", "百瓴舒足力，六字習心呵。", "未有焚魚興，寧爲扣角歌。", "茲辰拜高詠，適足慰蹉跎。"]'),
('7c9410ba-84d8-4316-8c42-a492f323e078','和孫叔康九日三首  其一','韋驤','宋','宋诗','song-poetry','','[]','樓壓西城埤堄重，使君才思浩無窮。',64,'全唐诗/poet.song.41000.json','["樓壓西城埤堄重，使君才思浩無窮。", "芳罇泛出陶潛菊，健筆吟成老杜風。", "西座一時飛大白，雙旌盡晚卷深紅。", "自憐遠蹟違高會，九月篇章亦幸同。"]'),
('a265727d-334a-49e6-bd47-3960194c2c44','和孫叔康九日三首  其二','韋驤','宋','宋诗','song-poetry','','[]','使旆登高拂曉来，賢賓道舊喜追陪。',64,'全唐诗/poet.song.41000.json','["使旆登高拂曉来，賢賓道舊喜追陪。", "東籬黄菊因時盛，北海清樽趁節開。", "簾幕雲收見洲渚，笙簫風引下樓臺。", "新詩侑酒窮佳興，不惜當筵恥執罍。"]'),
('8ceedbd9-d299-494f-b129-73be26375dda','和孫叔康九日三首  其三','韋驤','宋','宋诗','song-poetry','','[]','區區冷色度凉秋，不得乘時奉勝遊。',64,'全唐诗/poet.song.41000.json','["區區冷色度凉秋，不得乘時奉勝遊。", "九日杯觴雖獨遠，一番珠玉幸兼收。", "紫萸隨分浮金盞，明月還能照荻洲。", "欲寫蕭條才思拙，臨牋尤愧乏銀鉤。"]'),
('1ee729ea-261f-4b67-878c-6de4808e0a7b','和潘通甫芍藥','韋驤','宋','宋诗','song-poetry','','[]','牡丹謝後覺荒凉，此艷中興百步香。',64,'全唐诗/poet.song.41000.json','["牡丹謝後覺荒凉，此艷中興百步香。", "莫誚雕欄當晚節，須知名卉絕羣芳。", "金刀剪處雲霞被，翠籠擎來錦繡裳。", "别乘殷勤華府宴，應将花譜議前王。"]'),
('9c1189ca-4334-4e58-b4d4-7b08b9eee949','和叔康侍親遊琅山  其一','韋驤','宋','宋诗','song-poetry','','[]','晚揚紅旆出郊關，晝奉安輿上碧山。',64,'全唐诗/poet.song.41000.json','["晚揚紅旆出郊關，晝奉安輿上碧山。", "野色蒼茫雲色外，嵐光飛動水光間。", "行庖薦饌烹金鼎，荷劍挑罇結玉環。", "歸路邦人瞻慶侍，銀龜朱紱照酡顔。"]'),
('3506a71f-b6f7-443a-b75e-57fa806bf5d7','和叔康侍親遊琅山  其二','韋驤','宋','宋诗','song-poetry','','[]','五十如嬰孝慕難，公餘綵服侍登山。',64,'全唐诗/poet.song.41000.json','["五十如嬰孝慕難，公餘綵服侍登山。", "回頭民社千閭密，引望鄉關一水間。", "暫奉清遊臨佛界，都将塵事付莊環。", "憑誰畫與東州看，刺史何如閔與顔。"]'),
('40e41ba2-a368-49e3-bbcd-53445f2e31d8','和孫叔康以詩寄芋','韋驤','宋','宋诗','song-poetry','','[]','清淳一闋聽塤篪，磊落堆盤享芋鴟。',32,'全唐诗/poet.song.41000.json','["清淳一闋聽塤篪，磊落堆盤享芋鴟。", "拙令此時心飫足，暫忘野外有民饑。"]'),
('1f9b0ea3-bcd1-469f-9851-4894d9e555e4','琅山聽竇山人琴','韋驤','宋','宋诗','song-poetry','','[]','秋深危閣氣凄清，來聽先生促軫聲。',64,'全唐诗/poet.song.41000.json','["秋深危閣氣凄清，來聽先生促軫聲。", "一曲寫成君子操，七弦傳盡古人情。", "游雲簷外如将合，幽鳥枝間不敢鳴。", "未省琴心在何處，高山流水對前楹。"]'),
('beb6ff93-e64d-444d-9d0e-8e736d82fbf7','又和孫太守琅山席上','韋驤','宋','宋诗','song-poetry','','[]','薄霧輕籠曉日黄，攀從旌旆到禪坊。',64,'全唐诗/poet.song.41000.json','["薄霧輕籠曉日黄，攀從旌旆到禪坊。", "坐憐古木榮枯慣，仰笑秋雲聚散忙。", "酒約覆盆分甲乙，詩成擊鉢互宫商。", "興酣猶恨嚴闉逼，少促歸鞭趁月光。"]'),
('09cfa5a9-366d-4c50-98af-e7bc9cf65cc5','和潘通甫六月十二夜月','韋驤','宋','宋诗','song-poetry','','[]','去望猶三夕，光華宛矣同。',216,'全唐诗/poet.song.41000.json','["去望猶三夕，光華宛矣同。", "炎天幾及半，午夜喜當中。", "爽氣乾坤滿，清輝宇宙通。", "恍瞻銀界白，遽失火雲紅。", "庭葉霜花泛，池波雪色融。", "閭閻消烈暑，寥廓散輕風。", "快若離深甑，飄然出大籠。", "秋毫歸一鑒，宿翳却千重。", "誰弄桓伊笛，徒思范蠡篷。", "魁杓俄轉北，箕尾漸回東。", "林静疏瑶圃，橋虛臥玉虹。", "餘凉入幽室，暗霧泫深叢。", "緯象光仍小，銀河派自洪。", "依希太清境，彷彿廣寒宫。", "鳥宿羣疑定，人閑萬慮空。", "調琴閒對客，酌酒旋呼童。", "莫語身兼世，休論萍與蓬。", "且來明月下，舉白聽梧桐。"]'),
('385bc42c-408c-4485-ba20-8bab8488666b','送潘通甫沿牒淮東','韋驤','宋','宋诗','song-poetry','','[]','火雲燄燄野無風，淺澀河流小舸通。',64,'全唐诗/poet.song.41000.json','["火雲燄燄野無風，淺澀河流小舸通。", "尺紙遽傳朝命下，翼朝齊送使旌東。", "道間覧物應多感，職外成詩寓幾筒。", "王事念深忘畏景，賢勞安肯動胸中。"]'),
('09106065-91f5-4573-a390-81bd64e1ff39','和通甫見贈二首  其一','韋驤','宋','宋诗','song-poetry','','[]','幾年持養副天成，造次云爲必中程。',64,'全唐诗/poet.song.41000.json','["幾年持養副天成，造次云爲必中程。", "樂內何希儻來貴，畏知唯有白絲清。", "蓬瀛尚欠文章手，寰海徒傳學行聲。", "今日詩筒互酬唱，他時回記豈忘情。"]'),
('75c5ad19-e79d-4a50-a932-c77422b8e019','和通甫見贈二首  其二','韋驤','宋','宋诗','song-poetry','','[]','肝胆區區豈足矜，摶風寧復計鵬程。',64,'全唐诗/poet.song.41000.json','["肝胆區區豈足矜，摶風寧復計鵬程。", "未能名跡如山重，且固心誠似水清。", "學譬治畦猶失溉，文參擊缶不成聲。", "感君篇貺虛褒借，強抉蓁蕪寫鄙情。"]'),
('91e3e7f9-a7f3-4e2c-b149-a624b2de60c0','和通甫道中先寄','韋驤','宋','宋诗','song-poetry','','[]','神明不爽久𨈊跧，一望旌軒舊觀旋。',64,'全唐诗/poet.song.41000.json','["神明不爽久𨈊跧，一望旌軒舊觀旋。", "殘臘光陰江海上，新春消息柳梅間。", "傾風固喜同披霧，竊祿仍羞似抱關。", "更奉詩筒先寄貺，解頤高句動蒼顔。"]'),
('716aba17-0291-4012-b9fa-2e47b1fa4a08','和通甫同登慶和寺閣','韋驤','宋','宋诗','song-poetry','','[]','佛宫樓閣倚雲端，人世塵埃杳不干。',64,'全唐诗/poet.song.41000.json','["佛宫樓閣倚雲端，人世塵埃杳不干。", "萬里海光生目眩，半天風勢切肌寒。", "老僧指境依稀辨，往客題名次第看。", "一奉勝遊承健句，詩魔暗裏爲摧肝。"]'),
('9a3053e3-0b42-42da-b609-a332dc6c2e33','和潘通甫寄孫太守','韋驤','宋','宋诗','song-poetry','','[]','五馬傳呼盡避驄，二車行縣海壖東。',64,'全唐诗/poet.song.41000.json','["五馬傳呼盡避驄，二車行縣海壖東。", "歌聲被管騰新曲，酒盞垂蓮學倒蓬。", "迴馭望仙雙旆晚，戒程餘慶一帆風。", "拘攣不得陪供帳，只許區區鄙句通。"]'),
('e9e2f928-155c-45dc-953c-301bc55c3753','和潘通甫陳貼港道中作','韋驤','宋','宋诗','song-poetry','','[]','飛空恨乏王喬舄，擁弊幾如晏子裘。',64,'全唐诗/poet.song.41000.json','["飛空恨乏王喬舄，擁弊幾如晏子裘。", "興利略行田際港，冒寒仍上海邊樓。", "草埋古跡存荒壘，雲漏陽光見遠洲。", "不獨區區祗吏役，又隨軒旆作清遊。"]'),
('65212bd0-da1f-49c3-ae62-9688cae76e67','寄孫叔康','韋驤','宋','宋诗','song-poetry','','[]','歲華垂改月猶圓，寒夜長思一欿然。',64,'全唐诗/poet.song.41000.json','["歲華垂改月猶圓，寒夜長思一欿然。", "從政謾圖行幼學，濟民何術禦凶年。", "消憂姑酌賢人酒，託德唯瞻刺史天。", "安得居諸如過隙，早看麰麥被原田。"]'),
('aecf827f-40cc-42d1-8578-47b54cda780a','寄鄧舍人二首  其一','韋驤','宋','宋诗','song-poetry','','[]','頃隨旌旆按東州，一别門闌物再秋。',64,'全唐诗/poet.song.41000.json','["頃隨旌旆按東州，一别門闌物再秋。", "內誦德言如在耳，仰瞻雲步但昂頭。", "掖垣遥想絲綸暇，海角方深賑卹憂。", "安得此身如泛梗，區區能傍濟川舟。"]'),
('24f1173d-f100-4def-95e1-982870e0439d','寄鄧舍人二首  其二','韋驤','宋','宋诗','song-poetry','','[]','白髪書生意氣完，確然行學效民官。',64,'全唐诗/poet.song.41000.json','["白髪書生意氣完，確然行學效民官。", "九天宫闕心長在，萬里江河分亦安。", "屢愧姓名塵薦牘，豈論明類必彈冠。", "感公知遇如何報，唯有霜筠敵歲寒。"]'),
('13564887-4f8d-4e5e-8dce-1d04f7f92107','廷評慶壽口號','韋驤','宋','宋诗','song-poetry','','[]','納慶新春八十年，更逢誕日一開筵。',64,'全唐诗/poet.song.41000.json','["納慶新春八十年，更逢誕日一開筵。", "童顔鶴髪人間貴，道服烏巾地上仙。", "玉盞煇煇擎壽酒，金爐苒苒泛香煙。", "暫停絲管聽祈頌，願見恩書歷九遷。"]'),
('76376062-56c6-4270-8833-ea559acead2a','乙卯十二月十四日夜宿東禪僧舍','韋驤','宋','宋诗','song-poetry','','[]','簿書雖是不離身，一宿精廬興味真。',32,'全唐诗/poet.song.41000.json','["簿書雖是不離身，一宿精廬興味真。", "莫道後欄花未坼，夜來霜月豈慚春。"]'),
('66c706b0-b047-454a-a4da-d231acc42462','又題僧壁即事','韋驤','宋','宋诗','song-poetry','','[]','天地收功固欲全，朝廷恩惠豈容偏。',32,'全唐诗/poet.song.41000.json','["天地收功固欲全，朝廷恩惠豈容偏。", "饑羸大衆粟不足，縣令胡顔入俸錢。"]'),
('20b01aa5-a297-4d1b-b231-88d4228dc0f9','和潘通甫中春即事','韋驤','宋','宋诗','song-poetry','','[]','雜花交錯裹樓臺，二月向殘三月来。',64,'全唐诗/poet.song.41000.json','["雜花交錯裹樓臺，二月向殘三月来。", "塵跡遇時随分樂，酒樽逢景等閒開。", "幽禽有意名相喚，飛絮無情舞自回。", "遊覧莫爲頻數厭，逡巡便舉送春杯。"]'),
('be24013b-fb32-439b-b6cf-d9f2164eb518','和季春初牡丹花','韋驤','宋','宋诗','song-poetry','','[]','遶欄矜賞日千迴，賦詠慚無卓犖才。',64,'全唐诗/poet.song.41000.json','["遶欄矜賞日千迴，賦詠慚無卓犖才。", "天意似嫌羣卉雜，花王留在晚春開。", "曾經唐苑聲歌後，不是隋園剪綵來。", "安用繁言警躭惑，愛奇能有幾人栽。"]'),
('f991eacd-1152-4f22-9b35-c195daaee925','暮春對景書懷','韋驤','宋','宋诗','song-poetry','','[]','一番新雨洗樓臺，何處紅芳不爛開。',64,'全唐诗/poet.song.41000.json','["一番新雨洗樓臺，何處紅芳不爛開。", "春色漸隨流水去，薫風還入弄琴来。", "梁巢戢戢鳴雛燕，林葉陰陰覆老梅。", "遇景乘時須自適，江頭每到日西迴。"]'),
('635201ed-1034-4ecd-8f20-97ada5e75f72','和晚春雨霽','韋驤','宋','宋诗','song-poetry','','[]','油雲卷盡曉天明，風色融和日色輕。',64,'全唐诗/poet.song.41000.json','["油雲卷盡曉天明，風色融和日色輕。", "著處餘花知有命，一番綿雨喜初晴。", "園林經潤春難老，庭館無塵氣轉清。", "誰道東君忘所屬，此時於物特垂情。"]'),
('044b8df4-1b4e-4cf7-9503-1d2335dc787b','和落花','韋驤','宋','宋诗','song-poetry','','[]','春風幾日爲催開，却趁春風委翠苔。',64,'全唐诗/poet.song.41000.json','["春風幾日爲催開，却趁春風委翠苔。", "莫訝花王留不住，本緣真宰儻然来。", "暗隨蝶夢飄書榻，半逐鶯聲落吹臺。", "綠葉依依猶可愛，吟腸終日爲縈迴。"]'),
('818a4ce9-2357-4cbb-a945-469918311d6f','和木香花','韋驤','宋','宋诗','song-poetry','','[]','架竹引繁英，青羅簇素瓊。',48,'全唐诗/poet.song.41000.json','["架竹引繁英，青羅簇素瓊。", "潛卑寶相色，遠過瑞香清。", "被雨凝雲重，困風舞雪輕。", "憑誰變花譜，陞在最高名。"]'),
('3f481b29-ea57-4e60-abf0-f4a40c035460','和以雙頭牡丹贈叔康太守','韋驤','宋','宋诗','song-poetry','','[]','盈盈仙蘤忽雙開，似把輕羅一樣裁。',64,'全唐诗/poet.song.41000.json','["盈盈仙蘤忽雙開，似把輕羅一樣裁。", "綠蒂相扶真艷出，芳心齊送異香來。", "浪吟莫惜詩千首，爛賞何妨酒百盃。", "剪寄黄堂有餘愛，也應蝶夢不空迴。"]'),
('f54372e9-9860-477f-9162-319edceee2a2','和登琅山爲民祈福','韋驤','宋','宋诗','song-poetry','','[]','佛宫突兀枕琅山，金碧樓臺詰曲欄。',64,'全唐诗/poet.song.41000.json','["佛宫突兀枕琅山，金碧樓臺詰曲欄。", "霽雨願收田潦積，盛陽祈變麥秋寒。", "紅旌苒苒來何肅，赤子林林意自寛。", "早晚豐登應精懇，行看展報上層巒。"]'),
('8d0899f1-1d6b-4cb1-a6b0-0c6340428dc5','和書懷','韋驤','宋','宋诗','song-poetry','','[]','樸拙從来附會疏，恬然養內肯求無。',64,'全唐诗/poet.song.41000.json','["樸拙從来附會疏，恬然養內肯求無。", "自憐結髪遭平世，不愧孤蹤在坦途。", "一意固當知趣舍，百錢寧復問榮枯。", "鐘鳴鼎食非吾動，所得須論象罔珠。"]'),
('dc7f8347-d7b1-4862-a79f-f12da1b2c152','和晚晴書事','韋驤','宋','宋诗','song-poetry','','[]','圓荷貼水翠錢稀，風掠餘花片片飛。',64,'全唐诗/poet.song.41000.json','["圓荷貼水翠錢稀，風掠餘花片片飛。", "細雨有情容易歇，青春無繫等閒歸。", "樓頭晚鼓牽聲遠，海上雲山亂點微。", "坐喜民田見豐兆，幅巾談笑對殘暉。"]'),
('fa08fd1d-d213-492e-9b3f-19d0e95b76f1','和孫叔康探梅二十八韻','韋驤','宋','宋诗','song-poetry','','[]','臘過春将近，江梅想已苞。',288,'全唐诗/poet.song.41000.json','["臘過春将近，江梅想已苞。", "逢時在南國，探信出東郊。", "徑雪晴初掃，河冰薄易敲。", "尋香望林隙，驚素辨山坳。", "躍馬迴賓雁，飛旟懾蜡猫。", "初芳得消息，喜氣自并包。", "豈待鶯聲促，寧憂蝶足跑。", "先容爲桃李，脱跡遠蕭茅。", "此日花神睠，他年驛使譊。", "前騶傳已的，後乘聽猶聲。", "獨被陽功早，奚論地勢磽。", "新葩同衆閱，秀句仗誰抄。", "湛湛塵纓濯，纖纖痒背抓。", "金絲纔出莟，珠琲遍攢梢。", "攀折誠難忍，将承亦旋教。", "重疑仙界種，復過歲寒交。", "瑩潔疏情竇，精神動目窅。", "貪幽頻倚杖，薄晚倦迴鞘。", "有酒安辭釂，無魚孰嘆庖。", "輕裘忘擁腋，短髮任垂髾。", "坐不娛歌舞，盤非貴烙炮。", "量尊鍾與鼎，器隘斗兼筲。", "勇作先春計，甘從玩物嘲。", "瓊英行漸盛，玲賞莫輕抛。"]'),
('b3af29d4-4cb2-4e5a-9b8a-52f7321fd258','和觀雪二十韻','韋驤','宋','宋诗','song-poetry','','[]','紛紛隨朔吹，及物任洪纖。',240,'全唐诗/poet.song.41000.json','["紛紛隨朔吹，及物任洪纖。", "足以稱爲瑞，疏哉比撒鹽。", "朝飛收羽翼，夜象晦鉤鈐。", "農望先知喜，童心豈易厭。", "對疑銀界色，啖勝露華甜。", "寸隙期皆徧，微埃迥不兼。", "豪筵賓酒壯，遠塞虜兵殱。", "長坂愁羈旅，空山困隱潛。", "塵懷經歲撓，清興此時添。", "已變瓊鋪砌，還驚絮撲簾。", "扁舟誰念戴，采筆自追淹。", "野思生猶淺，詩情雅若爓。", "凝眸萬頃白，引袖六花尖。", "和寡思琴操，貲高憶酒簾。", "江潮雲蓋水，樓閣玉妝簷。", "折竹驚寒雀，衰葭擁暮鶼。", "冷官饒寂寞，僻邑飬安恬。", "坐患凶年久，行憂癘氣漸。", "探深評尺咫，均慶及閭閻。", "仰恃賢侯德，無勞太史占。"]'),
('5d48cfab-ee8e-45da-bd40-84451f82c5fe','和叔康席上  其一','韋驤','宋','宋诗','song-poetry','','[]','兩麾相遇百花春，煙海漫漫共此垠。',32,'全唐诗/poet.song.41000.json','["兩麾相遇百花春，煙海漫漫共此垠。", "席上笑談成秀句，一番傳詠樂邦人。"]'),
('75055d0b-1def-456d-b3fe-2a7c93a31537','和叔康席上  其二','韋驤','宋','宋诗','song-poetry','','[]','海上風光入暮春，使軒輕過古城垠。',32,'全唐诗/poet.song.41000.json','["海上風光入暮春，使軒輕過古城垠。", "琴臺此去猶千里，已有先聲慰昔人。"]'),
('e6a6eec4-8fa4-4c91-b49a-2a624f4270d8','哭路長吉','韋驤','宋','宋诗','song-poetry','','[]','器業本青雲，泥涂竟屈身。',48,'全唐诗/poet.song.41000.json','["器業本青雲，泥涂竟屈身。", "蓋棺窮海角，還葬大江濱。", "子幼今無怙，家清正苦貧。", "傳聞動歸旐，西望一沾巾。"]'),
('3f7a028c-b628-40f1-8edc-1ab0103cd9c5','和潘通甫頤齋書事','韋驤','宋','宋诗','song-poetry','','[]','簿領羈拘日少休，江山清興未能酬。',64,'全唐诗/poet.song.41000.json','["簿領羈拘日少休，江山清興未能酬。", "宓琴希弄緣誰咎，陶柳不栽還自謀。", "謾道庸庸多後福，豈甘泛泛祗隨流。", "高軒一過塵襟爽，旋折堂萱記酒籌。"]'),
('816b913d-a481-4d41-8163-fb7b907c3e0d','和中夏清虛堂','韋驤','宋','宋诗','song-poetry','','[]','碧玉闌干白石除，虛堂瀟灑聚書圖。',64,'全唐诗/poet.song.41000.json','["碧玉闌干白石除，虛堂瀟灑聚書圖。", "窗明晝可窺蚊睫，簷静時聞噪雀雛。", "凉吹東南生砌竹，繁陰朝夕在庭梧。", "主人襟量清如水，此段幽佳稱得無。"]'),
('8019f788-82b3-4f07-995d-226e825123ba','中夏偶成','韋驤','宋','宋诗','song-poetry','','[]','地交淮浙屬通川，官守區區改歲年。',64,'全唐诗/poet.song.41000.json','["地交淮浙屬通川，官守區區改歲年。", "鍳照自驚生鬢雪，感時還聽噪林蟬。", "鍾鳴鼎食何爲動，鶴引熊經似有緣。", "內樂無窮奚恤外，便便休誚孝先眠。"]'),
('4bed7486-c327-4911-93df-802ae7c60c20','和凌霄花','韋驤','宋','宋诗','song-poetry','','[]','翠蔓緣株上，紅芳冒暑開。',24,'全唐诗/poet.song.41000.json','["翠蔓緣株上，紅芳冒暑開。", "凌霄誠有謂，託質豈無媒。"]'),
('42a8a666-9e34-4dab-a8c3-5b1931c1d096','和餘慶道中','韋驤','宋','宋诗','song-poetry','','[]','荒凉古邑近東溟，時喜軒車出按行。',64,'全唐诗/poet.song.41000.json','["荒凉古邑近東溟，時喜軒車出按行。", "水鳥逆風如有向，晚蜺收雨似多情。", "心探畎澮豐年兆，目極雲沙遠思生。", "佳句更從清曠得，肯由塵事汩聪明。"]'),
('6667af62-7471-4e6c-8322-e17d8525e10d','和孫叔康中秋寄運判胡秘丞','韋驤','宋','宋诗','song-poetry','','[]','郡堞危樓夜氣清，江光海色接天平。',64,'全唐诗/poet.song.41000.json','["郡堞危樓夜氣清，江光海色接天平。", "凉秋一半無邊爽，皓月十分何太明。", "使者星軺行暫遠，史君兵釀恨徒傾。", "自憐負弩區區跡，却向澄霄望旆旌。"]'),
('85cdf7f8-af96-433a-ba40-a36108f79fbf','又借韻寄太守叔康','韋驤','宋','宋诗','song-poetry','','[]','城近江山夕靄澄，樓開欄檻與山平。',64,'全唐诗/poet.song.41000.json','["城近江山夕靄澄，樓開欄檻與山平。", "秋光正似鴻溝判，月影圓如白璧明。", "詩壓東陽臺上句，酒睎北海座中傾。", "荒壖拙令方匏繫，引脰西風畫隼旌。"]'),
('ae1afcb1-7773-40cf-a9e0-8f2caf32a742','和太守叔康以詩答桃','韋驤','宋','宋诗','song-poetry','','[]','鈴閣揮毫寫浩才，雲牋艷艷發松煤。',64,'全唐诗/poet.song.41000.json','["鈴閣揮毫寫浩才，雲牋艷艷發松煤。", "桃投愧匪千年種，瑶報榮誇十襲開。", "目送武陵佳實去，耳聽清廟雅音来。", "不龜獻藥嘗封地，未似芹誠致贈瑰。"]'),
('b9f80011-1965-43c2-9b28-846520f011e8','又借前韻謝惠茶','韋驤','宋','宋诗','song-poetry','','[]','靈芽産自越巖限，精製須調焙下煤。',64,'全唐诗/poet.song.41000.json','["靈芽産自越巖限，精製須調焙下煤。", "隱士寄題緘且密，使君分惠重其開。", "點疑白雪盈甌泛，啜恐清風兩腋来。", "却抒短章酬雅貺，畫墁何以謝瓊瑰。"]'),
('9185d759-0fec-4d93-b199-2817f0236ff5','寄橘柚','韋驤','宋','宋诗','song-poetry','','[]','海門橘柚勝湖湘，采獻鈴齋有意将。',64,'全唐诗/poet.song.41000.json','["海門橘柚勝湖湘，采獻鈴齋有意将。", "舊歲空希杜陵句，今年方報董涇霜。", "敢私磊落充賓豆，願貢甘香佐壽觴。", "藴藻可羞誠所致，厥包况是重維揚。"]'),
('54cc47ac-84ce-49bd-ba10-89be889933ae','送王聖途得代還青社','韋驤','宋','宋诗','song-poetry','','[]','坐嬰簿領久紛紛，解印終更興味新。',64,'全唐诗/poet.song.41000.json','["坐嬰簿領久紛紛，解印終更興味新。", "盡室圖書離海角，一船風雪渡淮濱。", "家山遠認雲門曉，里社行看孟宅春。", "術學似君須得路，早教馬足踏京塵。"]'),
('31cf0134-2dcd-4a1d-b0f3-5fd78be8c656','孫太守席賦催妝','韋驤','宋','宋诗','song-poetry','','[]','蘿蔓新懽可重誇，葭莩舊契轉增華。',64,'全唐诗/poet.song.41000.json','["蘿蔓新懽可重誇，葭莩舊契轉增華。", "閨門素守先生訓，牢巹來歸御史家。", "直戶三星乘節候，迎車百兩减浮奢。", "鵲橋深夜飛霜冷，早對菱花整鬢花。"]'),
('f7c80023-33f1-4927-9ff9-f2378d24a462','和孫叔康寄示上元','韋驤','宋','宋诗','song-poetry','','[]','聞說邦人慶上元，使君同樂具賓筵。',64,'全唐诗/poet.song.41000.json','["聞說邦人慶上元，使君同樂具賓筵。", "朱轓不得陪清賞，明月空能共此圓。", "和氣暗隨香穗散，微風輕送燭花偏。", "謾将鄙句追高會，已負當時白玉船。"]'),
('e5a36496-d543-444a-8838-d94a1256191e','和雪三十韻','韋驤','宋','宋诗','song-poetry','','[]','密雪連空散，同雲蓋野繁。',288,'全唐诗/poet.song.41000.json','["密雪連空散，同雲蓋野繁。", "朝暉掩羲馭，暮象蔽天垠。", "皦皦漫長陌，霏霏集短垣。", "杉松蒼翠奪，禽鳥語聲吞。", "病足樵斤斂，尋蹤獵騎奔。", "金莖迷沆瀣，銀界變崑崙。", "光借寒儒牖，威消貴胄門。", "酤簾表深巷，爨屋露幽村。", "可響紅爐燼，難忘醁酒樽。", "竹梢低欲折，梅蕚重猶存。", "沒谷吟當楚，離江咏去袁。", "高才題不盡，妙曲寫仍翻。", "旅雁宵飛戢，栖雞曉舌捫。", "塞嚴添玉壘，林迥化瓊園。", "遠岸舟藏鷁，高樓瓦匿鴛。", "秋濤千浪疊，夜甲萬軍屯。", "綴若凝酥潔，堆如琢琥蹲。", "脂車休旅傳，鏘佩放天閽。", "不以多爲瑞，誰言即也温。", "神鋒翦何利，地軸卷無痕。", "暗與春工敵，清隨朔吹噴。", "朽株銀作葉，圓沼璧爲盆。", "照耀偏宜月，侵陵只有萱。", "藩籬白羽插，略彴素虬蜿。"]'),
('52806864-e67c-4990-8d58-bb1b4b86521e','又和倒韻','韋驤','宋','宋诗','song-poetry','','[]','匿疵真有德，值物不偏恩。',288,'全唐诗/poet.song.41000.json','["匿疵真有德，值物不偏恩。", "細或穿幽隙，悠然被廣原。", "皚皚均旦暮，浩浩壹乾坤。", "凛冽添寒氣，蒼茫返混元。", "鵠鷗潛失影，狐貉暗忘魂。", "竹重風旌褭，池凝曉鑑昏。", "飛毫玉兔脱，蟠徑素龍蜿。", "陵弱侵庭柳，埋青抑砌萱。", "屑瓊誰措手，鍊粉若爲盆。", "當迥墻頭積，迴飈瓦口噴。", "羣飛停啅噪，萬醜掩瘢痕。", "窮巷情方憚，豪堂勢自温。", "蕭條孤驛路，冷落古祠閽。", "亂轍分明印，雙鴟彷彿蹲。", "何時飄絮定，著處白雲屯。", "酒榼傾浮螘，吟牋染戲鴛。", "妙才窺賦象，佳興襲遊園。", "冰鑑清相照，瑶枝俯可捫。", "剡舟那遽載，郢唱且重翻。", "啖齧深憐武，栖遲酷愛袁。", "韓詩高孰抗，謝賦久仍存。", "肅肅東方騎，優優北海樽。", "危樓登郡堞，遠目瞰江村。", "摛藻踰梁苑，申嚴過棘門。"]'),
('2787b9ee-d2f5-422d-b6b7-0ef0a6a254be','陳次全長春軒','韋驤','宋','宋诗','song-poetry','','[]','聞道新軒外，長春日日花。',48,'全唐诗/poet.song.41000.json','["聞道新軒外，長春日日花。", "幽人自薖軸，佳卉對葩華。", "波浪千重險，煙雲一望賒。", "徒思故園舊，短句寄君家。"]'),
('4cca4769-10c5-4e94-b4b6-69ffcbbe73b3','太守孫叔康下車','韋驤','宋','宋诗','song-poetry','','[]','榮過故里擁朱輪，乞得偏城便奉親。',64,'全唐诗/poet.song.41000.json','["榮過故里擁朱輪，乞得偏城便奉親。", "道路尚驚持斧使，衣冠猶是避驄人。", "下車懇懇唯宣澤，瀕海元元正食貧。", "草木無情還自喜，霜威不見見陽春。"]'),
('998bc2b8-1643-4fe1-ae97-67fed91cd351','别叔康','韋驤','宋','宋诗','song-poetry','','[]','數年爲邑幸焉依，德論源源每霽威。',64,'全唐诗/poet.song.41000.json','["數年爲邑幸焉依，德論源源每霽威。", "瓜代逡巡驚易及，棠陰躑躅忍輕違。", "倦蹤方此從塵路，旅夢多應遶繡衣。", "迴首海城煙霧杳，願聞三節召公歸。"]'),
('80bc987b-4f02-4fdc-95ef-4f60b058684a','復用叔康送篇韻和答','韋驤','宋','宋诗','song-poetry','','[]','岸柳參差影畫橋，雲横日薄旆旌高。',64,'全唐诗/poet.song.41000.json','["岸柳參差影畫橋，雲横日薄旆旌高。", "贈言有寵榮褒衮，制錦無功愧釋刀。", "苒苒征途行漸遠，拳拳德表望空勞。", "仰銜顧遇知何似，負戴丘山過巨鼇。"]'),
('8e967d3b-baec-470a-8e8f-eae8b51c2286','京口别叔康','韋驤','宋','宋诗','song-poetry','','[]','舳艫幸會艤江干，再别情悰豈易安。',64,'全唐诗/poet.song.41000.json','["舳艫幸會艤江干，再别情悰豈易安。", "坐邑三年師愷悌，歸程累日奉盤桓。", "金山寺外波濤曉，鐡甕城頭草木寒。", "欲上孤舟又南望，何時重戴觸邪冠。"]'),
('fb42b6cc-76c5-46c4-809f-2c1698fb2915','昨日以事不得陪赴和甫學士之召','韋驤','宋','宋诗','song-poetry','','[]','藩侯遣亊風霆疾，御史高談宇宙寛。',64,'全唐诗/poet.song.41000.json','["藩侯遣亊風霆疾，御史高談宇宙寛。", "千里幾年成遠别，一樽相對盡清懽。", "知無紅袖翻新曲，想有琱弓敵暮寒。", "塵跡鉤牽違燕集，坐追佳興入毫端。"]'),
('e5aa1cfd-4a73-4b5f-86e9-a59f4f937dda','蒜山酒','韋驤','宋','宋诗','song-poetry','','[]','蒜山高閣直連雲，酒以山名味獨醇。',64,'全唐诗/poet.song.41000.json','["蒜山高閣直連雲，酒以山名味獨醇。", "玉盞横飛光照眼，金罍滿泛氣迴春。", "幕天欲似劉生頌，卧甕寧爲畢卓身。", "須信主人如此酒，酣酣千里醉深仁。"]'),
('1ec6092d-85aa-468b-b5b0-86c558714937','和潘倅通甫遊狼山寺三首  其一','韋驤','宋','宋诗','song-poetry','','[]','川原浩蕩杳回環，附郭蒼然獨此山。',64,'全唐诗/poet.song.41000.json','["川原浩蕩杳回環，附郭蒼然獨此山。", "殿閣栖雲長苒苒，庵巖度日自閒閒。", "凋零花草三春後，彷彿閻閭十里閒。", "遠邑拘攣聞勝覧，馳心闇逐旆旌還。"]'),
('c924ee1c-0545-477c-948c-fd9a0a6bce15','和潘倅通甫遊狼山寺三首  其二','韋驤','宋','宋诗','song-poetry','','[]','參天雲木覆危岡，下瞰叢林釋氏坊。',64,'全唐诗/poet.song.41000.json','["參天雲木覆危岡，下瞰叢林釋氏坊。", "圖按古今詢露井，水分淮浙看風檣。", "清才得景吟還健，浩氣登高力更強。", "公暇此遊真可樂，紛紛何算少年場。"]'),
('baece3b9-bd44-4681-9fb4-a6bf9414c75f','和潘倅通甫遊狼山寺三首  其三','韋驤','宋','宋诗','song-poetry','','[]','譙門南向是狼山，車馬朝行意思寛。',64,'全唐诗/poet.song.41000.json','["譙門南向是狼山，車馬朝行意思寛。", "風散落花紅糝糝，日隨飛蓋翠團團。", "望窮滄海塵寰小，坐逼空巖晝景寒。", "三伏生秋有餘地，無人畫與雍州看。"]'),
('4b8073f6-134e-445e-a810-a46ad845f4af','和行海門','韋驤','宋','宋诗','song-poetry','','[]','畫船輕過綠楊灣，風掠雙旗勢自翻。',64,'全唐诗/poet.song.41000.json','["畫船輕過綠楊灣，風掠雙旗勢自翻。", "筆吏濡毫寫新句，厨人鱠玉薦行樽。", "翩翩舞燕随檣影，一一驚鷗破水痕。", "按部從容有佳趣，蒼煙落日肯銷魂。"]'),
('584a285e-5a22-4b8f-be50-8f153517d2a0','和金沙道中晚景','韋驤','宋','宋诗','song-poetry','','[]','海燕飛如織，紅花巧勝裁。',48,'全唐诗/poet.song.41000.json','["海燕飛如織，紅花巧勝裁。", "春光随水去，野色向人來。", "葦薄農家露，林疏古寺開。", "扁舟暫跧縮，曠望指層臺。"]'),
('5ab2eeaa-1054-4666-9092-d54579f8ecdb','謝通甫寄交藤方并氣術圖','韋驤','宋','宋诗','song-poetry','','[]','仰高誠府日欽欽，翰墨飛光忽見臨。',64,'全唐诗/poet.song.41000.json','["仰高誠府日欽欽，翰墨飛光忽見臨。", "練氣指迷先六字，餌丹傳訣勝千金。", "仁人錫類多推己，塵跡知非早有心。", "聊抒小詩酬厚賜，自慚布鼓若爲音。"]'),
('83ca5256-cdd7-4e90-9061-9c21bfb29f1f','和叔康首夏書懷五首  其一','韋驤','宋','宋诗','song-poetry','','[]','催得春歸始自安，杜鵑啼血血應乾。',64,'全唐诗/poet.song.41000.json','["催得春歸始自安，杜鵑啼血血應乾。", "晴林日永午陰重，烟海風多曉氣寒。", "壯志經時嗟苒苒，蒼顔覧照愧團團。", "公餘且學田家飲，也勝沙場引櫝丸。"]'),
('f2b45bc5-e375-464e-9365-913a534763a8','和叔康首夏書懷五首  其二','韋驤','宋','宋诗','song-poetry','','[]','清和氣候爽衣冠，海邑稀逢柱礎乾。',64,'全唐诗/poet.song.41000.json','["清和氣候爽衣冠，海邑稀逢柱礎乾。", "朝拂玉徽琴韻緊，夜開寶匣劍光寒。", "肺腸似石終難變，利祿如沙豈易團。", "行學但知無所負，奚爲逢射與僚丸。"]'),
('4b74b764-45c7-4400-a565-80d8bad6d081','和叔康首夏書懷五首  其三','韋驤','宋','宋诗','song-poetry','','[]','阮屐因山固少完，陶巾緣酒未嘗乾。',64,'全唐诗/poet.song.41000.json','["阮屐因山固少完，陶巾緣酒未嘗乾。", "庭疏紅藥三春過，地近滄溟四月寒。", "堂燕語酣如有訴，林蜂衙退自分團。", "太平吏隱真夷曠，安用機心寓臘丸。"]'),
('60018e98-6a95-4646-9270-f24ad1d96fec','和叔康首夏書懷五首  其四','韋驤','宋','宋诗','song-poetry','','[]','區區並海作民官，手裏魚須竹已乾。',64,'全唐诗/poet.song.41000.json','["區區並海作民官，手裏魚須竹已乾。", "仕路蹉跎誠計拙，世情巘險爲心寒。", "但全冲氣充丹府，莫問靈苗采紫團。", "夏景漸長民事簡，静開黄卷爇香丸。"]'),
('e5b5dd26-1b92-43db-a0e2-bf100d59d11d','和叔康首夏書懷五首  其五','韋驤','宋','宋诗','song-poetry','','[]','詩壇老将氣桓桓，招集同盟插未乾。',64,'全唐诗/poet.song.41000.json','["詩壇老将氣桓桓，招集同盟插未乾。", "句險直從天上落，辭清能使座中寒。", "勇揮健筆蛟生角，旋襞華箋鳳破團。", "更愛一時皆善和，聲聲嚴鼓中隤丸。"]'),
('6adc8e47-ad8b-4f43-9a0f-9554f6bc6047','次韻和孫世則以詩送别','韋驤','宋','宋诗','song-poetry','','[]','解印踰旬君已知，新詩相寄重相違。',64,'全唐诗/poet.song.41000.json','["解印踰旬君已知，新詩相寄重相違。", "由來從宦無期定，不得同時受代歸。", "攬轡益嗟賢誼遠，異鄉况是故人稀。", "宜春臺外空回首，獨整區區倦翼飛。"]'),
('16788dbf-f68c-4ac4-a9ba-44a7575c6993','介亭二十韻呈杭守祖龍圖','韋驤','宋','宋诗','song-poetry','','[]','列石何年出，危亭不日成。',240,'全唐诗/poet.song.41000.json','["列石何年出，危亭不日成。", "兩行分磊落，八顧壯經營。", "表裏山川秀，朝晡氣象清。", "江湖俱有趣，天地豈無情。", "聚井看棋布，重城視带縈。", "望通魚鼈遠，勢壓鳳凰輕。", "鳥背飛來見，雲頭過去平。", "屈盤疏一逕，浩蕩接雙盈。", "難秘神僊境，茲逢賞識精。", "元侯挾餘裕，樂俗沸休聲。", "物外籠真概，胸中愜雅誠。", "有時陵翠靄，極目聳紅旌。", "九萬鵬程近，三千客履榮。", "樽罍卑北海，篇詠小宣城。", "峴首空多嗜，蓬萊謾自評。", "古今爲絕觀，風月快平生。", "覧景聰明曠，書銘意思宏。", "優游傲圭衮，端正等權衡。", "愷悌均吾衆，中和得所行。", "此心非苟豫，奚愧介之名。"]'),
('f1356589-e40a-46f9-83ad-d8c174306e8f','和陳和叔內翰憶梅花因手植數本又命畫工作生枝于屏間','韋驤','宋','宋诗','song-poetry','','[]','翰林清興滿江鄉，尤憶梅花趁臘芳。',64,'全唐诗/poet.song.41000.json','["翰林清興滿江鄉，尤憶梅花趁臘芳。", "已寫幽屏外桃李，更攄藻思壓班揚。", "自期造化加先意，豈待嬋娟借末光。", "幸預樽前此佳賞，還祈手植早飄香。"]'),
('bdeeedcc-f683-4620-bea0-614dc3717ca0','叢山堂','韋驤','宋','宋诗','song-poetry','','[]','經營新自翰林公，勢壓南譙氣象雄。',64,'全唐诗/poet.song.41000.json','["經營新自翰林公，勢壓南譙氣象雄。", "四顧高明千里近，一團蒼翠萬山叢。", "琅邪路入青林轉，豐樂泉疏白石空。", "唐相若能前此制，當時應不暇懷嵩。"]'),
('68ba32f4-c18a-41e0-8def-64099e571042','次韻答和叔見招茅庵弈棋','韋驤','宋','宋诗','song-poetry','','[]','豈弟移風州事稀，何妨退食自逶迤。',32,'全唐诗/poet.song.41000.json','["豈弟移風州事稀，何妨退食自逶迤。", "新陽來復茅庵暖，喜奉高篇促對棋。"]'),
('05955856-b08c-4725-9b06-9dbf7dbed26c','次韻和同遊溪北竹園','韋驤','宋','宋诗','song-poetry','','[]','追攀却憶謫仙詩，曾向東城倒接䍦。',64,'全唐诗/poet.song.41000.json','["追攀却憶謫仙詩，曾向東城倒接䍦。", "此日清遊非痛飲，一時幽趣有枯棋。", "鳥聲似逐新陽囀，竹色如便晚景遲。", "勝概佳辰莫輕寘，看看召節動歸期。"]'),
('a1304597-ac3a-45ef-b16c-5ab1ee1a6136','詠雪','韋驤','宋','宋诗','song-poetry','','[]','密雪乘新臘，凝陰混太清。',120,'全唐诗/poet.song.41000.json','["密雪乘新臘，凝陰混太清。", "灑空寒送色，著物静無聲。", "舞恨庭除隘，鋪宜原野平。", "枯株資點綴，朽壤藉包并。", "價踴村罏酒，愁添古塞兵。", "巧裁梁苑賦，幽動剡溪情。", "可慶豐年兆，何虞盭氣生。", "行看窮歲籥，坐喜覆山城。", "遠祖篇章在，元侯德政成。", "與民爲福外，閶闔一心傾。"]'),
('474ee7c3-b285-4706-a205-bb9c7abc8777','詠雪霽月夜見簡','韋驤','宋','宋诗','song-poetry','','[]','百尺城頭雪月間，城樓更向碧霄干。',64,'全唐诗/poet.song.41000.json','["百尺城頭雪月間，城樓更向碧霄干。", "優游野步來危坐，彷彿仙蹤在廣寒。", "幽致獨爲中夜賞，清輝分與近鄰看。", "瑶臺十二傳佳句，瀟灑高情豈易闌。"]'),
('46a103aa-9437-40dd-a17e-6eedf0a00d93','和雪前數刻迎郊赦口占','韋驤','宋','宋诗','song-poetry','','[]','君恩無遠近，千里到山城。',48,'全唐诗/poet.song.41000.json','["君恩無遠近，千里到山城。", "人意方均喜，天心爲降霙。", "旌旗增德色，簫鼓變和聲。", "盛際千年會，誰将史册評。"]'),
('71902160-8ead-4cc4-87a5-50c1e296c731','明月庵','韋驤','宋','宋诗','song-poetry','','[]','南譙郡古牙城壯，城上樓臺屹相向。',96,'全唐诗/poet.song.41000.json','["南譙郡古牙城壯，城上樓臺屹相向。", "晴天落日碧山横，登覧依稀在屏障。", "從容北步上茅庵，圓如氈帳幽如巖。", "眼前竹石皆自得，物外氣象容誰探。", "公餘時來興清切，幅巾道服雙笻節。", "廓然遺照坐可忘，更向庵心畫明月。"]'),
('8dc4218f-cdad-4d73-b224-5089143e7b59','和閒步城上率遊城南','韋驤','宋','宋诗','song-poetry','','[]','城南古木未全凋，溪裏寒魚正可撩。',32,'全唐诗/poet.song.41000.json','["城南古木未全凋，溪裏寒魚正可撩。", "紅旆追攀真得趣，塵懷萬斛等閒消。"]'),
('a8bc485f-f2aa-441a-b114-4ac868804097','和夜登東閣','韋驤','宋','宋诗','song-poetry','','[]','夜初乘興上城頭，白玉蟾蜍碧玉天。',32,'全唐诗/poet.song.41000.json','["夜初乘興上城頭，白玉蟾蜍碧玉天。", "爽曠襟懷誰得似，謫仙身世豈非前。"]'),
('24610c6b-108a-405b-bd75-9f96cf18ad99','辭勸飲','韋驤','宋','宋诗','song-poetry','','[]','主意固慇懃，須辭酒味醇。',24,'全唐诗/poet.song.41000.json','["主意固慇懃，須辭酒味醇。", "願爲投轄客，不作吐茵人。"]'),
('9798383c-0ad4-4b6a-9324-a3b9854401c1','雪後遊琅邪山聯句','韋驤','宋','宋诗','song-poetry','','[]','南溪約幽尋，西嶺極遐觀。',288,'全唐诗/poet.song.41000.json','["南溪約幽尋，西嶺極遐觀。", "初陽色朦朧，殘雪光汗漫。", "相望樓殿間，宛在雲霄半。", "泉聲减琤淙，山勢欲飛竄。", "巖寒雨花霏，谷暖煙絮亂。", "幽鳥度喬林，驚猿折枯幹。", "決決漲溪流，輝輝披野岸。", "蘭芽吐尚微，冰乳凝未泮。", "佛屋對峰尖，禪庵倚崖斷。", "軒窗愛虛豁，赤白從漫漶。", "竹敲玉玲琅，松溜珠璀璨。", "寧将瓊礫分，未省蘭蒿判。", "行幽兔跡深，瞩遠鴉翅緩。", "登宜阮孚屐，隱稱嵇康鍛。", "結遊賢躅多，鑱石清詩爛。", "極目窮躋攀，投隙違羈絆。", "榮觀太帝書，暫憩飛仙館。", "石立翠屏張，霞收丹錦散。", "覘坐客爐擁，負暄僧衲換。", "選勝唯務得，陟危寧復憚。", "誰乘泛海槎，直欲傍銀漢。", "况有凌雲才，何妨舉風翰。", "景多苦冥搜，歡解惬佳玩。", "乃情慰懸想，昔傳非謾讕。"]'),
('dcbdd903-b89b-4280-babc-4c588aaa788a','和會峰亭','韋驤','宋','宋诗','song-poetry','','[]','千峰環聚翠糢糊，欲卜爲鄰豈易圖。',32,'全唐诗/poet.song.41000.json','["千峰環聚翠糢糊，欲卜爲鄰豈易圖。", "且使縑綃畫将去，披觀未必後仙都。"]'),
('4db9442c-bc8a-49d7-a72a-adf22d0ad953','和喜奉御札改元元豐口號','韋驤','宋','宋诗','song-poetry','','[]','改號泥封下碧空，天光遠燭郡城中。',32,'全唐诗/poet.song.41000.json','["改號泥封下碧空，天光遠燭郡城中。", "禁林舊德承宣重，預向偏州致歲豐。"]'),
('2ada4607-7218-413b-b6d8-863298fce9c9','又和','韋驤','宋','宋诗','song-poetry','','[]','元豐嘉號改明年，萬里江山色愈鮮。',32,'全唐诗/poet.song.41000.json','["元豐嘉號改明年，萬里江山色愈鮮。", "侍從舊臣承紫詔，拜恩如在御床前。"]'),
('a897ae3a-5892-4d87-9633-bd7634a41243','幽谷迴口占呈和叔內翰','韋驤','宋','宋诗','song-poetry','','[]','五騎行歌五馬前，亂雲輕點亂峰巔。',32,'全唐诗/poet.song.41000.json','["五騎行歌五馬前，亂雲輕點亂峰巔。", "此時佳興此中醉，一闋清詩一玉船。"]'),
('de0ac7b4-6641-4f3c-b4ec-12529a985f6d','和山郡早起  其一','韋驤','宋','宋诗','song-poetry','','[]','牙城曉色動旌旗，筆吏來鈔枕上詩。',32,'全唐诗/poet.song.41000.json','["牙城曉色動旌旗，筆吏來鈔枕上詩。", "溪柳山梅應闇覺，先春芳意肯遲遲。"]'),
('fe1026d9-8507-4eb2-8cd0-c7d65b1eeab4','和山郡早起  其二','韋驤','宋','宋诗','song-poetry','','[]','鈴齋書几燭花消，簾外寒霜曉尚飄。',32,'全唐诗/poet.song.41000.json','["鈴齋書几燭花消，簾外寒霜曉尚飄。", "却憶夜乘行樂處，煙村雲塢聽農謡。"]'),
('f2b830e0-dd80-4bca-a974-1116f5f780fb','和臘日初晴會同僚射飲投壺','韋驤','宋','宋诗','song-poetry','','[]','曉風吹雨作晴雲，臘日山城已似春。',64,'全唐诗/poet.song.41000.json','["曉風吹雨作晴雲，臘日山城已似春。", "林木欣欣初有趣，郡齋皦皦迥無塵。", "祭軍雅戲齊酣戰，矍圃環觀密布鱗。", "此樂得爲知所自，天将豐歲與滁人。"]'),
('196c8459-47b2-446d-81a9-8bb27dd9832b','和雪意','韋驤','宋','宋诗','song-poetry','','[]','凍雲慘淡連吳野，舞雪繽紛鬬楚宫。',64,'全唐诗/poet.song.41000.json','["凍雲慘淡連吳野，舞雪繽紛鬬楚宫。", "郡守華堂方置酒，山翁鶴馭忽乘風。", "未看夜月光輝助，已喜寒梅信息通。", "欲把新詩解嗟嘆，強隨高韻愧無功。"]'),
('665622a5-5b59-4b48-83bd-cba765152c88','坐中聞擊鼓毆儺聲戲聯數韻','韋驤','宋','宋诗','song-poetry','','[]','故歲妖癘逐，新春祥慶多。',72,'全唐诗/poet.song.41000.json','["故歲妖癘逐，新春祥慶多。", "旌旗催出獵，簫鼓引毆儺。", "𠿕𧇠将軍至，鬅鬙羅刹過。", "丹書神按籍，白晝士揮戈。", "革面徒爲異，清門豈有魔。", "成功在搜厭，正氣滿天龢。"]'),
('52fb92da-9486-4e9a-864a-eab0bd8daa0b','行縣坐野館食次得所貺手墨兼惠雀鮓兔饌因以鄙句馳謝','韋驤','宋','宋诗','song-poetry','','[]','清江雀鮓冠江南，罝兔鮮腴美可參。',64,'全唐诗/poet.song.41000.json','["清江雀鮓冠江南，罝兔鮮腴美可參。", "旅食尋常疑指動，鈴齋方丈忽分甘。", "行庖飣餖珍非八，下筯矜持嗅必三。", "知味便知公意重，屬饜寧以小人貪。"]'),
('9fa02b8a-d262-40b0-a85c-bd6b3ed8e326','和郡齋即事','韋驤','宋','宋诗','song-poetry','','[]','郡齋鈴索静無聲，風引香煙入翠屏。',64,'全唐诗/poet.song.41000.json','["郡齋鈴索静無聲，風引香煙入翠屏。", "棋勝文枰子收玉，詩成汗簡竹書青。", "治民不害爲高卧，對客何嘗衒獨醒。", "他日鳳凰池上樂，也應難忘養生經。"]'),
('9d957de9-7159-4172-924a-afabbc37f8e9','和歲除','韋驤','宋','宋诗','song-poetry','','[]','莫惜年華此夕凋，漫漫将旦即春朝。',64,'全唐诗/poet.song.41000.json','["莫惜年華此夕凋，漫漫将旦即春朝。", "緹帷指刻更殘律，析木循環復建杓。", "玉琖椒花投曉薦，銀檠蠟炬隔年消。", "祗應幽谷知時早，已欲飛遷翠木喬。"]'),
('ec22f34c-d201-4fb9-994e-29bcc7f96e88','元豐改元元日登行春閣','韋驤','宋','宋诗','song-poetry','','[]','夜盡銅壺漏，朝生玉律春。',96,'全唐诗/poet.song.41000.json','["夜盡銅壺漏，朝生玉律春。", "日稱元最重，年與號俱新。", "郡閣晴光早，山城喜氣均。", "椒觴初獻壽，仙木已書神。", "鷹隼飛還止，龍蛇蟄欲伸。", "溪冰仍泛泛，園柳自欣欣。", "物意幡然作，人情豈不倫。", "區區添甲子，斂拙任洪鈞。"]'),
('0943ef93-8fea-4bb2-9a28-40fa7c91d3dc','和歲節見招城上閒步','韋驤','宋','宋诗','song-poetry','','[]','山頭宿靄微微見，木末春風細細生。',64,'全唐诗/poet.song.41000.json','["山頭宿靄微微見，木末春風細細生。", "動植逢時俱有意，乾坤造物本無情。", "拘攣未易逃繩檢，休暇何妨解組纓。", "所幸得吟瀟灑句，又隨旌旆上牙城。"]'),
('a961b48d-b571-4266-aacb-0689559b937c','和天慶觀醮宿','韋驤','宋','宋诗','song-poetry','','[]','璧月團團徹曉明，琳宫深邃寂無聲。',32,'全唐诗/poet.song.41000.json','["璧月團團徹曉明，琳宫深邃寂無聲。", "傳聞此夜曾齋宿，讀著新詩骨也清。"]'),
('7386229f-2d96-4d21-87d7-26e03026778f','和因觀罩魚斫鱠  其一','韋驤','宋','宋诗','song-poetry','','[]','一丈深溪一丈魚，不論高價只愁無。',32,'全唐诗/poet.song.41000.json','["一丈深溪一丈魚，不論高價只愁無。", "携來縷作霜盤鱠，美玉紛紛得所沽。"]'),
('465ad746-9d9e-45b6-a8a0-1438c238eab6','和因觀罩魚斫鱠  其二','韋驤','宋','宋诗','song-poetry','','[]','昔詠洗刀魚眼紅，少陵才思摩秋空。',32,'全唐诗/poet.song.41000.json','["昔詠洗刀魚眼紅，少陵才思摩秋空。", "今朝大嚼有餘興，佳句復出文章翁。"]'),
('bdac7a44-9333-4200-81cc-0dae47f32f83','和野步','韋驤','宋','宋诗','song-poetry','','[]','追隨仙舫南溪去，欲向春波擲釣竿。',32,'全唐诗/poet.song.41000.json','["追隨仙舫南溪去，欲向春波擲釣竿。", "無奈東風攬清興，却吹晴靄作溪寒。"]'),
('245b05e2-f298-47a1-ad9d-c73d3f553bf5','和柳眼','韋驤','宋','宋诗','song-poetry','','[]','覘煙窺月早于梅，不待東風著意催。',32,'全唐诗/poet.song.41000.json','["覘煙窺月早于梅，不待東風著意催。", "應爲朱輪屢迴顧，未春先向道傍開。"]'),
('20e05885-b7fe-4b1f-948d-004d53f27de2','小檜毬','韋驤','宋','宋诗','song-poetry','','[]','裁芳翦嫩巧間關，屈葉蟠枝不可攀。',32,'全唐诗/poet.song.41000.json','["裁芳翦嫩巧間關，屈葉蟠枝不可攀。", "抛擲似遺春女戲，一團輕翠在朱欄。"]'),
('8f4e1c1e-565b-44ca-bb3f-057d0ddc20ee','和見招','韋驤','宋','宋诗','song-poetry','','[]','仙館憩旌輿，清篇手自書。',24,'全唐诗/poet.song.41000.json','["仙館憩旌輿，清篇手自書。", "撥煩雖欲往，俗吏得休無。"]'),
('03b0fe3f-8760-426f-95ed-b6bbb06d34f4','竹徑','韋驤','宋','宋诗','song-poetry','','[]','縈紆一道貫檀欒，入翠穿斜步履慳。',32,'全唐诗/poet.song.41000.json','["縈紆一道貫檀欒，入翠穿斜步履慳。", "俗客也應無暇到，不煩春笋爲遮攔。"]'),
('e43af95c-7734-4fb4-b54d-986c341c4175','和寶嚴閣','韋驤','宋','宋诗','song-poetry','','[]','佛宫高閣踞城東，巾履閒来面碧峰。',64,'全唐诗/poet.song.41000.json','["佛宫高閣踞城東，巾履閒来面碧峰。", "風却雲頭護清景，春催柳眼作先容。", "溪傍幾簇紅梢露，竹外誰家翠幕重。", "玉局棋收歸路近，昏鴉驚潰一聲鐘。"]'),
('c3769f53-92d8-4766-8c75-397aecdb2587','和立春日東風雪意偶作','韋驤','宋','宋诗','song-poetry','','[]','紞紞城頭五鼓催，東風連夜逐春回。',64,'全唐诗/poet.song.41000.json','["紞紞城頭五鼓催，東風連夜逐春回。", "物心方喜寒威改，雲色猶將雪意來。", "戟戶勸農牛破土，琴堂介壽螘浮醅。", "何妨盈尺饒嘉瑞，發滯開萌有迅雷。"]'),
('f3b3d7d0-4d24-4bb5-97a9-eb0455f23b98','和山城燈夜','韋驤','宋','宋诗','song-poetry','','[]','山城燈夕興厭厭，俗樂年豐令節參。',64,'全唐诗/poet.song.41000.json','["山城燈夕興厭厭，俗樂年豐令節參。", "竿首挂星還拱北，雲中迴雁倦圖南。", "笙簫度曲喧芳席，綵翠交光結秀巖。", "邦伯欲歸人戀戀，帳兵休報鼓聲三。"]'),
('4a895144-fe5d-4926-9698-fa4ba083b2d9','上元後南溪泛舟聯句','韋驤','宋','宋诗','song-poetry','','[]','野渡半篙水，春風一葦航。',48,'全唐诗/poet.song.41000.json','["野渡半篙水，春風一葦航。", "柳梢舒嫩綠，梅蕚泛幽香。", "繡羽驚波起，翠鱗跳日光。", "環城得佳趣，清思滿高塘。"]'),
('9071abe9-4547-4f82-9739-4eb697d7830d','和適意','韋驤','宋','宋诗','song-poetry','','[]','陽春催物態，清暇養天和。',48,'全唐诗/poet.song.41000.json','["陽春催物態，清暇養天和。", "求外於情薄，陶真所得多。", "梅苞新爛漫，松影舊婆娑。", "此日銜杯樂，何如鼓腹歌。"]'),
('24debcdb-fc11-49f4-aafd-8fdd956789ea','和春陰倦遊','韋驤','宋','宋诗','song-poetry','','[]','鈴閣興何幽，公庭訟不留。',48,'全唐诗/poet.song.41000.json','["鈴閣興何幽，公庭訟不留。", "未能清晝寢，偶作夾城遊。", "竹色仍煙翠，梅香趁水流。", "持杯聽暮角，一任起樓頭。"]'),
('46d47adf-4e01-48b2-a940-9ab551232ef5','和新晴','韋驤','宋','宋诗','song-poetry','','[]','泛鷁兼乘竹，高低秀色間。',48,'全唐诗/poet.song.41000.json','["泛鷁兼乘竹，高低秀色間。", "鴨頭生野水，鳳翼展晴山。", "掎摭青春態，消磨白日閒。", "郡園雙白鷺，投晚逐人還。"]'),
('4f0d709d-0055-49b9-8341-5925d72a9530','謝惠瓦墩','韋驤','宋','宋诗','song-poetry','','[]','百尺危亭舊路榛，自公呼吸變蘭蓀。',32,'全唐诗/poet.song.41000.json','["百尺危亭舊路榛，自公呼吸變蘭蓀。", "更憐數奉親輿到，分惠芳齋碧瓦墩。"]'),
('11caeb56-667a-497e-8032-b4370d476225','謝惠山花菜','韋驤','宋','宋诗','song-poetry','','[]','鈴下雕盤送，山蔬雅惠沾。',48,'全唐诗/poet.song.41000.json','["鈴下雕盤送，山蔬雅惠沾。", "亂絲銀鯽鱠，交疊玉龍髯。", "日膳榮分美，晨羞荷見添。", "題詩授來使，珍重豈知饜。"]'),
('813704e5-c244-4932-b809-50bb6f9e4e6f','和見招遊城東園','韋驤','宋','宋诗','song-poetry','','[]','東城老圃掃青苔，竹柏深中一逕開。',32,'全唐诗/poet.song.41000.json','["東城老圃掃青苔，竹柏深中一逕開。", "桃蕊柳芽俱有意，安排春態待公来。"]'),
('1f4e58f3-6df1-4c91-9324-2cc4b6adb940','賦新笋','韋驤','宋','宋诗','song-poetry','','[]','竹裏行厨洗玉盤，旋尋新笋捃檀欒。',64,'全唐诗/poet.song.41000.json','["竹裏行厨洗玉盤，旋尋新笋捃檀欒。", "柔鞭乍斷泥猶濕，嫩籜初苞蘚未乾。", "象箸偶存遺様短，瓊林纔拆冷光寒。", "如何且緩雕觴薦，留作青林虎豹看。"]'),
('daffd5c7-7cfc-4b9c-9a65-3729556017af','迎春花','韋驤','宋','宋诗','song-poetry','','[]','欺梅壓柳肯相然，佳號迎春豈浪傳。',64,'全唐诗/poet.song.41000.json','["欺梅壓柳肯相然，佳號迎春豈浪傳。", "細葉茸茸垂綠髪，繁英璨璨簇金鈿。", "先時不入林鶯妬，晚節唯容露菊鮮。", "繡在羅衣真有趣，不將紅紫累嬋娟。"]'),
('4ec2c808-fd99-4f1b-955b-7c8d38f2cc04','以前韻作春寒攀迓','韋驤','宋','宋诗','song-poetry','','[]','春寒山色似昏煙，風度譙門晝漏傳。',64,'全唐诗/poet.song.41000.json','["春寒山色似昏煙，風度譙門晝漏傳。", "露柳軟條金綴紐，雨苔圓點翠遺鈿。", "登樓引領情方遠，行帳来詩墨尚鮮。", "坐想琅邪歸路晚，兩行紅蠟代嬋娟。"]'),
('d53ecf95-9b5b-4466-aa06-7856f587b9d6','再和春寒次來韻','韋驤','宋','宋诗','song-poetry','','[]','雲迷曉日山頭闇，風落春梅水面香。',64,'全唐诗/poet.song.41000.json','["雲迷曉日山頭闇，風落春梅水面香。", "十里郊原皆有趣，一番歌吹從尋芳。", "佳辰浩蕩情懷惬，化國優游晷刻長。", "更把高才酬勝景，他年吟誦倍難忘。"]'),
('71c10ca6-366a-454b-aba2-5db9a887c409','賦石棋子以機字韻','韋驤','宋','宋诗','song-poetry','','[]','靈巖山下石，採拾比珠璣。',72,'全唐诗/poet.song.41000.json','["靈巖山下石，採拾比珠璣。", "圜璞生難小，文楸數可圍。", "紛紜星並霣，黑白玉争輝。", "值賦神工妙，磨礲俗巧非。", "透關經手耐，争道轉心稀。", "落落無情甚，誰爲勝負機。"]'),
('55031042-f997-45bb-bd77-68dc8fbabed5','滁上閒日陰晴聯句','韋驤','宋','宋诗','song-poetry','','[]','陰晴淮海氣何殊，一昔風光互慘舒。',160,'全唐诗/poet.song.41000.json','["陰晴淮海氣何殊，一昔風光互慘舒。", "大塊養春禆造化，繁雲閒日蔽居諸。", "暖回沙磧催來雁，寒徹冰池怯上魚。", "山色晦明如代謝，花枝涼曝似相於。", "朝暾忽蕩川原净，夕翳還籠井落疏。", "快適得朋釃醁酒，困眠無興讀殘書。", "紅霞灼灼飛琳館，煙靄濛濛襲隼旟。", "定與物情均燥濕，殆非星好有盈虚。", "連空雪意迷高柳，遶舍陽和坼嫩蔬。", "林外昏鴉啼野盡，城頭新月上簾初。"]'),
('5d9a6b11-bb4e-4d8b-8c8b-c8858ba534a3','和觀新曆  其一','韋驤','宋','宋诗','song-poetry','','[]','玉琯初回太簇春，新頒中朔到淮濱。',32,'全唐诗/poet.song.41000.json','["玉琯初回太簇春，新頒中朔到淮濱。", "眼前節物南來雁，出處知時似智人。"]'),
('17157bde-593a-4482-b0d1-29ac017d2df6','和觀新曆  其二','韋驤','宋','宋诗','song-poetry','','[]','龍蛇蟄久待春雷，鴻雁圖南去却回。',32,'全唐诗/poet.song.41000.json','["龍蛇蟄久待春雷，鴻雁圖南去却回。", "山國不驚時節改，九天新賜曆書來。"]'),
('2ba52bda-65fa-4ccc-b3ea-5ac7787fbd0d','雨後城上種蜀葵效轆轤體聯句','韋驤','宋','宋诗','song-poetry','','[]','不惮移根遠，姑憐向日姿。',288,'全唐诗/poet.song.41000.json','["不惮移根遠，姑憐向日姿。", "春風從自得，夜雨况相資。", "敏速飛霜钁，婆娑擁碧枝。", "幽葩兹有待，雜卉漫多奇。", "野藿非余尙，庭蘭盍爾知。", "傾心安所守，衛足豈其私。", "得地何妨徙，干霄固可疑。", "采幢須夏節，綠餅與秋期。", "莫以叢生陋，唯其秀出宜。", "遷非拔茅進，愛豈揠苗爲。", "色解凌溪錦，花應當酒巵。", "遶欄窠尙小，傍砌影猶卑。", "援護情宜倍，栽培力已施。", "桃蹊容爛熳，竹逕聳參差。", "不待毛嬙妬，何嫌魯相辭。", "土簁憂壓嫩，竹插爲扶欹。", "疏密齊行列，芳華遞疾遲。", "纖莖簪閒導，繁蕊珥交垂。", "恐踐禽須逐，防侵草必夷。", "飬完先固本，採折俟乘時。", "屢戒園夫守，頻煩墨客窺。", "拾來同地芥，吟就比江蘺。", "泛與蕭蒿長，偏饒雨露滋。", "何如君子德，修直任榮衰。"]'),
('a0175619-4313-48c7-a041-6050bd69c5d8','和答代簡二絕  其一','韋驤','宋','宋诗','song-poetry','','[]','遠想陰雲鎖碧山，坐聽簷溜響潺潺。',32,'全唐诗/poet.song.41000.json','["遠想陰雲鎖碧山，坐聽簷溜響潺潺。", "却驚漏洩洪鈞妙，變化風雷頃刻間。"]'),
('ca1bdb13-256e-4615-bbaf-9741aaa26891','和答代簡二絕  其二','韋驤','宋','宋诗','song-poetry','','[]','曉風吹聚幾山雲，掩抑朝暉氣候昏。',32,'全唐诗/poet.song.41000.json','["曉風吹聚幾山雲，掩抑朝暉氣候昏。", "想望城頭飛蓋阻，郡齋應樂舊書温。"]'),
('0d480a9d-9d6a-4dc9-bed0-ba67cbef4ea7','和城頭相望','韋驤','宋','宋诗','song-poetry','','[]','雨餘山溜漲春溝，欲上危亭奉燕遊。',32,'全唐诗/poet.song.41000.json','["雨餘山溜漲春溝，欲上危亭奉燕遊。", "前望籃輿轉城角，恍疑仙步在鰲頭。"]'),
('6bed7aa4-ea47-4855-b08c-0d6c636449cf','畫舫泛春偶聯一絕','韋驤','宋','宋诗','song-poetry','','[]','近郭風光日日新，城頭溪上互尋春。',32,'全唐诗/poet.song.41000.json','["近郭風光日日新，城頭溪上互尋春。", "欲知昨日籃輿客，便是今朝畫舫人。"]'),
('85556280-a68b-4676-8a52-8889168dc48e','和野步自幽谷之寺莊','韋驤','宋','宋诗','song-poetry','','[]','出郭愛暄韶，芳蹊接澗橋。',72,'全唐诗/poet.song.41000.json','["出郭愛暄韶，芳蹊接澗橋。", "輕車侵草色，飛蓋拂林梢。", "自得行春樂，且無眠晝嘲。", "淺黄看柳嫩，淡碧辨山遥。", "此院遊曾記，他林隱倦招。", "放懷天地闊，落日聽歌樵。"]'),
('e9716240-e1af-4dd8-a3cd-43b74e47422f','茅亭觀雨中杏花得中字','韋驤','宋','宋诗','song-poetry','','[]','茅亭高對杏花叢，漠漠陰雲小雨中。',64,'全唐诗/poet.song.41000.json','["茅亭高對杏花叢，漠漠陰雲小雨中。", "蜀錦濯来添潤色，燕脂洗出變輕紅。", "幽香肯怯殘梅妬，膩艷尤便弱柳籠。", "不放晴陽老芳態，令人曲意度春工。"]'),
('c2a0b528-9c25-4791-ac9e-f803973e800c','幽谷謝惠新釀家饌奉親','韋驤','宋','宋诗','song-poetry','','[]','花裏深深使語傳，銀壺乘酒副珍鮮。',64,'全唐诗/poet.song.41000.json','["花裏深深使語傳，銀壺乘酒副珍鮮。", "翰林舊德垂情至，鶴髪慈親荷惠偏。", "壽琖此時添樂只，綵衣今日倍忻然。", "却吟鄙句通鈴閣，匪報尤慚木李篇。"]'),
('a17947c1-a073-40c3-81c9-60651acec860','和櫻桃花開帳飲口占','韋驤','宋','宋诗','song-poetry','','[]','櫻桃花裏置行厨，一榼瓊漿數尾鱸。',32,'全唐诗/poet.song.41000.json','["櫻桃花裏置行厨，一榼瓊漿數尾鱸。", "勇趁紅芳集賓履，玉山傾倚照冰壺。"]'),
('7907280e-e93c-4b38-93f3-5fe793674d3d','又和行字二韻','韋驤','宋','宋诗','song-poetry','','[]','東風如酒醉朱櫻，終日酣酣弄秀英。',32,'全唐诗/poet.song.41000.json','["東風如酒醉朱櫻，終日酣酣弄秀英。", "天上謫仙乘興賞，一番歌吹傍雲行。"]'),
('f6b76bd4-c211-457d-a189-86a51289fa5d','和正閏晦日','韋驤','宋','宋诗','song-poetry','','[]','孟陬閏晦半春光，夜刻初消晝刻強。',64,'全唐诗/poet.song.41000.json','["孟陬閏晦半春光，夜刻初消晝刻強。", "谷鳥有聲皆得意，林花無處不飄香。", "池經夕雨添新淥，柳舞東風發故狂。", "亭壓高城延過躅，湛然清興引盃長。"]'),
('0cd7f279-3ea0-4a78-869a-b1af990fe5da','和春晚過幽谷口占','韋驤','宋','宋诗','song-poetry','','[]','先春當日探芳芽，瞬息而今已落花。',32,'全唐诗/poet.song.41000.json','["先春當日探芳芽，瞬息而今已落花。", "碧實有心應見笑，豈須新艷引流霞。"]'),
('fe846e05-96a0-40e5-8ffe-2eda5d6021c8','又和至叢山堂口占','韋驤','宋','宋诗','song-poetry','','[]','殘紅新綠媚朝晴，脚到叢山眼倍明。',32,'全唐诗/poet.song.41000.json','["殘紅新綠媚朝晴，脚到叢山眼倍明。", "春老物情皆有趣，只應猶欠早鶯聲。"]'),
('86ea0e42-4bd9-43d0-ab7d-e4aa45c3ddb8','和小雨乘興遊城西竹園','韋驤','宋','宋诗','song-poetry','','[]','冷逼林坳笋未筠，潤通花底砌無塵。',32,'全唐诗/poet.song.41000.json','["冷逼林坳笋未筠，潤通花底砌無塵。", "且傾文舉盈樽酒，莫惜林宗折角巾。"]'),
('3aa5498a-59e1-4427-a7d6-bc78abfe71f5','和會飲牡丹叢間','韋驤','宋','宋诗','song-poetry','','[]','移樽近檻就香多，輙效花前小子歌。',32,'全唐诗/poet.song.41000.json','["移樽近檻就香多，輙效花前小子歌。", "願擴酒腸無惜醉，淡紅樓子獨嵯峨。"]'),
('95904a9b-dd41-42d2-9ab7-32c675f47e08','倒用前韻','韋驤','宋','宋诗','song-poetry','','[]','宛轉眉山效蜀峨，花前執板爲清歌。',32,'全唐诗/poet.song.41000.json','["宛轉眉山效蜀峨，花前執板爲清歌。", "歌聲暗與春風合，催折芳心不厭多。"]'),
('17a95ddb-3edc-4f1a-b562-157c0ce56d88','再和前韻仍以峨字爲首尾','韋驤','宋','宋诗','song-poetry','','[]','峨冠莫惜插花多，多插名花壯醉歌。',32,'全唐诗/poet.song.41000.json','["峨冠莫惜插花多，多插名花壯醉歌。", "歌罷襟懷肆夷曠，願平羣險剗嵯峨。"]'),
('b39abc20-c646-49b5-bf84-9b482599581c','和山行迴坐臨清橋啜茶','韋驤','宋','宋诗','song-poetry','','[]','雲軿迴處引笙簫，疑向春宵度鵲橋。',32,'全唐诗/poet.song.41000.json','["雲軿迴處引笙簫，疑向春宵度鵲橋。", "橋上茗杯烹白雪，枯腸搜遍俗緣消。"]'),
('56f4bdc0-6697-41d1-89a5-a289b53531bf','再和  其一','韋驤','宋','宋诗','song-poetry','','[]','醉向溪頭按洞簫，夜瞻略彴似星橋。',32,'全唐诗/poet.song.41000.json','["醉向溪頭按洞簫，夜瞻略彴似星橋。", "清歡未足班荆坐，一任紗籠蠟炬消。"]'),
('aea40328-4c4a-4993-b11d-a8d75966d34a','再和  其二','韋驤','宋','宋诗','song-poetry','','[]','暮角清聲雜鳳簫，一時冠带似圜橋。',32,'全唐诗/poet.song.41000.json','["暮角清聲雜鳳簫，一時冠带似圜橋。", "謫仙詩句春泉湧，萬斛量愁頃刻消。"]'),
('88ba0be0-8ea9-47f7-b94b-657a1a07cbb2','偶疾未平不得預龍蟠之遊輙成詩以迓還旆','韋驤','宋','宋诗','song-poetry','','[]','小城春物已闌珊，病肺朝來强自寛。',64,'全唐诗/poet.song.41000.json','["小城春物已闌珊，病肺朝來强自寛。", "疲苶未堪隨驥尾，高明空想到龍蟠。", "日烘欄楯花枝卧，風滾階除柳絮團。", "索筆題詩待迴馭，肯將塵語累清歡。"]'),
('f512a635-e19f-4fe3-a30b-e81eca80a20d','牙城話别口占','韋驤','宋','宋诗','song-poetry','','[]','移節名藩去有期，牙城重上思依依。',32,'全唐诗/poet.song.41000.json','["移節名藩去有期，牙城重上思依依。", "落花也似人情戀，撲袂飄香不浪飛。"]'),
('4a7e5ea3-4894-4f03-ae49-751fd9f02ed3','餞别勸飲','韋驤','宋','宋诗','song-poetry','','[]','垂楊樓上卷珠簾，歌扇輕搖落絮黏。',64,'全唐诗/poet.song.41000.json','["垂楊樓上卷珠簾，歌扇輕搖落絮黏。", "邦伯指期移絳節，州人終日擁彤襜。", "危弦脆筦催金盞，芳草青山照畫簷。", "酩酊願公無惜醉，祗應羲馭駐峰尖。"]'),
('ca320ce8-e119-4586-9689-feacf39ae2d1','送别迴作','韋驤','宋','宋诗','song-poetry','','[]','祖餞初還重仳違，懶鞭款段入城扉。',64,'全唐诗/poet.song.41000.json','["祖餞初還重仳違，懶鞭款段入城扉。", "旌旂人去山川晚，臺榭春歸花藥稀。", "鼓吹漸遥空望望，旄倪相顧共依依。", "自憐無以紓誠戀，唯有詩筒殆庶幾。"]'),
('8f9f168b-f828-4b57-97b9-3f9c6ff23ac6','和耿天隲翦綵梅花得開字','韋驤','宋','宋诗','song-poetry','','[]','根如芝草不因栽，葉似春雲容易開。',64,'全唐诗/poet.song.41000.json','["根如芝草不因栽，葉似春雲容易開。", "應有靚妝偷艷去，且無狂蝶爲香來。", "殷勤玉盞頻飛舉，酬酢金刀巧剪裁。", "爛賞更於何處好，蟾光雪色在瑶臺。"]'),
('5e4b3d2e-a37c-441b-89f5-56d2435a406f','元日','韋驤','宋','宋诗','song-poetry','','[]','蔟律新聲應，寅杓舊觀還。',48,'全唐诗/poet.song.41000.json','["蔟律新聲應，寅杓舊觀還。", "三朝思北闕，萬壽祝南山。", "謬忝金閨籍，遐違玉笋班。", "山城濡滯跡，望日想天顔。"]'),
('64687bb3-342d-4bb1-a052-ab35aa8af94d','席上勸仲元著作勿辭酒','韋驤','宋','宋诗','song-poetry','','[]','百盞先嘗一盞醇，三分纔破一分春。',64,'全唐诗/poet.song.41000.json','["百盞先嘗一盞醇，三分纔破一分春。", "花間剔火香煙細，竹外垂縑畫筆新。", "落日穿林照簷額，緒風吹草動階唇。", "莫愁酩酊辭公勸，金斝空時跡已陳。"]'),
('efc28dbf-363a-434d-9052-f204d21740de','和蘇正甫勸飲之作','韋驤','宋','宋诗','song-poetry','','[]','芳陌草萋萋，相逢又解携。',48,'全唐诗/poet.song.41000.json','["芳陌草萋萋，相逢又解携。", "柳梢迷酒綠，歌韻怨春低。", "蘭菊時難一，鷦鵬樂自齊。", "送君須滿飲，未放錦障泥。"]'),
('68bfb88a-b2dd-4627-ba21-d0010cb85036','賦迎賞欲開杏花得花字','韋驤','宋','宋诗','song-poetry','','[]','閏月春光助物華，杏園迎賞欲開花。',64,'全唐诗/poet.song.41000.json','["閏月春光助物華，杏園迎賞欲開花。", "晝慵閨繡工猶淺，曉起宫妝色漸佳。", "嫋嫋風枝偏弄送，酣酣煙蕊自交加。", "對君安得辭昏醉，更作狂歌恣所夸。"]'),
('5dc02536-bdaf-45b9-9b79-02eea935d701','又用花字爲即席','韋驤','宋','宋诗','song-poetry','','[]','春色漫漫不可涯，謫仙亭館最幽佳。',64,'全唐诗/poet.song.41000.json','["春色漫漫不可涯，謫仙亭館最幽佳。", "歌聲闇逐風中絮，酒算旁看盞裏花。", "擊鉢題詩助清曠，藏鬮傳令止喧嘩。", "他年追念從真適，炊熟黄粱一夢賒。"]'),
('b6cfd515-d06e-4dbb-a52e-8c9a5a978b45','陪秋叔遊幽谷即席賦一川花','韋驤','宋','宋诗','song-poetry','','[]','城南幽谷去非賒，踏石穿雲境趣佳。',64,'全唐诗/poet.song.41000.json','["城南幽谷去非賒，踏石穿雲境趣佳。", "門下車魚情浃洽，道旁旌旆影鬖髿。", "笙簫宛轉隨風遠，臺榭參差對日斜。", "白玉爲船載瓊醑，未容輕負一川花。"]'),
('2215d1d1-a418-4936-8a7a-708cb68f9cf2','和社日小飲','韋驤','宋','宋诗','song-poetry','','[]','挑菜佳辰過夕醺，又逢春社舉清罇。',32,'全唐诗/poet.song.41000.json','["挑菜佳辰過夕醺，又逢春社舉清罇。", "不爲歸遺東方態，且對韶妍一醉昏。"]'),
('db31929d-ccd8-40bc-892b-c63fa704a287','賦牡丹黄虀','韋驤','宋','宋诗','song-poetry','','[]','依欄凋謝若爲情，旋拾殘紅入鼎烹。',32,'全唐诗/poet.song.41000.json','["依欄凋謝若爲情，旋拾殘紅入鼎烹。", "吞秀嚼香須細細，送春唯此一杯羮。"]'),
('545dd5f3-012e-4781-ae20-8150995c6e72','和范子功學士留題二賢堂','韋驤','宋','宋诗','song-poetry','','[]','屹然榱桷傍雲烟，榜揭堂名以二賢。',64,'全唐诗/poet.song.41000.json','["屹然榱桷傍雲烟，榜揭堂名以二賢。", "翰苑鉅公存往躅，集仙膚使出新篇。", "寒光共杳山椒月，幽韻相投隴下泉。", "一等聲輝驚海內，後先蹤跡似忘年。"]'),
('5785ebc3-651b-49eb-9cc1-278734d0250e','真守侯公輔見留之勤因辭以詩言欲遽往早還之意','韋驤','宋','宋诗','song-poetry','','[]','洗滌炎蒸夕雨凉，瞥然行役過鄰邦。',64,'全唐诗/poet.song.41000.json','["洗滌炎蒸夕雨凉，瞥然行役過鄰邦。", "旅懷耿耿通秋漏，征舸蕭蕭倚暮江。", "禮豆輙辭蘄義許，緒言傾聽祇心降。", "莫疑迹以便奔走，雲下孤親雪鬢雙。"]'),
('391078b3-6c6e-42be-9079-5494178eb713','夜宿淤丘','韋驤','宋','宋诗','song-poetry','','[]','古岸維舟夜向深，胡床踞坐絕囂音。',64,'全唐诗/poet.song.41000.json','["古岸維舟夜向深，胡床踞坐絕囂音。", "烟林隱隱成孤壘，水月輝輝滉碎金。", "勉强官途情易厭，衝蒙狙詐力難任。", "予心欲道從誰語，祗有清宵一苦吟。"]'),
('a2516fd9-245d-4b1f-a95e-da1f7973bfe8','泛滁河','韋驤','宋','宋诗','song-poetry','','[]','十里之間五六灣，行舟終日繞青山。',64,'全唐诗/poet.song.41000.json','["十里之間五六灣，行舟終日繞青山。", "更爲先後楓林翠，互出東西古屋閒。", "酒爲孤斟心易倦，詩非共賦思仍慳。", "秋風颯颯吹襟袂，可是無情促鬢斑。"]'),
('8cc0a86e-438b-4c4c-85f3-4c01b2d15462','出滁口入江峽','韋驤','宋','宋诗','song-poetry','','[]','逆風吹浪雪花翻，舟出滁河浩蕩間。',64,'全唐诗/poet.song.41000.json','["逆風吹浪雪花翻，舟出滁河浩蕩間。", "柁轉一聲鳴似鼓，櫓搖數丈漩如環。", "路通淮右千源水，望斷江南一带山。", "莫恨區區緣吏役，此時清曠亦開顔。"]'),
('2b2fe815-bea3-4e41-98ba-8a08d623a6ea','和徐仲元以詩見送','韋驤','宋','宋诗','song-poetry','','[]','火雲湧起勢崔巍，行舸紗窗一一開。',64,'全唐诗/poet.song.41000.json','["火雲湧起勢崔巍，行舸紗窗一一開。", "自是宦途無定跡，莫嫌臺檄屬非材。", "往還倐忽南柯夢，離合殷勤北海壘。", "更謝□人爲吉語，果然朝夕得歸來。"]'),
('e6ff05ab-21f7-4359-99fd-a6742ad04505','吳六合道原席上','韋驤','宋','宋诗','song-poetry','','[]','單舸西來六月初，偶逃遠役且躊躇。',64,'全唐诗/poet.song.41000.json','["單舸西來六月初，偶逃遠役且躊躇。", "幽尋古寺情懷放，高會虛堂暑氣除。", "地主延留情已厚，故人邂逅樂何如。", "迴頭陳跡無尋處，姓字閒於壁上書。"]'),
('8fada209-6341-4489-acfd-91c42c387c62','李白祠堂','韋驤','宋','宋诗','song-poetry','','[]','祠宇前臨姑熟溪，溪流湛湛清無泥。',96,'全唐诗/poet.song.41000.json','["祠宇前臨姑熟溪，溪流湛湛清無泥。", "春來秋去幾百載，朝雲夜月長相繄。", "堂間畫像冰玉質，高風爽氣何凄凄。", "文章光燄本萬丈，來此寂寞由讒擠。", "當時放蕩沉清骨，因有聲名不漂没。", "莫論楚屈與吴胥，誰有高才追彷彿。"]'),
('5363f0c6-48f0-43ba-b77c-c43206ef4a04','姑熟州宅後泛舟清飲','韋驤','宋','宋诗','song-poetry','','[]','古郡蕭蕭草木秋，牙城北出上扁舟。',64,'全唐诗/poet.song.41000.json','["古郡蕭蕭草木秋，牙城北出上扁舟。", "喬林有隙山微見，曲岸無風水自流。", "竹色雅如侵筦研，鳥聲時似勸觥籌。", "勿咍吏役能拘束，酒興詩腸亦自由。"]'),
('421ebfb6-b0bd-4b59-87a7-ac5e10983c80','過九華山','韋驤','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','旌騎前頭是九華，未能遊歷已咨嗟。',32,'全唐诗/poet.song.41000.json','["旌騎前頭是九華，未能遊歷已咨嗟。", "好將秀色開塵眼，又被浮雲一半遮。"]'),
('84447b32-2f69-44aa-8d88-a50d32ce7c12','冠幘峰','韋驤','宋','宋诗','song-poetry','','[]','渡江行役走埃塵，路過名山興味新。',32,'全唐诗/poet.song.41000.json','["渡江行役走埃塵，路過名山興味新。", "冠幘危峰勿相笑，儼然雲外亦辛勤。"]'),
('e08d09f1-5179-43ae-b74d-85e98a5e74ff','閲九華録','韋驤','宋','宋诗','song-poetry','','[]','仙居巖巘幾千重，秀入青冥氣勢崇。',32,'全唐诗/poet.song.41000.json','["仙居巖巘幾千重，秀入青冥氣勢崇。", "他日却來尋勝境，且將圖録記諸峰。"]'),
('79912c8f-9579-40af-ace9-c5be80a00d46','宿九華驛阻雨','韋驤','宋','宋诗','song-poetry','','[]','喜無簷溜滴空階，秣馬輕裝入夜催。',32,'全唐诗/poet.song.41000.json','["喜無簷溜滴空階，秣馬輕裝入夜催。", "一陣松風驚曉枕，又疑天外雨聲來。"]'),
('3d764204-c7ed-4c2c-be49-2ee7b99510d8','又過九華山','韋驤','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','昔年嘗慕此山遊，今日經行不暇留。',32,'全唐诗/poet.song.41000.json','["昔年嘗慕此山遊，今日經行不暇留。", "好意尙爲塵跡累，碧雞山鳳勿相尤。"]'),
('8de3490d-5bae-4908-b733-2bce519cef34','登齊山','韋驤','宋','宋诗','song-poetry','','[]','臨岐跋馬向齊山，苒苒烟蘿試一攀。',64,'全唐诗/poet.song.41000.json','["臨岐跋馬向齊山，苒苒烟蘿試一攀。", "怪石何年居物表，白雲終日伴僧閒。", "氣吞城郭紛囂外，勢接江湖浩蕩間。", "况是重陽時節近，紫微前詠好開顔。"]'),
('7b32eb4d-ab24-41e4-ab31-3cf3dbdb4e52','弄水亭','韋驤','宋','宋诗','song-poetry','','[]','清溪翠巘兩相宜，雄構峥嶸壓貴池。',64,'全唐诗/poet.song.41000.json','["清溪翠巘兩相宜，雄構峥嶸壓貴池。", "弄水得名應有謂，登山留詠想同時。", "角聲北起秋雲動，橋影西横晚照遲。", "佳趣古今看不盡，前人遺美後人思。"]'),
('2b05585d-b952-4afb-95b5-6b9eec44a4f5','離池州過長圍嶺','韋驤','宋','宋诗','song-poetry','','[]','孤城西出夕陽偏，嶺上行行思渺然。',64,'全唐诗/poet.song.41000.json','["孤城西出夕陽偏，嶺上行行思渺然。", "草木高低共秋色，江湖左右各天邊。", "凌風短鬢無由掠，投宿輕蹄不用鞭。", "一簇人烟紫巖驛，解鞍聊看月嬋娟。"]'),
('7bb3b048-6ab1-435a-84cc-6bc4e8f8bccd','别滕元發侍郎','韋驤','宋','宋诗','song-poetry','','[]','塵役間關旅思收，幸瞻旌戟少淹留。',64,'全唐诗/poet.song.41000.json','["塵役間關旅思收，幸瞻旌戟少淹留。", "多年目斷丹霄步，再拜心輕萬戶侯。", "三節行催虎符去，雙毛將近鳳池游。", "門闌欲别徒惆悵，吟對江山迥不休。"]'),
('ff33d3aa-8d5f-4a0f-9303-7b937589e910','宿楊梅驛','韋驤','宋','宋诗','song-poetry','','[]','兩壁萬千嶂，一村三四家。',48,'全唐诗/poet.song.41000.json','["兩壁萬千嶂，一村三四家。", "度橋逢古驛，下馬踏秋花。", "夜永蛩尤苦，雲空月自華。", "冷官無好趣，安用五書車。"]'),
('9e93000d-b978-4413-bc7e-8b181241688a','早行','韋驤','宋','宋诗','song-poetry','','[]','雞聲喔喔似相催，秣馬登途酒一杯。',64,'全唐诗/poet.song.41000.json','["雞聲喔喔似相催，秣馬登途酒一杯。", "海日欲升山頂赤，林霏初散嶺頭開。", "自憐旅夢經千變，誰謂離腸祇九回。", "苟祿奔馳還竊笑，未能容易賦歸來。"]'),
('f12d4590-c3eb-45de-b7fd-01f9873ba21e','曉離楊梅驛','韋驤','宋','宋诗','song-poetry','','[]','長坡峻阪足崎嶇，曉出楊梅古驛孤。',64,'全唐诗/poet.song.41000.json','["長坡峻阪足崎嶇，曉出楊梅古驛孤。", "山腹带雲如曳練，稻梢垂露欲流珠。", "穿籬鴨脚深深碧，近水雞冠小小株。", "行役雖勞遇佳境，且将幽句慰瘏痡。"]'),
('a0735da7-fe04-4aeb-a9f9-6968c9fb519a','即事','韋驤','宋','宋诗','song-poetry','','[]','舞蝶雙飛穿宿露，鳴禽相喚弄朝暾。',64,'全唐诗/poet.song.41000.json','["舞蝶雙飛穿宿露，鳴禽相喚弄朝暾。", "澗盤石逕長蛇轉，山入秋空翠鳳騫。", "楓葉園林看自好，菊花時節興難論。", "高懷不爲塵勞減，安用笙簫簇酒樽。"]'),
('44bcda64-f447-47d2-be9c-87ca705404d3','過麵山渡','韋驤','宋','宋诗','song-poetry','','[]','碧溪深水不勝篙，船尾嘔啞一櫓搖。',32,'全唐诗/poet.song.41000.json','["碧溪深水不勝篙，船尾嘔啞一櫓搖。", "岸北岸南秋色好，西風吹葉馬蕭蕭。"]'),
('4f0abd5e-e882-4662-a9c2-4acf11bc1fa9','食鱖','韋驤','宋','宋诗','song-poetry','','[]','踰尺秋江鱖，貲輕愧自深。',48,'全唐诗/poet.song.41000.json','["踰尺秋江鱖，貲輕愧自深。", "穿腮窺秣頳，引鬛訝塗金。", "捂鼎情雖鋭，飛刀愛不任。", "何須鱸滿箸，始動季鷹心。"]'),
('75d8c354-d5b5-4996-995c-044fc8c760d2','對鑑','韋驤','宋','宋诗','song-poetry','','[]','寒光滿尺餘，拂拭在朝晡。',48,'全唐诗/poet.song.41000.json','["寒光滿尺餘，拂拭在朝晡。", "敵面知相應，纖毫肯見誣。", "壯顔隨歲老，短髪任秋枯。", "皦皦胸中事，君能照得無。"]'),
('a9ad3add-4ac6-458c-8a3b-ef875cd59f7f','建德道中感興','韋驤','宋','宋诗','song-poetry','','[]','穿雲度水涉修程，日日長亭復短亭。',64,'全唐诗/poet.song.41000.json','["穿雲度水涉修程，日日長亭復短亭。", "秋老聲音聞過雁，夜凉精彩見飛螢。", "羈懷遇物如縈絮，詩思投閒似建瓴。", "却羡野人收刈畢，寂然無事掩柴扃。"]'),
('9eaad6ea-3715-4a01-a880-952581957ae7','思侍','韋驤','宋','宋诗','song-poetry','','[]','旅宦經秋厭路塵，家書累日寂無聞。',64,'全唐诗/poet.song.41000.json','["旅宦經秋厭路塵，家書累日寂無聞。", "勞身江左馳单傳，目極淮東望白雲。", "俚聽難將至音悅，天和不學衆人焚。", "趨庭往往逢寒律，叱馭迴轅兩未分。"]'),
('6fab25e7-ce8a-424f-9ddf-d7fc8daef593','感懷','韋驤','宋','宋诗','song-poetry','','[]','埃壒滿袛裯，誰矜意氣豪。',48,'全唐诗/poet.song.41000.json','["埃壒滿袛裯，誰矜意氣豪。", "獨知安履坦，寧復嘆屯膏。", "劍氣藏秋匣，弓聲閉古弢。", "臨風浩歌罷，短髪不勝搔。"]'),
('bbe0ec53-809d-4367-b49f-9d6ab89111fb','憶後城覧秀亭登望','韋驤','宋','宋诗','song-poetry','','[]','村落園林有幾家，隔墻遥出拒霜花。',32,'全唐诗/poet.song.41000.json','["村落園林有幾家，隔墻遥出拒霜花。", "自憐馬上看秋色，不似城頭覧物華。"]'),
('0e334560-be78-43a7-9342-b82d0a43f8d3','過查林','韋驤','宋','宋诗','song-poetry','','[]','路向山腰轉，雲從隴首飛。',48,'全唐诗/poet.song.41000.json','["路向山腰轉，雲從隴首飛。", "曉天初衣裌，村驛罕乘肥。", "覧物驚秋老，論心悟境非。", "歸期且寛計，雨雪或霏霏。"]'),
('3e8d8cb1-5eae-4520-a55f-570c44e16b47','落日','韋驤','宋','宋诗','song-poetry','','[]','郊原爽氣入衣巾，佳趣源源立馬頻。',32,'全唐诗/poet.song.41000.json','["郊原爽氣入衣巾，佳趣源源立馬頻。", "落日山川無限思，秋風江海未閒身。"]'),
('a25f617e-e9cf-40b4-8f7e-8087791bf84a','闡陽驛觀中秋月','韋驤','宋','宋诗','song-poetry','','[]','却掃陰雲藉晚風，十分圓月挂天東。',64,'全唐诗/poet.song.41000.json','["却掃陰雲藉晚風，十分圓月挂天東。", "中秋此夜光華盛，萬國鈞情喜翫同。", "何處樓臺恨偏照，幾家樽俎對寒空。", "自憐獨宿荒山驛，浩興長歌未易窮。"]'),
('bdf4ba08-6c5a-4c59-9496-c6a19f04297c','宿壇石驛六首  其一','韋驤','宋','宋诗','song-poetry','','[]','秋高征袂怯西風，寂寞郵亭倍旅悰。',32,'全唐诗/poet.song.41000.json','["秋高征袂怯西風，寂寞郵亭倍旅悰。", "獨有無心清夜月，更深山裏也相逢。"]'),
('5658c80d-a9bd-4628-8160-0b4fe03c5c11','宿壇石驛六首  其二','韋驤','宋','宋诗','song-poetry','','[]','山館蕭條冷似冰，黄昏四壁但蛩聲。',32,'全唐诗/poet.song.41000.json','["山館蕭條冷似冰，黄昏四壁但蛩聲。", "無端更惡飛螢點，强起前簷鬭月明。"]'),
('a8f237e6-f293-4a55-93a1-a38a4754c934','宿壇石驛六首  其三','韋驤','宋','宋诗','song-poetry','','[]','歸期尙遠路程賒，已覺秋林菊漸花。',32,'全唐诗/poet.song.41000.json','["歸期尙遠路程賒，已覺秋林菊漸花。", "莫怪臨風多北望，琅邪山外寄吾家。"]'),
('866387ff-a32a-431b-a008-c289ca166a23','宿壇石驛六首  其四','韋驤','宋','宋诗','song-poetry','','[]','求官窮僻本藏頭，遠冒風霜不自由。',32,'全唐诗/poet.song.41000.json','["求官窮僻本藏頭，遠冒風霜不自由。", "豈是有才如碩鼠，可能無術似蝸牛。"]'),
('25bdc396-4238-413f-8d1d-b1d1f53060c0','宿壇石驛六首  其五','韋驤','宋','宋诗','song-poetry','','[]','紛紛貴賤別錙銖，義命由來共取諸。',32,'全唐诗/poet.song.41000.json','["紛紛貴賤別錙銖，義命由來共取諸。", "推己及人人所慕，不然何以稱襟裾。"]'),
('eafaa1ba-d9d0-4659-b4dc-ec0ec151ac7d','宿壇石驛六首  其六','韋驤','宋','宋诗','song-poetry','','[]','獨賢安敢輒咨嗟，靡盬當如載舊詩。',32,'全唐诗/poet.song.41000.json','["獨賢安敢輒咨嗟，靡盬當如載舊詩。", "迴轡未堪期早晚，望雲終日起親思。"]'),
('f5e28e16-0fe8-4b3c-9c6a-3dca4804bf2d','想廬山三首  其一','韋驤','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','昔年曾遇九江秋，引睇廬山不及遊。',32,'全唐诗/poet.song.41000.json','["昔年曾遇九江秋，引睇廬山不及遊。", "行役今朝垂欲到，無端牽制又迴輈。"]'),
('58ed4a41-94c7-4075-9aca-c956648438bf','想廬山三首  其二','韋驤','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','訪水尋山好已迂，勝遊難必果何如。',32,'全唐诗/poet.song.41000.json','["訪水尋山好已迂，勝遊難必果何如。", "二林咫尺還淹興，空讀匡廬易覧書。"]'),
('9f85af6e-8c5d-496d-8900-1ed760825d4b','想廬山三首  其三','韋驤','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','走徧江南二十州，廬山未到謾悠悠。',32,'全唐诗/poet.song.41000.json','["走徧江南二十州，廬山未到謾悠悠。", "故知塵事相邀阻，唯想他年取次遊。"]'),
('0327af9f-bdd2-475f-b997-8ebcebf6635d','適江表','韋驤','宋','宋诗','song-poetry','','[]','水落山高古渡幽，馬蹄輕健蹴溪流。',64,'全唐诗/poet.song.41000.json','["水落山高古渡幽，馬蹄輕健蹴溪流。", "朝行暮止三千里，叙舊逢新一十州。", "倦聽亂蝉催落日，喜看黄菊助殘秋。", "不才於世無禆補，强就奔馳祗自羞。"]'),
('e221ec7a-5343-4af0-960b-cf4c575e9b16','中秋十八夜雨望月阻興','韋驤','宋','宋诗','song-poetry','','[]','賞過中秋纔兩夕，人心獨待月華多。',32,'全唐诗/poet.song.41000.json','["賞過中秋纔兩夕，人心獨待月華多。", "也知不惜饒光照，争奈閒雲好事何。"]'),
('a58e499f-9934-4d66-9f6a-1b236a2b112d','饒守游晉老席上偶成','韋驤','宋','宋诗','song-poetry','','[]','西風吹葉影悠悠，行役江城旅思收。',64,'全唐诗/poet.song.41000.json','["西風吹葉影悠悠，行役江城旅思收。", "名慕荆州欣一見，道經鄱水愛三秋。", "芙蓉欲蕊斜陽轉，鴻雁初飛爽氣浮。", "不用樽前苦相勸，斗筲唯恨怯觥籌。"]'),
('a75ffe09-d2cf-4f64-9612-be2fb8e281a7','再答和篇','韋驤','宋','宋诗','song-poetry','','[]','落日山川晚鼓休，西風樓閣遠烟收。',64,'全唐诗/poet.song.41000.json','["落日山川晚鼓休，西風樓閣遠烟收。", "清談亹亹忘塵役，醁酒深深戰暮秋。", "獨恨去當霜草路，不能留見菊花浮。", "更慚健句酬衰唱，刻燭甘輸第一籌。"]'),
('89594931-23c5-4dee-9aeb-3e9aeccf6fb3','又和答并叙别','韋驤','宋','宋诗','song-poetry','','[]','風騫繡額爐香轉，江照金樽宿靄收。',64,'全唐诗/poet.song.41000.json','["風騫繡額爐香轉，江照金樽宿靄收。", "塵客輕装渡寒水，主人佳句壓清秋。", "自忘遠馭瘏兼病，豈顧閒書沈與浮。", "回首高城空企望，馳情無算不堪籌。"]'),
('2972c8fe-86cc-4b50-83e6-61f660e021a1','龜峰  其一','韋驤','宋','宋诗','song-poetry','','[]','偶向塵勞得勝遊，縱觀三十六峰秋。',32,'全唐诗/poet.song.41000.json','["偶向塵勞得勝遊，縱觀三十六峰秋。", "巢雲負月幾千歲，欲問神龜不轉頭。"]'),
('192636f3-ae09-4d0d-908c-00ce26dc0afc','龜峰  其二','韋驤','宋','宋诗','song-poetry','','[]','龜鳳猿鰲各定名，峰峰峭怪倚青冥。',32,'全唐诗/poet.song.41000.json','["龜鳳猿鰲各定名，峰峰峭怪倚青冥。", "也知造物無情甚，凝結如何特肖形。"]'),
('9d6eb1d9-670d-401c-923c-124fcee8af27','别鉛山楊公濟','韋驤','宋','宋诗','song-poetry','','[]','征塵淟涊暮秋時，稅鞅登堂暗澣衣。',64,'全唐诗/poet.song.41000.json','["征塵淟涊暮秋時，稅鞅登堂暗澣衣。", "久别自憐心鬰鬰，相逢今喜語霏霏。", "池中盡謂蛟難畜，塞上行看馬自歸。", "落日西風滿襟袖，臨岐迴首重瞻依。"]'),
('9ef68780-5865-490d-82bb-cbb3b32351c0','行赴雲門驛','韋驤','宋','宋诗','song-poetry','','[]','石逕踏羊腸，朦朧曉日光。',48,'全唐诗/poet.song.41000.json','["石逕踏羊腸，朦朧曉日光。", "久行情易厭，少事興還長。", "林表霜楓赤，山根露菊黄。", "從來清冷趣，今日倍陽陽。"]'),
('8cf0297e-d910-4c6c-80c8-ba2a718e0252','謝簡夫太博惠茶','韋驤','宋','宋诗','song-poetry','','[]','越嶺掇春英，淮城惠不輕。',48,'全唐诗/poet.song.41000.json','["越嶺掇春英，淮城惠不輕。", "一杯分爽氣，千里想高情。", "啜與幽人共，烹宜庶子清。", "揮毫答珍貺，還愧玉川名。"]'),
('a4e90968-117c-4e39-9ce1-c9344e03155f','海陵按事','韋驤','宋','宋诗','song-poetry','','[]','小城幽趣遠，海國暮寒多。',48,'全唐诗/poet.song.41000.json','["小城幽趣遠，海國暮寒多。", "委瑣從誰遣，拘攣祗自訶。", "庭虚哀度雁，巷閴絕鳴珂。", "案牘縈仍外，陳編亦可磨。"]'),
('99d60d0d-e5f6-47d7-ab65-8d9ffa558292','琅邪三十二詠 琅邪山門','韋驤','宋','宋诗','song-poetry','','[]','雙鶴栖華表，仙山自此通。',24,'全唐诗/poet.song.41000.json','["雙鶴栖華表，仙山自此通。", "雲霞自扃鎖，塵土若爲攻。"]'),
('65e7f83b-dc2c-4572-9a81-daf25ee32b1a','琅邪三十二詠 長松逕','韋驤','宋','宋诗','song-poetry','','[]','十里開幽逕，松陰互蔽虧。',24,'全唐诗/poet.song.41000.json','["十里開幽逕，松陰互蔽虧。", "山翁心亦侈，步幛用青絲。"]'),
('4156fbda-d5bb-4ebb-b0e5-64e31bc3c7d9','琅邪三十二詠 净鏡亭','韋驤','宋','宋诗','song-poetry','','[]','路轉翬簷出，山迴秀氣多。',24,'全唐诗/poet.song.41000.json','["路轉翬簷出，山迴秀氣多。", "亭名不須看，對鏡已如何。"]'),
('0de20b04-91c2-4008-b482-973cd2e326c5','琅邪三十二詠 翠微亭','韋驤','宋','宋诗','song-poetry','','[]','謝屐低前齒，登臨勢漸雄。',24,'全唐诗/poet.song.41000.json','["謝屐低前齒，登臨勢漸雄。", "嵐光動衣袂，知在翠微中。"]'),
('32ab99c2-4964-47c0-8057-7ba9c3b6e695','琅邪三十二詠 白雲亭','韋驤','宋','宋诗','song-poetry','','[]','路作兩岐分，亭多聚白雲。',24,'全唐诗/poet.song.41000.json','["路作兩岐分，亭多聚白雲。", "無心本無戀，於此尙紛紛。"]'),
('6fa0332d-70e0-4709-9954-8911818c39f1','琅邪三十二詠 醉翁亭','韋驤','宋','宋诗','song-poetry','','[]','醉翁雖已沒，遺構在山阿。',24,'全唐诗/poet.song.41000.json','["醉翁雖已沒，遺構在山阿。", "不比陶潛石，清時樂自多。"]'),
('6586c6ab-4406-41ad-8d99-31c420a05324','琅邪三十二詠 薛老橋','韋驤','宋','宋诗','song-poetry','','[]','流泉渟處闊，跨石石橋横。',24,'全唐诗/poet.song.41000.json','["流泉渟處闊，跨石石橋横。", "題柱無蹤跡，茫然薛老名。"]'),
('16f6026e-1ba8-445b-8882-2b312f403205','琅邪三十二詠 遜泉','韋驤','宋','宋诗','song-poetry','','[]','兩竇涓涓瀉，無何後却前。',24,'全唐诗/poet.song.41000.json','["兩竇涓涓瀉，無何後却前。", "誰能來酌飲，迴意學相先。"]'),
('dace05ff-67a6-42a3-a7f3-917f3cb57aec','琅邪三十二詠 班春亭','韋驤','宋','宋诗','song-poetry','','[]','雲木氣氤氲，風光日日新。',24,'全唐诗/poet.song.41000.json','["雲木氣氤氲，風光日日新。", "豐謡隨五馬，來此聽班春。"]'),
('ac1d4a73-039b-4971-bf18-4ba04b0b74f1','琅邪三十二詠 石流渠','韋驤','宋','宋诗','song-poetry','','[]','鑿渠疏白石，繞檻走清泉。',24,'全唐诗/poet.song.41000.json','["鑿渠疏白石，繞檻走清泉。", "不爲流觴醉，來當滌萬緣。"]'),
('8b50f18d-cc31-4ac9-9c37-8ae0eb95db12','琅邪三十二詠 琅邪山','韋驤','宋','宋诗','song-poetry','','[]','晉王曾此隱，釋子住何年。',24,'全唐诗/poet.song.41000.json','["晉王曾此隱，釋子住何年。", "泉石無今古，圖經有後先。"]'),
('79e6418e-fa8f-4e5c-95a2-5771a98b298e','琅邪三十二詠 迴馬嶺','韋驤','宋','宋诗','song-poetry','','[]','有意尋幽勝，躋攀固所懷。',24,'全唐诗/poet.song.41000.json','["有意尋幽勝，躋攀固所懷。", "如今嶺路稳，鞍馬不須迴。"]'),
('cfea9436-a11b-48ea-a74c-6ca691d58692','琅邪三十二詠 開化寺','韋驤','宋','宋诗','song-poetry','','[]','架巘及依崖，軒窗次第開。',24,'全唐诗/poet.song.41000.json','["架巘及依崖，軒窗次第開。", "等爲方外客，於此更清懷。"]'),
('607a801c-3dec-44f3-9f92-d8a6585de03e','琅邪三十二詠 御書閣','韋驤','宋','宋诗','song-poetry','','[]','岌岌淩霄漢，風傳寶閣香。',24,'全唐诗/poet.song.41000.json','["岌岌淩霄漢，風傳寶閣香。", "三朝神翰在，奎壁夜交光。"]'),
('8f11da6a-eab7-4385-b0ce-4ec0157b82c1','琅邪三十二詠 陽冰篆','韋驤','宋','宋诗','song-poetry','','[]','筆力真奇偉，磨崖幾百年。',24,'全唐诗/poet.song.41000.json','["筆力真奇偉，磨崖幾百年。", "勿嫌人貴耳，此學世無傳。"]'),
('634460bb-f6a1-4901-a84d-79b0aca01ade','琅邪三十二詠 庶子泉','韋驤','宋','宋诗','song-poetry','','[]','宫相湮淪久，兹泉日夜生。',24,'全唐诗/poet.song.41000.json','["宫相湮淪久，兹泉日夜生。", "泉存人不見，空復著虛名。"]'),
('9830e912-085f-4219-9227-bc3f383d68b6','琅邪三十二詠 白龍泉','韋驤','宋','宋诗','song-poetry','','[]','殿角滀泓澄，源高登地靈。',24,'全唐诗/poet.song.41000.json','["殿角滀泓澄，源高登地靈。", "老僧來洗鉢，不畏白龍腥。"]'),
('d80bff89-e8f7-4bf8-905e-3ae1ba667823','琅邪三十二詠 酴醾軒','韋驤','宋','宋诗','song-poetry','','[]','詰曲小軒斜，酴醾一架遮。',24,'全唐诗/poet.song.41000.json','["詰曲小軒斜，酴醾一架遮。", "春風零落後，渾似雨天花。"]'),
('24df5ceb-9010-4932-8915-303979fa6e27','琅邪三十二詠 寂樂亭','韋驤','宋','宋诗','song-poetry','','[]','踏石穿林去，披雲就坐來。',24,'全唐诗/poet.song.41000.json','["踏石穿林去，披雲就坐來。", "禪翁寂樂地，猿鳥肯相猜。"]'),
('f3082b08-a906-42ca-be17-df6bbb4d4881','琅邪三十二詠 招隱堂','韋驤','宋','宋诗','song-poetry','','[]','小蹊回石角，締構倚山腰。',24,'全唐诗/poet.song.41000.json','["小蹊回石角，締構倚山腰。", "一片幽棲地，誰令便可招。"]'),
('f6f589f2-0ca5-42a9-bb2d-159b3c2e77a1','琅邪三十二詠 歸雲洞','韋驤','宋','宋诗','song-poetry','','[]','石洞何年有，名傳事或非。',24,'全唐诗/poet.song.41000.json','["石洞何年有，名傳事或非。", "那知爲雨後，却向此中歸。"]'),
('c6ad19aa-1857-4497-96aa-ebbca0b2d1a6','琅邪三十二詠 清風亭','韋驤','宋','宋诗','song-poetry','','[]','松竹繁陰滿，峰巒秀色并。',24,'全唐诗/poet.song.41000.json','["松竹繁陰滿，峰巒秀色并。", "暑風從此度，别是一般清。"]'),
('3156696e-52c7-4356-a522-378d6ae87798','琅邪三十二詠 大曆井','韋驤','宋','宋诗','song-poetry','','[]','竹裏藏深井，欄鐫大曆春。',24,'全唐诗/poet.song.41000.json','["竹裏藏深井，欄鐫大曆春。", "不知開鑿後，幾過鍊丹人。"]'),
('5163a68e-f6e8-4bff-868d-c7c37ded287b','琅邪三十二詠 千佛塔','韋驤','宋','宋诗','song-poetry','','[]','礲石施丹雘，凌雲勢亦孤。',24,'全唐诗/poet.song.41000.json','["礲石施丹雘，凌雲勢亦孤。", "如何千種相，併在一浮圖。"]'),
('4bf237d0-c591-4cce-8612-5d48d2d13008','琅邪三十二詠 石庵','韋驤','宋','宋诗','song-poetry','','[]','不獨烟霞窟，天然石作庵。',24,'全唐诗/poet.song.41000.json','["不獨烟霞窟，天然石作庵。", "坐禪遺跡在，巖溜自香甘。"]'),
('b308d0d8-f5c2-4bfb-9393-3a10cd3f8d97','琅邪三十二詠 曉光亭','韋驤','宋','宋诗','song-poetry','','[]','東面雙峰缺，遐瞻萬里平。',24,'全唐诗/poet.song.41000.json','["東面雙峰缺，遐瞻萬里平。", "朝朝滄海日，先向此中明。"]'),
('109aeb91-f75c-4b7a-b8ae-3da9100e9f07','琅邪三十二詠 了了堂','韋驤','宋','宋诗','song-poetry','','[]','了了還未了，都忘了始真。',24,'全唐诗/poet.song.41000.json','["了了還未了，都忘了始真。", "登堂知此意，方悟死前身。"]'),
('345b8196-1394-464b-9c52-2eb0b78cd237','琅邪三十二詠 望日臺','韋驤','宋','宋诗','song-poetry','','[]','曾有長安客，題爲望日臺。',24,'全唐诗/poet.song.41000.json','["曾有長安客，題爲望日臺。", "樵蘇人不測，到此亦裴回。"]'),
('56845a22-6493-4b04-a8f6-801706b1ac7e','琅邪三十二詠 石屏風','韋驤','宋','宋诗','song-poetry','','[]','造化非無意，都如圖畫中。',24,'全唐诗/poet.song.41000.json','["造化非無意，都如圖畫中。", "猶嫌未奇怪，更出石屏風。"]'),
('4fc3df17-3fff-4119-a0fb-44b8c7372f03','琅邪三十二詠 會峰亭','韋驤','宋','宋诗','song-poetry','','[]','勝概當衝要，回環擁翠巒。',24,'全唐诗/poet.song.41000.json','["勝概當衝要，回環擁翠巒。", "煙雲藏不得，如在掌中看。"]'),
('dd1bdae0-455b-4542-97d9-d2568b0042d7','琅邪三十二詠 法華池','韋驤','宋','宋诗','song-poetry','','[]','會峰亭下路，斜带法華池。',24,'全唐诗/poet.song.41000.json','["會峰亭下路，斜带法華池。", "不待觀池水，塵迷已頓離。"]'),
('657dbf5a-9ee5-4eaf-b781-a4d6a5a6927a','琅邪三十二詠 東峰亭','韋驤','宋','宋诗','song-poetry','','[]','山中時節早，地勢近春華。',24,'全唐诗/poet.song.41000.json','["山中時節早，地勢近春華。", "歲歲東風至，先看傍砌花。"]'),
('45ae3dfa-e23a-4512-9329-c75f38de8356','客舍早春','韋驤','宋','宋诗','song-poetry','','[]','早春晴靄乍悠悠，客舍深沈物趣幽。',64,'全唐诗/poet.song.41000.json','["早春晴靄乍悠悠，客舍深沈物趣幽。", "日薄草頭初破甲，風旋鳥毳偶成毬。", "庭柯憔悴紅猶遠，池水澄明淥漸浮。", "隱吏近來多鞅掌，紓懷何處一登樓。"]'),
('522f2cba-5d9c-497d-a853-6a5537a6abd1','栩栩亭','韋驤','宋','宋诗','song-poetry','','[]','碧崖高處築遺基，締構岧然得所依。',64,'全唐诗/poet.song.41000.json','["碧崖高處築遺基，締構岧然得所依。", "境趣似仙探絕跡，登臨如夢悟輕飛。", "路穿幽谷雲霞密，勢接豐山草木稀。", "欲識主公題榜意，不容紛擾累忘機。"]'),
('f15b0794-9260-462e-b35f-d1a185412a08','偃蓋松','韋驤','宋','宋诗','song-poetry','','[]','摧折風霜久，猶傳偃蓋松。',24,'全唐诗/poet.song.41000.json','["摧折風霜久，猶傳偃蓋松。", "只憑文筆力，何必大夫封。"]'),
('b16567f8-87f2-49e4-8d69-ccf984762fed','春曉','韋驤','宋','宋诗','song-poetry','','[]','百舌穿林語未完，悠悠歸夢忽驚殘。',32,'全唐诗/poet.song.41000.json','["百舌穿林語未完，悠悠歸夢忽驚殘。", "心知庭外春霜重，裘壓单衾覺曉寒。"]'),
('0c852111-597f-4ee9-980f-421bd6270e4a','海陵逢春','韋驤','宋','宋诗','song-poetry','','[]','海角春初至，林樊氣未和。',48,'全唐诗/poet.song.41000.json','["海角春初至，林樊氣未和。", "天寒梅發晚，沙近雁飛多。", "窗紙疏明玉，簾旌蕩翠波。", "旅懷隨日長，索莫不勝歌。"]'),
('b6012fa7-24be-45cd-a3f2-b4e4a50ad79c','感興','韋驤','宋','宋诗','song-poetry','','[]','富貴功名豈足邀，鷦鵬所得各逍遥。',32,'全唐诗/poet.song.41000.json','["富貴功名豈足邀，鷦鵬所得各逍遥。", "古今多少難齊事，燭理都如見睍消。"]'),
('f2a2e9e0-132e-443c-805f-2279474810bd','觀飛雁偶十有三','韋驤','宋','宋诗','song-poetry','','[]','肅羽度春晴，差肩足弟兄。',48,'全唐诗/poet.song.41000.json','["肅羽度春晴，差肩足弟兄。", "何時别燕塞，此日類秦筝。", "應律聲猶剩，排空字宛成。", "冥冥奚所滯，惆悵弋人情。"]'),
('b468e222-a867-4269-a7c7-b3dfe1439417','憶梅二首  其一','韋驤','宋','宋诗','song-poetry','','[]','去年幽谷探寒梅，把酒曾將累句催。',32,'全唐诗/poet.song.41000.json','["去年幽谷探寒梅，把酒曾將累句催。", "不意今年行海角，玉英開盡未歸來。"]'),
('7dc659fb-0651-4377-a05b-b26444914835','憶梅二首  其二','韋驤','宋','宋诗','song-poetry','','[]','向來踏雪舊枝旁，指日相期折素香。',32,'全唐诗/poet.song.41000.json','["向來踏雪舊枝旁，指日相期折素香。", "可是去春吟太苦，闇招離别間清狂。"]'),
('9950b4d7-aca0-44b1-878c-3b544cfe43cf','近元夕懷景純少卿','韋驤','宋','宋诗','song-poetry','','[]','憶逐雙旌下暮城，歲華垂盡魄哉生。',64,'全唐诗/poet.song.41000.json','["憶逐雙旌下暮城，歲華垂盡魄哉生。", "瞬眸已見元宵月，歸步猶淹累日程。", "遠想笙簫同衆樂，坐憐刀筆久相嬰。", "馳情只有清輝共，更走詩筒代寄聲。"]'),
('42fcaffd-9e3b-4d8f-b4b4-522e003c47ef','燈花','韋驤','宋','宋诗','song-poetry','','[]','燁燁銀檠上，開榮歘爾新。',48,'全唐诗/poet.song.41000.json','["燁燁銀檠上，開榮歘爾新。", "芳心唯報喜，艷色不關春。", "翠幕障風稳，蘭膏借潤頻。", "屢占皆取驗，始信有花神。"]'),
('6003cf69-0c40-4b9e-9cfb-93523b50b6fe','水精筆架','韋驤','宋','宋诗','song-poetry','','[]','璞琢窮工巧，書帷適用高。',48,'全唐诗/poet.song.41000.json','["璞琢窮工巧，書帷適用高。", "得鄰輝寶墨，棲跡卧文毫。", "匪月光長在，非冰暑自逃。", "千金不論直，一字若爲褒。"]'),
('057c4858-306a-46d7-a665-d9a4ae29e287','自寶豐鎮移紅蕉於永陽後圃','韋驤','宋','宋诗','song-poetry','','[]','爲愛紅蕉品格殊，移根千里涉崎嶇。',32,'全唐诗/poet.song.41000.json','["爲愛紅蕉品格殊，移根千里涉崎嶇。", "不知今歲秋陽裏，能有丹心似舊無。"]'),
('0e35a072-7de1-4c4a-95e9-e6257d5f632e','風琴','韋驤','宋','宋诗','song-poetry','','[]','穴竹張弦聳碧空，不勞抑按任天風。',64,'全唐诗/poet.song.41000.json','["穴竹張弦聳碧空，不勞抑按任天風。", "莫誇有智藏聲足，須信無心觸處通。", "明月夜深飄更遠，閒窗人静聽何窮。", "知音弗辨山兼水，都在洪鈞一噫中。"]'),
('8cacc3fb-554f-4d3d-ac0d-75cb41281759','雁屏','韋驤','宋','宋诗','song-poetry','','[]','羽翮本雲程，丹青入小屏。',48,'全唐诗/poet.song.41000.json','["羽翮本雲程，丹青入小屏。", "長年離遠塞，盡日啄寒汀。", "暮角無驚勢，春風悄去翎。", "幾回疑繋帛，旅枕夢初醒。"]'),
('93748a60-dd84-4661-958d-ba0ac7215ab0','春寒','韋驤','宋','宋诗','song-poetry','','[]','簷霜重如雪，池水冷于冰。',48,'全唐诗/poet.song.41000.json','["簷霜重如雪，池水冷于冰。", "鳥舌生根澀，花心起怨憎。", "旅人尤倍覺，年少尚難勝。", "欲作新春飲，高樓未可登。"]'),
('49889d12-691d-4391-b736-0039690e11d7','春陰','韋驤','宋','宋诗','song-poetry','','[]','雲靄結青冥，成陰重復輕。',48,'全唐诗/poet.song.41000.json','["雲靄結青冥，成陰重復輕。", "雖知飬春色，終是慘人情。", "索莫初花態，躊躇去雁聲。", "芳時不宜忽，紫陌待暄晴。"]'),
('3c0ba095-4446-4176-8f6c-984490c6b877','詠馬','韋驤','宋','宋诗','song-poetry','','[]','種格得房精，權奇豈易名。',48,'全唐诗/poet.song.41000.json','["種格得房精，權奇豈易名。", "耳批秋竹薄，蹄蹴水雲輕。", "徒受雙覊制，誰知千里程。", "未爲良樂遇，春陌自長鳴。"]'),
('09fc9c93-c0d6-4509-bb08-c2239ae28047','詠素扇','韋驤','宋','宋诗','song-poetry','','[]','不羡裁紈妙，唯憐入手輕。',48,'全唐诗/poet.song.41000.json','["不羡裁紈妙，唯憐入手輕。", "月從天上落，風向座中生。", "却暑期宣力，經秋任寡情。", "人心能似此，及物豈無成。"]'),
('ec21deb9-e0ab-43d5-ae88-46939d98100e','火筯','韋驤','宋','宋诗','song-poetry','','[]','勁直不容偏，纖纖體並圓。',48,'全唐诗/poet.song.41000.json','["勁直不容偏，纖纖體並圓。", "附炎非曲致，執熱藉雙全。", "熾炭隨方減，寒灰應手然。", "洪爐在調適，持此以爲權。"]'),
('6055551e-8222-45ce-8535-9f73fc9bfec5','桔橰','韋驤','宋','宋诗','song-poetry','','[]','露井無窮惠，機心在桔橰。',48,'全唐诗/poet.song.41000.json','["露井無窮惠，機心在桔橰。", "淺深皆應取，俯仰不爲勞。", "固免羸瓶悔，全勝短綆操。", "如何翻鄙笑，抱甕自孤高。"]'),
('c141fd47-df88-4376-99a6-5ca7e86b6286','投壺格','韋驤','宋','宋诗','song-poetry','','[]','古來壺矢樂，今日亦鈞情。',48,'全唐诗/poet.song.41000.json','["古來壺矢樂，今日亦鈞情。", "慶馬誰亡法，論籌自有評。", "較能分勝負，按數計虧盈。", "好是摧機中，收功特地輕。"]'),
('5c2e5d9f-c018-45c0-be64-9f5795fa5009','花鐡書鎮','韋驤','宋','宋诗','song-poetry','','[]','鐡尺平如砥，銀花貼軟枝。',48,'全唐诗/poet.song.41000.json','["鐡尺平如砥，銀花貼軟枝。", "成由巧匠手，持以鎮書爲。", "弹壓全繄爾，推遷實在台。", "不能柔繞指，方册最相宜。"]'),
('e88cab95-579e-4b08-8b4e-b1a112b6309a','鵰狐圖','韋驤','宋','宋诗','song-poetry','','[]','戢翼下雲中，驚狐計遂窮。',48,'全唐诗/poet.song.41000.json','["戢翼下雲中，驚狐計遂窮。", "筆端傳擊搏，座上感英雄。", "猛勢看如活，妖魂覺已空。", "推姦當若此，不獨畫爲空。"]'),
('aeea32ec-04db-49db-a2ff-c4d49e64586a','詠影','韋驤','宋','宋诗','song-poetry','','[]','所賦一何鈞，悠悠各一身。',48,'全唐诗/poet.song.41000.json','["所賦一何鈞，悠悠各一身。", "行藏寧逆物，進退本由人。", "向晦都忘累，逢明固任真。", "含沙尙能禍，辨早莫因循。"]'),
('02e0ff8a-14dc-4340-9278-a81cf7355c09','詠聲','韋驤','宋','宋诗','song-poetry','','[]','寂寞曾非跡，能聞乃辨聲。',48,'全唐诗/poet.song.41000.json','["寂寞曾非跡，能聞乃辨聲。", "於人緣有感，在物本無情。", "濤怒中秋盛，雷威百里驚。", "更論空谷答，至理自相傾。"]'),
('0b1ac5ea-fbbc-48c8-a3fd-22c2c2871383','陳後主','韋驤','宋','宋诗','song-poetry','','[]','綺閣寶爲床，庭花曲韻長。',48,'全唐诗/poet.song.41000.json','["綺閣寶爲床，庭花曲韻長。", "三妃惑沈湎，十客助驕荒。", "不作强鄰備，還罹獨足殃。", "胡顔猶侍飲，更獻請封章。"]'),
('3eb9f713-3e31-4ae6-a2fe-d9f8b2c63e89','方竹杖','韋驤','宋','宋诗','song-poetry','','[]','鈞是龍孫種，憐方與衆殊。',48,'全唐诗/poet.song.41000.json','["鈞是龍孫種，憐方與衆殊。", "既能同勁直，還自表廉隅。", "雨露恩雖一，風霜跡更孤。", "端人以爲杖，氣類雅相符。"]'),
('7b9429cc-4ac0-4964-9b53-cb216281cadd','訪隱','韋驤','宋','宋诗','song-poetry','','[]','暫出紛囂外，相尋寂寞鄉。',48,'全唐诗/poet.song.41000.json','["暫出紛囂外，相尋寂寞鄉。", "掃門風竹影，撲座露花香。", "白玉爲琴軫，丹砂貯藥嚢。", "疑年閒試問，甲子亦都忘。"]'),
('c3467d2b-2059-4269-9c83-7b1cc326c7da','詠煙','韋驤','宋','宋诗','song-poetry','','[]','漠漠復霏霏，因風任所之。',48,'全唐诗/poet.song.41000.json','["漠漠復霏霏，因風任所之。", "山家晨起後，漁舍晚歸時。", "散遠連雲沒，飄斜誤鳥隨。", "更堪縈旅思，悵望碧江湄。"]'),
('09d04757-d018-447e-9534-6eb4c13b9310','探後園桃花二首  其一','韋驤','宋','宋诗','song-poetry','','[]','憶對殘花邀客醉，留連花下惜芳辰。',32,'全唐诗/poet.song.41000.json','["憶對殘花邀客醉，留連花下惜芳辰。", "而今只待微紅露，便向枝頭覓舊春。"]'),
('f0a4ded3-f9eb-459a-9117-736d9dacd179','探後園桃花二首  其二','韋驤','宋','宋诗','song-poetry','','[]','藉草開樽往興深，搖花落盞十分斟。',32,'全唐诗/poet.song.41000.json','["藉草開樽往興深，搖花落盞十分斟。", "當時已有今年約，肯放花殘負賞心。"]'),
('d1ee7a96-2fec-4d1e-b8b5-5f249e442101','溪上桃','韋驤','宋','宋诗','song-poetry','','[]','數本臨溪岸，春多色更夭。',48,'全唐诗/poet.song.41000.json','["數本臨溪岸，春多色更夭。", "暗香穿水膩，細蕊入風嬌。", "枝卧侵微草，紅繁蔽小橋。", "武陵迷客路，與此不相遼。"]'),
('658f5b4f-d9ff-40ab-8024-141ab4e52094','多景樓','韋驤','宋','宋诗','song-poetry','','[]','盡道人間占勝遊，天將多景遺斯樓。',64,'全唐诗/poet.song.41000.json','["盡道人間占勝遊，天將多景遺斯樓。", "江山遠顧窮千里，風月平分入兩州。", "日日高明疑後夜，年年瀟灑覺先秋。", "不知今古登臨客，消却塵懷幾斛愁。"]'),
('9c04d0a0-faa5-417a-b151-ea58d106027a','和吕景純以梅花盛開見寄','韋驤','宋','宋诗','song-poetry','','[]','曉寒雖在有春催，坐想庭梅爛漫開。',64,'全唐诗/poet.song.41000.json','["曉寒雖在有春催，坐想庭梅爛漫開。", "滯跡方愁冰蕊過，清風還喜玉音來。", "傳芳酷重裁雲手，比美遥評傅粉腮。", "歸見餘花須共醉，相宜况有水精杯。"]'),
('4be2ed25-ec34-4bdf-a8a8-76a527c47be2','又和燈夕見寄','韋驤','宋','宋诗','song-poetry','','[]','瞥來海國未言旋，歘見新春換舊年。',64,'全唐诗/poet.song.41000.json','["瞥來海國未言旋，歘見新春換舊年。", "佳節阻陪千騎樂，元宵空想萬燈燃。", "民聲喧溢豐時歲，酒價飛騰要市鄽。", "多謝高情不遐棄，清詩相寄寶珠圓。"]'),
('1da0936d-7e68-4629-b43c-b8fd4614e506','春思五首  其一','韋驤','宋','宋诗','song-poetry','','[]','庭前弱柳黄金線，池畔新苔綠玉錢。',32,'全唐诗/poet.song.41000.json','["庭前弱柳黄金線，池畔新苔綠玉錢。", "可是燕鴻戀韶景，猶將健羽度晴天。"]'),
('3b48bc9e-1e9f-4f71-8687-c4173b4de318','春思五首  其二','韋驤','宋','宋诗','song-poetry','','[]','香心夭艷尚包藏，蜂蝶優游苦未忙。',32,'全唐诗/poet.song.41000.json','["香心夭艷尚包藏，蜂蝶優游苦未忙。", "何處紙鳶飛白晝，幾家歸燕認雕梁。"]'),
('08f6360b-245e-454c-b33a-fd9ebed55024','春思五首  其三','韋驤','宋','宋诗','song-poetry','','[]','青煙拂拂撲晴暉，簾幕無風永日垂。',32,'全唐诗/poet.song.41000.json','["青煙拂拂撲晴暉，簾幕無風永日垂。", "不恨離人歸不早，只疑春色故相欺。"]'),
('a2a6fb1e-5fa2-4028-ba03-17c9f91b154e','春思五首  其四','韋驤','宋','宋诗','song-poetry','','[]','近來碧瓦減朝霜，春意垂垂滿衆芳。',32,'全唐诗/poet.song.41000.json','["近來碧瓦減朝霜，春意垂垂滿衆芳。", "未睹花光照庭榭，且看草色繞池塘。"]'),
('b9d2e027-609d-4d9e-8148-0bbeec89b019','春思五首  其五','韋驤','宋','宋诗','song-poetry','','[]','半慘半舒雲外日，似無似有水邊風。',32,'全唐诗/poet.song.41000.json','["半慘半舒雲外日，似無似有水邊風。", "覉愁不爲陽和減，只恐因春綠鬢空。"]'),
('c3161577-b441-47d5-9c12-ce463d5621c4','春遊','韋驤','宋','宋诗','song-poetry','','[]','春遊是處接紛華，寒食風光日欲斜。',64,'全唐诗/poet.song.41000.json','["春遊是處接紛華，寒食風光日欲斜。", "柳拂畫橋嘶玉勒，草綿香陌度金車。", "雲邊蹴鞠聲相遠，花外鞦韆影半遮。", "莫羡少年多意思，隨時行樂自無涯。"]'),
('e7b10695-5f18-477b-a04a-dc1993f8e782','將歸','韋驤','宋','宋诗','song-poetry','','[]','他鄉蔽訟改新年，事竟歸心頓釋然。',64,'全唐诗/poet.song.41000.json','["他鄉蔽訟改新年，事竟歸心頓釋然。", "坐厭簾間窺晝景，行將馬上看春天。", "無窮芳草含朝霧，幾許初花倚暮烟。", "長陌風光應漸好，覊懷朝夕付金鞭。"]'),
('811a81fe-0e60-4256-80d0-530693c5d0b2','蔡仲遠內翰出虢州劉龍圖所寄詩因次其韻','韋驤','宋','宋诗','song-poetry','','[]','暫離翰苑出南州，匼匝金覊絡馬頭。',64,'全唐诗/poet.song.41000.json','["暫離翰苑出南州，匼匝金覊絡馬頭。", "泉石清幽爲己物，耕桑勤苦共民憂。", "筆驅滯事如飛電，語決塵緣似破漚。", "內閤舊交詩遠寄，心期猶未許裴休。"]'),
('b55e32fe-de87-4d86-a2be-d556cbd3fd00','和仲遠留題方鋭長老方丈','韋驤','宋','宋诗','song-poetry','','[]','當知迷悟不相因，舉手如何拂鑑塵。',32,'全唐诗/poet.song.41000.json','["當知迷悟不相因，舉手如何拂鑑塵。", "試問禪翁住方丈，近來多少晚參人。"]'),
('2020c03b-919d-4c51-ae35-e94923d647ee','又和仲遠答鋭長老二首  其一','韋驤','宋','宋诗','song-poetry','','[]','庭柏經霜色半黄，暫安禪室意陽陽。',32,'全唐诗/poet.song.41000.json','["庭柏經霜色半黄，暫安禪室意陽陽。", "高懷洞見人間世，鳬鶴紛紛自短長。"]'),
('66761502-595f-4388-ae0e-ba8c60434efa','又和仲遠答鋭長老二首  其二','韋驤','宋','宋诗','song-poetry','','[]','山前旌劍弄晴光，瞻謁裴回殿角香。',32,'全唐诗/poet.song.41000.json','["山前旌劍弄晴光，瞻謁裴回殿角香。", "却坐靈堂問禪伯，莫持迂論作金湯。"]'),
('f272259c-0baa-4353-8d61-ebca6a92d731','送周開祖赴闕引對','韋驤','宋','宋诗','song-poetry','','[]','君繇雁蕩解官時，我亦琅邪受代歸。',64,'全唐诗/poet.song.41000.json','["君繇雁蕩解官時，我亦琅邪受代歸。", "邂逅故鄉方道舊，逡巡行舸又成違。", "十年離合都如夢，千里衝蒙勿自欷。", "况是楓庭將奏課，好攄奇藴動恩輝。"]'),
('99b8ffc6-a8b4-456d-8b27-0aaaac9a5d87','和鄧温伯內翰九月七日約遊北高峰','韋驤','宋','宋诗','song-poetry','','[]','幸奉清遊入翠微，陰雲漏日照旌旗。',64,'全唐诗/poet.song.41000.json','["幸奉清遊入翠微，陰雲漏日照旌旗。", "登高預整孟嘉帽，訪古閒尋白傅詩。", "桂子正傳飄岝峉，菊英先喜泛瑠璃。", "公歸留宿湖山暮，恐誤郊關竹馬兒。"]'),
('da9b4a8c-4ac9-491e-8c94-a03ad1feb8db','用别韻再和','韋驤','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','岱嶽參天十八盤，當年旌旆許追攀。',64,'全唐诗/poet.song.41000.json','["岱嶽參天十八盤，當年旌旆許追攀。", "兹遊况近重陽節，何幸還陪一日閒。", "陟巘舍車登岌岌，愛泉持酒聽潺潺。", "玉堂健筆成高詠，欲和臨池恨思慳。"]'),
('efa1c86f-5704-4e52-ba17-5e0b8229a376','和温伯道舊見寄','韋驤','宋','宋诗','song-poetry','','[]','憶隨星騎按膠東，屢說餘杭氣象雄。',64,'全唐诗/poet.song.41000.json','["憶隨星騎按膠東，屢說餘杭氣象雄。", "今日共爲鄉里慶，看公雙擁旆旌紅。", "回環山水仙壺外，高下樓臺畫幅中。", "剩把豪篇傳美概，免教清話又成空。"]'),
('9a9748f2-7f82-44a1-9d48-b94704072bd2','又和九日有懷見寄','韋驤','宋','宋诗','song-poetry','','[]','九日風光不可辜，更堪瀟灑在江隅。',64,'全唐诗/poet.song.41000.json','["九日風光不可辜，更堪瀟灑在江隅。", "興如藍水真能適，詩比齊山亦自娱。", "莫向三秋悲齒髪，須將一醉等賢愚。", "酒闌忽憶膠東路，跋馬隨軒望上都。"]'),
('27a00f23-e27a-4f42-a737-968ff6626115','致政孫朝請過故里爲五老之會','韋驤','宋','宋诗','song-poetry','','[]','榮參天上列星躔，閒向人間作地仙。',64,'全唐诗/poet.song.41000.json','["榮參天上列星躔，閒向人間作地仙。", "故里相逢十華鬢，一時同會五高年。", "圖傳略過商山叟，齒序幾齊洛宅賢。", "有子奉觴公最美，繡衣使者綵衣鮮。"]'),
('b45abcb2-2219-4f55-a51c-9e39054f46dd','胡巨源郎中挽詞三首  其一','韋驤','宋','宋诗','song-poetry','','[]','官榮符列宿，政術妙專城。',48,'全唐诗/poet.song.41000.json','["官榮符列宿，政術妙專城。", "未盡平生藴，俄從長夜行。", "坦情歸浩蕩，爽氣入清明。", "獨有南州俗，空傳遺愛聲。"]'),
('0b82f283-afa3-44c8-9c15-2f135ebdfe2b','胡巨源郎中挽詞三首  其二','韋驤','宋','宋诗','song-poetry','','[]','語論常驚座，精神迥照人。',48,'全唐诗/poet.song.41000.json','["語論常驚座，精神迥照人。", "中途多坎壈，久疾遂湮淪。", "彷彿朱輪改，裴回畫翣新。", "秋風入哀挽，行路亦傷神。"]'),
('44409675-6a1e-43ff-96f5-f33297a50f67','胡巨源郎中挽詞三首  其三','韋驤','宋','宋诗','song-poetry','','[]','汲守卧猶治，馮郎髪半華。',48,'全唐诗/poet.song.41000.json','["汲守卧猶治，馮郎髪半華。", "冥鴻方避弋，美玉已埋砂。", "露濕銘旌重，風隨輓紼斜。", "九原無甚恨，嗣子善傳家。"]'),
('dcdc4ad9-4de5-4577-a4b4-a87a0cf74f11','汴上簡陳成伯學士','韋驤','宋','宋诗','song-poetry','','[]','除書何日到宣城，水驛迢迢引旆旌。',64,'全唐诗/poet.song.41000.json','["除書何日到宣城，水驛迢迢引旆旌。", "千里謳謡猶在耳，雙溪風月豈忘情。", "行庖薦玉淮魚美，坐席浮香楚醴清。", "何幸舊遊衰晚者，得隨舟尾共修程。"]'),
('9c4c6554-563e-4ca8-81eb-e0f9b9913d18','次韻答所和','韋驤','宋','宋诗','song-poetry','','[]','蒼茫雲水度淮城，檣影聯聯注羽旌。',64,'全唐诗/poet.song.41000.json','["蒼茫雲水度淮城，檣影聯聯注羽旌。", "汴泗幸隨行舸末，瀟湘况重故人情。", "晨征共濟襟懷豁，夜泊交談氣味清。", "應有高篇思宛句，可無美酎繼烏程。"]'),
('902a939f-e12d-4fb4-be27-716748cd4c7a','和見寄','韋驤','宋','宋诗','song-poetry','','[]','公到蓬瀛十五春，我猶碌碌似輕身。',64,'全唐诗/poet.song.41000.json','["公到蓬瀛十五春，我猶碌碌似輕身。", "自忻今日旌軒遇，却憶當年研席親。", "高論聳聽多皦皦，孤衷懶叙且循循。", "試將輩學樽前數，白髪相逢有幾人。"]'),
('28b5c0d7-e651-4e5c-9c81-a14228a91507','和丹陽守許仲途朝議春深飲會即席二首  其一','韋驤','宋','宋诗','song-poetry','','[]','寶爐香穗戰春寒，四座融怡極日懽。',64,'全唐诗/poet.song.41000.json','["寶爐香穗戰春寒，四座融怡極日懽。", "且樂杯觴隨水曲，莫愁煙雨滿江干。", "首題詩句争傳詠，欲插花枝更細看。", "衆客爲公須一醉，何妨倒著接䍦冠。"]'),
('2342a88a-ea8d-486d-bf12-dfa11cead1a0','和丹陽守許仲途朝議春深飲會即席二首  其二','韋驤','宋','宋诗','song-poetry','','[]','疑怪和風却暮寒，華堂賓主正酣歡。',64,'全唐诗/poet.song.41000.json','["疑怪和風却暮寒，華堂賓主正酣歡。", "人間高會真難偶，身外浮名豈足干。", "綠螘泛杯春可吸，紅英近燭夜宜看。", "梁塵莫逐歌聲轉，只恐紛紛撲醉冠。"]'),
('130e78f2-ac90-47e6-9101-68f2b83da28f','勸酒','韋驤','宋','宋诗','song-poetry','','[]','二月已破三月來，青春白日映樓臺。',32,'全唐诗/poet.song.41000.json','["二月已破三月來，青春白日映樓臺。", "勸君更飲一杯酒，一月人生笑幾迴。"]'),
('224139fd-86cf-492a-9bd9-76a94948bb87','離丹陽','韋驤','宋','宋诗','song-poetry','','[]','人從北固山前去，雲水蒼茫日向西。',32,'全唐诗/poet.song.41000.json','["人從北固山前去，雲水蒼茫日向西。", "今夜渡江何處宿，楊花落盡子規啼。"]'),
('847e0391-4a2b-4d02-99ca-ec8bba0bd6c1','惜花','韋驤','宋','宋诗','song-poetry','','[]','東風吹園雜花開，不忍虚擲委黄埃。',32,'全唐诗/poet.song.41000.json','["東風吹園雜花開，不忍虚擲委黄埃。", "且來相就飲一斗，漸老逢春能幾迴。"]'),
('e16a95eb-fd3e-4e9c-b47c-77583cf4f824','和陳成伯小飲','韋驤','宋','宋诗','song-poetry','','[]','布素平生友，如公乃達人。',48,'全唐诗/poet.song.41000.json','["布素平生友，如公乃達人。", "相逢臨遠水，累歲望清塵。", "萬語難窮意，三杯且混真。", "鵬鷦各飛舉，同是未歸身。"]'),
('96e79b1f-953f-4289-9fb2-327b00e79ec6','再和','韋驤','宋','宋诗','song-poetry','','[]','百丈卷河濱，相歡席上人。',48,'全唐诗/poet.song.41000.json','["百丈卷河濱，相歡席上人。", "香飄清近水，歌動净無塵。", "良會誠難必，開懷好任真。", "心期在他日，湖海共閒身。"]'),
('2ac835c5-6a3e-418d-9ea3-313cde321c53','再和陳成伯見寄集句三首','韋驤','宋','宋诗','song-poetry','','[]','兩篇藻思敵青春，開撥塵昏向此身。',64,'全唐诗/poet.song.41000.json','["兩篇藻思敵青春，開撥塵昏向此身。", "道舊悠悠言易感，論心炯炯誼還親。", "光陰似轂何難轉，事物如環且謾循。", "白雪調高知寡和，强歌徒愧郢中人。"]'),
('907725df-6ceb-49a3-b375-1f1c932fb067','舟次柳子小飲呈成伯學士','韋驤','宋','宋诗','song-poetry','','[]','久客無佳思，長途有戒心。',48,'全唐诗/poet.song.41000.json','["久客無佳思，長途有戒心。", "繫舟偕擇地，擊柝互傳音。", "西月光猶淺，南薰候已深。", "一樽雖冷落，所幸不孤斟。"]'),
('a7a9eab8-94a2-4212-926f-563a388e54f1','石懿老大夫生日','韋驤','宋','宋诗','song-poetry','','[]','萬石風流盛，中秋氣序清。',48,'全唐诗/poet.song.41000.json','["萬石風流盛，中秋氣序清。", "門弧當日慶，壽琖此時盈。", "庭下芝蘭茂，腰間印綬榮。", "况高頤養術，龜鶴得長生。"]'),
('adba935e-1350-4e3e-a5b6-275691a263c6','留别張樞言龍圖二首  其一','韋驤','宋','宋诗','song-poetry','','[]','夔臯事業久聲華，尚鬰謀猷世所嗟。',64,'全唐诗/poet.song.41000.json','["夔臯事業久聲華，尚鬰謀猷世所嗟。", "專閫收功全整暇，偃藩從請示優嘉。", "高談聳服三千客，和氣融怡十萬家。", "不日九天飛詔下，行看騕褭蹴堤沙。"]'),
('a8d0d1ed-5e7d-454f-951c-14107d6d05b7','留别張樞言龍圖二首  其二','韋驤','宋','宋诗','song-poetry','','[]','政成西蜀肆高懷，乞得東吳盛府開。',64,'全唐诗/poet.song.41000.json','["政成西蜀肆高懷，乞得東吳盛府開。", "千里慘舒都在手，百城趨禀孰爲才。", "恩寛疲瘵精神健，威懾姦憸膽氣摧。", "下客拳拳唯慕誼，欲違旌戟更徘徊。"]'),
('ef033be5-a603-4a99-8a33-3f7d0e9f96da','陳公武中散生日','韋驤','宋','宋诗','song-poetry','','[]','身作名卿早挂冠，飲冰清節久堅完。',64,'全唐诗/poet.song.41000.json','["身作名卿早挂冠，飲冰清節久堅完。", "門弧遠想當年慶，壽琖宜深此日歡。", "簪紱詵詵侍佳讌，弦匏苒苒戰輕寒。", "葭莩敢以詩爲獻，唯祝公如衛武安。"]'),
('def36ae2-bfc7-4010-9338-9e09e706f476','過金陵上僕射王舒公','韋驤','宋','宋诗','song-poetry','','[]','天眷皇圖盛，真儒德性高。',288,'全唐诗/poet.song.41000.json','["天眷皇圖盛，真儒德性高。", "文章追孔孟，事業過伊皋。", "難進輕三幣，功收變一陶。", "斗樞符斡運，主柄贊持操。", "萬務繇吾揆，千齡慶所遭。", "邦財理豐本，民力較秋毫。", "惠徧農無乏，輸均役不騷。", "保兵知警守，祿吏絕貪饕。", "信令朝廷重，伸威塞境牢。", "深謀壓夷狄，侵地復岷洮。", "萬里耕桑富，中原氣象豪。", "河淤開億頃，海貢集千艘。", "著義尊經典，更科待雋髦。", "養材從引類，設學派紛袍。", "試士先三尺，傳師或六韜。", "進賢輕似汲，去弊勇如薅。", "化俗遷狙詐，乘時等鳳翺。", "赤心全皦皦，鄙議過滔滔。", "表正銷羣靡，言深决衆謟。", "郭崔奢自減，楊墨謬皆逃。", "勳烈輕銘鼎，光華外奏驁。", "台階迴遠趾，仙觀乞閒曹。", "異寵藏珍带，優恩避節旄。", "鍾山歸舊隱，槐府輟先勞。"]'),
('b0f28e43-e866-43a8-bbd2-7eeeb7fcf14c','送范子鎮承議同年宰清源','韋驤','宋','宋诗','song-poetry','','[]','願君安慮宰清源，已雪南閩大獄冤。',64,'全唐诗/poet.song.41000.json','["願君安慮宰清源，已雪南閩大獄冤。", "勿嘆割雞猶屈刃，當知容駟可高門。", "解舟蘭水春沙淺，稅鞅榆關夏木繁。", "所得最多公誼在，他年富貴豈須論。"]'),
('dacafef1-14e7-443b-8a31-ddd005da2b78','中書張侍郎生日','韋驤','宋','宋诗','song-poetry','','[]','薰風初泛舜弦聲，崧嶽儲精王佐生。',64,'全唐诗/poet.song.41000.json','["薰風初泛舜弦聲，崧嶽儲精王佐生。", "巨室當時慶弧矢，熙朝今日贊機衡。", "燕堂榮映台躔近，壽琖光浮晝景清。", "願祝修齡如衛武，長揮相筆化隆平。"]'),
('71001a6b-b682-406e-a581-dd198b6bec7b','遷居近局謝陳成伯假車惠茶','韋驤','宋','宋诗','song-poetry','','[]','冷官遠室足間關，疲馬羸兵倦往還。',64,'全唐诗/poet.song.41000.json','["冷官遠室足間關，疲馬羸兵倦往還。", "局左卜居甘迫窄，城東寓跡謝寛閒。", "短轅助載方銜惠，靈荈蠲煩愈厚顔。", "兩腋風生家事少，併吟慚匪昔賢班。"]'),
('e308b246-1cbc-47ac-9323-6ae342b9916c','再和答篇','韋驤','宋','宋诗','song-poetry','','[]','爲困奔馳乃近遷，勿咍飛倦不知還。',64,'全唐诗/poet.song.41000.json','["爲困奔馳乃近遷，勿咍飛倦不知還。", "趁朝遂免三更起，歸舍新添數刻閒。", "謾致鄙篇酬雅貺，却煩秀句解衰顔。", "高軒若許來驚座，陋室杯盤亦可班。"]'),
('79ad019a-f45d-4e60-a7d6-65e0c746d7d3','又和來篇','韋驤','宋','宋诗','song-poetry','','[]','已愧蒼葭倚玉難，更慚投礫引珠還。',64,'全唐诗/poet.song.41000.json','["已愧蒼葭倚玉難，更慚投礫引珠還。", "盧生破屋居新穩，韓子豪篇語自閒。", "雖有清樽佇高躅，須期黄菊奉朱顔。", "自惟雅集猶淹緩，詩戰雄師未必班。"]'),
('bf7ffd00-72cf-4c7f-ab4f-6cbd8112547e','和趙達夫元夕禮闈鎖宿','韋驤','宋','宋诗','song-poetry','','[]','元宵鎖宿禮闈清，春意寒威兩戰争。',64,'全唐诗/poet.song.41000.json','["元宵鎖宿禮闈清，春意寒威兩戰争。", "月照樓臺疑晝景，風傳車馬訝雷聲。", "蹉跎自愧青雲志，勤苦須憐皓首生。", "勿嘆拘攣度良夕，共開精鍳選經明。"]'),
('a16d1405-7251-4cab-a21b-82b7f7720e2c','次韻楊久中将試進士','韋驤','宋','宋诗','song-poetry','','[]','雙扉盡日關，舊觀恍然還。',48,'全唐诗/poet.song.41000.json','["雙扉盡日關，舊觀恍然還。", "進士將紛集，經生且暫閒。", "較材歸俊傑，兀坐屬疏頑。", "遠想駒空谷，移文愧北山。"]'),
('80132d52-cc28-4325-b9ae-ba071981af52','又和鎖宿即事','韋驤','宋','宋诗','song-poetry','','[]','金門拜敕望嚴宸，禁陌聯鑣傍早春。',64,'全唐诗/poet.song.41000.json','["金門拜敕望嚴宸，禁陌聯鑣傍早春。", "此日貢闈身亦與，昔年文陣意如新。", "爲僚况偶羣英集，投隙何妨雅論頻。", "共念殘科多滯士，歸期緩指甲申旬。"]'),
('0575b5ed-d10d-4e95-9ec2-8820ef2ea72b','示黄彦發歐陽勉甫道舊','韋驤','宋','宋诗','song-poetry','','[]','浮世難逢故舊併，貢闈風月可忘情。',64,'全唐诗/poet.song.41000.json','["浮世難逢故舊併，貢闈風月可忘情。", "當年論事皆陳跡，此日評文亦浪名。", "荏苒光陰踰一紀，間關志氣話平生。", "且將觴詠消閒隙，鵬鷃逍遥理自明。"]'),
('cf6c5392-07cc-48a5-a9ee-ae7b24dff2fc','和久中聞笛','韋驤','宋','宋诗','song-poetry','','[]','風搖古木影蕭森，何處飄來暮笛音。',64,'全唐诗/poet.song.41000.json','["風搖古木影蕭森，何處飄來暮笛音。", "杳杳迥如天上曲，悠悠不減隴頭吟。", "未逢明月心猶恨，却憶殘梅興亦深。", "幽思縈迴長不斷，欲量應及数千尋。"]'),
('eba63141-2bff-47fc-a4b0-4f0c3328589c','和達夫雪霽','韋驤','宋','宋诗','song-poetry','','[]','雪餘著處是瓊瑶，惜向春風勢易消。',64,'全唐诗/poet.song.41000.json','["雪餘著處是瓊瑶，惜向春風勢易消。", "野色澄明經一洗，鳥聲喧滑自相招。", "潤通弱柳晴林媚，清逼歸鴻雲路遥。", "浩蕩幽懷吟不盡，高樓斜日望寥寥。"]'),
('787b6819-8dc2-4c30-aa09-e2fb69199246','戲呈吳伯固同年','韋驤','宋','宋诗','song-poetry','','[]','白玉墀前共得仙，而今邂逅半華顛。',64,'全唐诗/poet.song.41000.json','["白玉墀前共得仙，而今邂逅半華顛。", "評文我辨異同字，由義君持難易權。", "畏簡不能成共酌，紓情莫惜寄新篇。", "上林春晚歸鞭動，意思何如癸巳年。"]'),
('36cba903-a8ac-44fe-b58e-3d7dfe6af2e1','又次前韻答所和詩','韋驤','宋','宋诗','song-poetry','','[]','裁句清如李謫仙，揮毫放浪近張顛。',64,'全唐诗/poet.song.41000.json','["裁句清如李謫仙，揮毫放浪近張顛。", "偶於貢部同官責，更向詩壇擅將權。", "戲筆謾追丹桂舊，報言還愧木瓜篇。", "一樽何處偕吟嘯，浩興猶堪逐少年。"]'),
('88fc7612-45af-43ab-a925-f84fdabab6c9','和久中春風','韋驤','宋','宋诗','song-poetry','','[]','二月東風勢渺漫，侵陵和景作清寒。',64,'全唐诗/poet.song.41000.json','["二月東風勢渺漫，侵陵和景作清寒。", "發揚造化非無力，鼓動芳菲自有端。", "鬭草戲兒憂手瘃，懷邊思婦忍眉攢。", "祗輸便腹忘機者，不廢書帷晝寢安。"]'),
('bf235ce1-ce68-4c08-ab1d-5c1c7a9c7334','寄陳君佐','韋驤','宋','宋诗','song-poetry','','[]','山陽判袂幾三紀，鐡柱題名過十年。',64,'全唐诗/poet.song.41000.json','["山陽判袂幾三紀，鐡柱題名過十年。", "聚散信如萍逐水，光陰奚翅筈離絃。", "高材未用君猶健，弱羽無心我自全。", "鳬鶴短長何足算，相逢樽酒且留連。"]'),
('af6f32ea-d3a8-4627-ae94-06d234a242b7','和吳子友貢院作','韋驤','宋','宋诗','song-poetry','','[]','曉躍驊騮紫禁開，詔音不許少淹迴。',64,'全唐诗/poet.song.41000.json','["曉躍驊騮紫禁開，詔音不許少淹迴。", "斜鞭忽過天街柳，曳履還侵佛閤苔。", "晝幕四垂如近漢，夜燈相比似占台。", "會將精識掄荆璞，當有孚尹應手來。"]'),
('dcda0835-63f3-415a-a702-71a647e7c77d','和中裕古鑑','韋驤','宋','宋诗','song-poetry','','[]','君有青銅獨可憐，規模奇古衆疑年。',64,'全唐诗/poet.song.41000.json','["君有青銅獨可憐，規模奇古衆疑年。", "寒光不減雖人致，真鑑無期本自然。", "秋水未堪方洞照，霜蟾應是恨長圓。", "主人較藝還如爾，坐别嫫施醜與妍。"]'),
('3bb6ff76-577b-4461-820e-1367f5a25a65','京居','韋驤','宋','宋诗','song-poetry','','[]','冷官仍白髪，陋巷足青苔。',48,'全唐诗/poet.song.41000.json','["冷官仍白髪，陋巷足青苔。", "彌月不書刺，經時長覆杯。", "未能依澗壑，空欲遠塵埃。", "聊作支離况，詩成祗自咍。"]'),
('b8f7f0d2-c250-44a4-ad71-2b953f00a723','送馮材叔宰蘄春','韋驤','宋','宋诗','song-poetry','','[]','海角分攜僅十年，鉅創鈞是偶生全。',64,'全唐诗/poet.song.41000.json','["海角分攜僅十年，鉅創鈞是偶生全。", "相逢未暇聊持酒，就别還驚欲放船。", "顧我滯蹤徒衮衮，羡君歸翅自翩翩。", "蘄春豈足勞餘刃，應有佳聲慰慊然。"]'),
('9d723d75-6b0a-4aa2-80fc-df66ee1fa8e0','韓敏之學士貳少府往拜凡三而未覯因致以詩','韋驤','宋','宋诗','song-poetry','','[]','一枝棲息又逢春，何幸高賢晚獲親。',64,'全唐诗/poet.song.41000.json','["一枝棲息又逢春，何幸高賢晚獲親。", "顧我畫墁慚所食，荷公傾蓋異于新。", "緒餘衮衮心尤慕，盤辟區區禮未伸。", "三望膺門漫刺字，且持累句愬因循。"]'),
('38f9e0f5-6462-4e03-9e7f-967b9a450446','邃明生日','韋驤','宋','宋诗','song-poetry','','[]','昴宿儲精嶽降神，乾坤鍾異鉅賢身。',64,'全唐诗/poet.song.41000.json','["昴宿儲精嶽降神，乾坤鍾異鉅賢身。", "間生慶候年彌永，輔世休聲日又新。", "台鼎梅調方夏實，鳳池風好正南薰。", "因時願祝松椿壽，長贊熙朝秉化鈞。"]'),
('c5831697-b6f7-44f7-ae00-19dfd0465c58','致政孫大夫挽詞','韋驤','宋','宋诗','song-poetry','','[]','榮養如公世所稀，薤歌今日勿深悲。',64,'全唐诗/poet.song.41000.json','["榮養如公世所稀，薤歌今日勿深悲。", "生封郎位腰金貴，老向仙鄉擁節隨。", "積德已酬高閈志，遺蹤何愧北山移。", "義方有子聲華重，千古靈丘起後思。"]'),
('bd225ad8-d118-4360-833d-90831d4cffd0','同文館試上舍和同事孔彦常學士即事','韋驤','宋','宋诗','song-poetry','','[]','筆陣收鋒考戰文，喧喧車馬隔重門。',64,'全唐诗/poet.song.41000.json','["筆陣收鋒考戰文，喧喧車馬隔重門。", "心矜力學求之密，目到雄辭氣不昏。", "美寶辨來三獻惬，雕蟲屏盡六經尊。", "囊封奏號須明發，吉夢應先徹九閽。"]'),
('2a96db0e-83e3-4bb8-ba36-72b387fe59e0','又和','韋驤','宋','宋诗','song-poetry','','[]','强繼高吟豈足論，聊持布鼓過雷門。',64,'全唐诗/poet.song.41000.json','["强繼高吟豈足論，聊持布鼓過雷門。", "解頤傳咏知辭妙，落筆酬言怯思昏。", "霜葉舞風鳴碧瓦，寒雲漏月射清尊。", "好傳秀句頻驚座，索馬行將戒守閽。"]'),
('09c934c2-eaa5-49a8-a999-ffdfb1e2bfb3','又和前韻呈彦常明叔','韋驤','宋','宋诗','song-poetry','','[]','軟語霏霏過夜分，程文都已辨專門。',64,'全唐诗/poet.song.41000.json','["軟語霏霏過夜分，程文都已辨專門。", "香焚龍腦神還健，書檢蝇頭眼易昏。", "騶從傳呼金闕曉，星辰環拱紫垣尊。", "拆封御史何時到，曳組相将謁禁閽。"]'),
('58e733e2-7815-4bf8-b4fa-9fd7e47b308e','較試將畢呈彦衡察院上官','韋驤','宋','宋诗','song-poetry','','[]','當年京口望清塵，德論於今想記頻。',64,'全唐诗/poet.song.41000.json','["當年京口望清塵，德論於今想記頻。", "何幸上庠參較藝，又依高鍳免遺珍。", "下帷晝寂霜威斂，揮麈宵寒月色新。", "早晚奏名歸駛迅，九衢多少避驄人。"]'),
('f955eaae-885c-48eb-98b2-66f90b98ebe4','又和彦常試院即事  其一','韋驤','宋','宋诗','song-poetry','','[]','城壖候館勢弘開，捧詔彤庭薄暮來。',64,'全唐诗/poet.song.41000.json','["城壖候館勢弘開，捧詔彤庭薄暮來。", "庠序旁延優上舍，行能參考見高才。", "糊名獨得珠無脛，摭實更忻山有萊。", "賢傑聞風争入彀，簞瓢何足樂顔回。"]'),
('40bc74d0-cd55-4284-849f-4ccee50433d8','又和彦常試院即事  其二','韋驤','宋','宋诗','song-poetry','','[]','天寒簾幕氣蕭騷，終日披文不厭勞。',64,'全唐诗/poet.song.41000.json','["天寒簾幕氣蕭騷，終日披文不厭勞。", "但有誠心禆藻鍳，敢矜明目察秋毫。", "璵璠啟襲光難掩，鵰鶚凌虚勢自高。", "號奏身閒無一事，唱酬尤喜得詩豪。"]'),
('a95e0f6b-db3f-4de2-a15a-9ae3a900f785','又和彦常試院即事  其三','韋驤','宋','宋诗','song-poetry','','[]','辨駿由來盡馬羣，裁聲今已得龍孫。',64,'全唐诗/poet.song.41000.json','["辨駿由來盡馬羣，裁聲今已得龍孫。", "不容一字虚褒貶，可見諸生究本源。", "衡鍳有憑宜自信，毫釐無益懶輕論。", "分携莫惜頻交語，且盡樽前蠟淚痕。"]'),
('7fcde034-abfe-49b0-8665-a2656fc3b7c8','呈郭奉議明叔','韋驤','宋','宋诗','song-poetry','','[]','嶠北分攜一紀逾，浮梁唯奉數行書。',64,'全唐诗/poet.song.41000.json','["嶠北分攜一紀逾，浮梁唯奉數行書。", "如何邂逅同縈絆，遂得從容接緒餘。", "道舊良多動嚬笑，忘形不覺度居諸。", "出門幸且時相顧，更望新篇數起予。"]'),
('2925e5b3-7ed2-497f-8b2e-a77740a4b0f9','食蛤蜊二首  其一','韋驤','宋','宋诗','song-poetry','','[]','適口珍鮮品格高，泥深海近不能逃。',32,'全唐诗/poet.song.41000.json','["適口珍鮮品格高，泥深海近不能逃。", "若教畢卓曾知味，豈肯甘心把蟹螯。"]'),
('58fca635-a309-4645-b343-a5f44ae3633d','食蛤蜊二首  其二','韋驤','宋','宋诗','song-poetry','','[]','自衛區區亦甚勤，刳腸剔柱奈何人。',32,'全唐诗/poet.song.41000.json','["自衛區區亦甚勤，刳腸剔柱奈何人。", "若知射影能相懼，應學含沙得保身。"]'),
('caefb77a-9edd-4da4-8fec-7745cd4eeb3f','謝鍾離中散公序惠草書','韋驤','宋','宋诗','song-poetry','','[]','留心不減漢張芝，體意俱完世學稀。',64,'全唐诗/poet.song.41000.json','["留心不減漢張芝，體意俱完世學稀。", "下筆欲爲來者法，臨池時見古人非。", "篇篇駭目神如電，字字凌虚勢若飛。", "多謝公餘憐所好，璨然累幅遺珠璣。"]'),
('c9681308-b1ef-46c4-9860-f18c503d6731','呈戶部李尚書二首  其一','韋驤','宋','宋诗','song-poetry','','[]','八座輝光道德隆，陋儒何幸奉從容。',64,'全唐诗/poet.song.41000.json','["八座輝光道德隆，陋儒何幸奉從容。", "聽言迥出羣賢表，顧己榮於萬戶封。", "密啟更慚先薦鶚，高門况是晚登龍。", "荷公恩意知難報，勁節當先比澗松。"]'),
('cac3fcc8-e569-4be1-bd8a-fd8e3192c7a1','呈戶部李尚書二首  其二','韋驤','宋','宋诗','song-poetry','','[]','三紀光陰疾若馳，一身孤宦亦逶迤。',64,'全唐诗/poet.song.41000.json','["三紀光陰疾若馳，一身孤宦亦逶迤。", "人疑碌碌非奇節，誰信囂囂足有爲。", "白髪精神憐晚景，青雲志氣慊卑枝。", "門闌此日蒙優遇，可是嚢中穎脱時。"]'),
('12c4530a-7657-4cc6-b4eb-8791b1bfc397','呈南鄰司門盛誨之同年','韋驤','宋','宋诗','song-poetry','','[]','昔詠相過人不知，于今想見少陵詩。',64,'全唐诗/poet.song.41000.json','["昔詠相過人不知，于今想見少陵詩。", "鄰居何幸偏依德，交語乘閒祗隔籬。", "攀桂當年聯步武，近蘭此日慰瞻思。", "冷官罷局方無頼，但向清風且樂饑。"]'),
('76c7d85c-e624-455a-9ec0-10c5c0eaa7c9','過二里山','韋驤','宋','宋诗','song-poetry','','[]','夜宿陳倉驛，朝行三里山。',48,'全唐诗/poet.song.41000.json','["夜宿陳倉驛，朝行三里山。", "千峰排欎鬰，萬石激潺潺。", "征馭來何亟，幽禽語自閒。", "塵勞亦知幸，勝景得躋攀。"]'),
('8463a285-6f1a-4b82-8557-76fb4a66ee4b','御愛山','韋驤','宋','宋诗','song-poetry','','[]','五峰列翠儼如屏，御愛知非浪得名。',32,'全唐诗/poet.song.41000.json','["五峰列翠儼如屏，御愛知非浪得名。", "行客勿輕加誚詠，播遷豈是不關情。"]'),
('013513fe-1a2b-4dd2-a823-e9bce5b91fe5','鳳翔劉明復龍圖刊李茂正德政碑勒移維摩塑像文求詩因寄','韋驤','宋','宋诗','song-poetry','','[]','龜趺螭首勢嵬然，輕重由來在所鐫。',64,'全唐诗/poet.song.41000.json','["龜趺螭首勢嵬然，輕重由來在所鐫。", "名削姦臣磨僞說，像遷居士記真詮。", "精文本自精誠出，妙手幡因妙相傳。", "以善闢邪殊可敬，爲公嗟嘆作詩篇。"]'),
('518ec892-a5f0-49a6-9a78-cdeb203437b7','和遂州太守李安上年兄見貽','韋驤','宋','宋诗','song-poetry','','[]','擁麾遥想陟崔嵬，驟喜清談復屢陪。',64,'全唐诗/poet.song.41000.json','["擁麾遥想陟崔嵬，驟喜清談復屢陪。", "攀桂當年追遠趾，偃藩今日仰高才。", "如公閎博難淹外，顧我迂疏任儻來。", "相遇且宜忘倍道，暫同持酒賦層臺。"]'),
('f8324212-64b2-49ab-aba6-779043c95c65','寄提刑岑巖起','韋驤','宋','宋诗','song-poetry','','[]','兩世同年世亦稀，同官同路復同詞。',64,'全唐诗/poet.song.41000.json','["兩世同年世亦稀，同官同路復同詞。", "登途先後無多日，聚論參差已過時。", "劍外石梯方息鞅，山南珍翰忽伸眉。", "情知邂逅當非晚，聊寓長言寫所思。"]'),
('27cb1b96-ede9-4bf9-9c67-d5b1aa65db96','過朝天嶺','韋驤','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','崔嵬陟盡復凌兢，暫捨銀鞍杖策行。',64,'全唐诗/poet.song.41000.json','["崔嵬陟盡復凌兢，暫捨銀鞍杖策行。", "棧閣架空霄路近，欄干護險曉雲平。", "仰看翠壁層城峻，下瞰長江一带縈。", "自惜仙才難蜀道，始知難此不虚名。"]'),
('eeaedcda-5bb6-4470-9254-98e76e078c1c','三盤閣','韋驤','宋','宋诗','song-poetry','','[]','江山千里勢雄豪，終日緣崖未是勞。',32,'全唐诗/poet.song.41000.json','["江山千里勢雄豪，終日緣崖未是勞。", "欲識寒心騎馬處，三盤閣上看驚濤。"]'),
('c7580d99-a54f-4f58-8b04-32142083641e','玉枕驛','韋驤','宋','宋诗','song-poetry','','[]','嵬然峭壁入青雲，玉枕光輝絕世塵。',32,'全唐诗/poet.song.41000.json','["嵬然峭壁入青雲，玉枕光輝絕世塵。", "豈是羣仙露奇跡，故將珍玩感途人。"]'),
('c47398eb-e2b7-49da-9ecd-be10f75e8a2c','過故平','韋驤','宋','宋诗','song-poetry','','[]','間關危棧過岧嶤，忽見平原旅恨銷。',32,'全唐诗/poet.song.41000.json','["間關危棧過岧嶤，忽見平原旅恨銷。", "却被飛濤送鄉思，悠悠想見浙江潮。"]'),
('8be24101-3ca7-4e9d-ac90-2a6d59174ecb','迴宿故縣驛','韋驤','宋','宋诗','song-poetry','','[]','回首邊城暮靄輕，亂山深處宿歸程。',32,'全唐诗/poet.song.41000.json','["回首邊城暮靄輕，亂山深處宿歸程。", "流泉遶榻鳴寒夜，别是勞生一段清。"]'),
('902280b3-ce44-4aba-804e-26efb554c24d','文劍道中','韋驤','宋','宋诗','song-poetry','','["\u897f\u6e56"]','劍閣文臺相去遥，朝行山頂暮行腰。',64,'全唐诗/poet.song.41000.json','["劍閣文臺相去遥，朝行山頂暮行腰。", "雙眸視險睛常眩，兩髀乘鞍肉半消。", "空有辛勤馳遠道，愧無毫末補清朝。", "何時解組歸鄉國，十里西湖弄短橈。"]'),
('68a36bdb-ea0c-41fd-8d15-979a2b75fb50','登科  其一','韋驤','宋','宋诗','song-poetry','','[]','先世曾誇尺五天，後來苗裔獨蕭然。',32,'全唐诗/poet.song.41000.json','["先世曾誇尺五天，後來苗裔獨蕭然。", "可憐三十三年內，科第唯吾父子傳。"]'),
('fd75ef01-a8ec-4862-9fd6-4f29764d78e5','登科  其二','韋驤','宋','宋诗','song-poetry','','[]','青雲意氣已參差，白髪精神祇自嗤。',32,'全唐诗/poet.song.41000.json','["青雲意氣已參差，白髪精神祇自嗤。", "喜汝登科年尚少，好攄事業趁明時。"]'),
('4972ad7f-36c1-4ca0-8849-b829667d30ea','黄石榴花','韋驤','宋','宋诗','song-poetry','','[]','六月羣芳歇，榴花拆淺黄。',48,'全唐诗/poet.song.41000.json','["六月羣芳歇，榴花拆淺黄。", "色方金菊淡，體異玉簪長。", "觸日猶能媚，迎風不在香。", "無勞問朱實，秀發占中央。"]'),
('b9fb309d-50e1-4cdf-b5c7-032871ff71c2','大行皇帝挽辭二首  其一','韋驤','宋','宋诗','song-poetry','','[]','聖文攄道妙，神武拓邊封。',48,'全唐诗/poet.song.41000.json','["聖文攄道妙，神武拓邊封。", "治跡超三代，焦心厭九重。", "方儀韶樂鳳，忽駕鼎湖龍。", "遺烈傳千世，鴻基固祖宗。"]'),
('3c717f66-49d9-47aa-b928-3dcb9d1184c8','大行皇帝挽辭二首  其二','韋驤','宋','宋诗','song-poetry','','[]','檢玉將封岱，遺弓已上僊。',48,'全唐诗/poet.song.41000.json','["檢玉將封岱，遺弓已上僊。", "新陵崇永裕，舊節罷同天。", "哀仗愁雲外，悲笳慘月邊。", "攀髯臣子恨，萬淚欲成川。"]'),
('d1b5d81f-2d33-499a-91db-e5b5f5544e71','再詠黄石榴花二首  其一','韋驤','宋','宋诗','song-poetry','','[]','花似新鵝色澤均，蕚如柘繭亂紛紛。',32,'全唐诗/poet.song.41000.json','["花似新鵝色澤均，蕚如柘繭亂紛紛。", "更臨返照遥凝目，翠幄無端惹瑞雲。"]'),
('964b2d86-ffb4-4ae6-9b34-f11440a1dcd5','再詠黄石榴花二首  其二','韋驤','宋','宋诗','song-poetry','','[]','佳人最愛石榴紅，染作輕裙步履同。',32,'全唐诗/poet.song.41000.json','["佳人最愛石榴紅，染作輕裙步履同。", "唯有此花難入意，任教榮悴逐薰風。"]'),
('e1598648-a54b-49d1-b459-cc975160df57','自劍還道中寄同事蘇進之','韋驤','宋','宋诗','song-poetry','','[]','君寓姑蘇吾舍杭，慣從雲水樂仙鄉。',64,'全唐诗/poet.song.41000.json','["君寓姑蘇吾舍杭，慣從雲水樂仙鄉。", "相逢邂逅趨端禮，同職間關到益昌。", "疲俗未肥心所病，故園何在夢偏長。", "新陽欲動林泉好，觴詠隨時且自强。"]'),
('a2121dac-dbd0-4c1f-82e0-ba9e5ca19da3','宿上亭驛','韋驤','宋','宋诗','song-poetry','','[]','按部嶔崎向梓潼，上亭孤驛倚寒空。',64,'全唐诗/poet.song.41000.json','["按部嶔崎向梓潼，上亭孤驛倚寒空。", "淋鈴盡想當時雨，吼地愁聞竟夕風。", "衝冒狂飈憂病體，驅除宿翳懶神功。", "翼朝攬轡逢清霽，致敬宜將樵意同。"]'),
('06dd5063-2ea7-46d5-be87-277862948a06','謁梓潼廟','韋驤','宋','宋诗','song-poetry','','[]','英威凛凛愯西州，血食潼江度幾秋。',64,'全唐诗/poet.song.41000.json','["英威凛凛愯西州，血食潼江度幾秋。", "曾運陰兵摧賊壘，每均甘澤惠農疇。", "翠幃半捲香烟動，金榜高題日影浮。", "暫止軺車聊一奠，肯將曲禱累神休。"]'),
('fb61633f-5c5a-4350-9b54-c9ccc92a35bf','題岑巖起劍門詩刻後','韋驤','宋','宋诗','song-poetry','','[]','撲面塵埃二十年，紗籠石刻頓光鮮。',32,'全唐诗/poet.song.41000.json','["撲面塵埃二十年，紗籠石刻頓光鮮。", "廋辭不用題黄絹，自有驚人秀句傳。"]'),
('2b67ec97-1d42-4acf-bc2b-661e8f11ba6d','和巖起觀舊詩有感','韋驤','宋','宋诗','song-poetry','','[]','棄繻東去有遺篇，杖節西還今幾年。',32,'全唐诗/poet.song.41000.json','["棄繻東去有遺篇，杖節西還今幾年。", "莫向長岐悲齒髪，似君行學可怡然。"]'),
('0464c9b1-42f5-41fb-834f-8999c29a9e42','又和十二月二十九日思封道中','韋驤','宋','宋诗','song-poetry','','[]','巴山險阻備嘗之，笑讀豪篇似抵巇。',64,'全唐诗/poet.song.41000.json','["巴山險阻備嘗之，笑讀豪篇似抵巇。", "况是歲華垂盡日，却爲賢者獨勞時。", "寒多未放泉聲活，春近先從柳眼知。", "早晚星軺趣回轡，東園共醉小枝枝。"]'),
('acc0bc1b-2fd2-40fa-b110-23b7da36284b','和資守許澤翁見寄','韋驤','宋','宋诗','song-poetry','','[]','十年爲别只逡巡，喜見來篇墨色新。',32,'全唐诗/poet.song.41000.json','["十年爲别只逡巡，喜見來篇墨色新。", "且解征鞍同一醉，異鄉難遇故鄉人。"]'),
('085cdc27-613a-4123-a437-f973a1b7a03d','長柳館','韋驤','宋','宋诗','song-poetry','','[]','地名長柳柳初長，下馬臨泉却坐床。',32,'全唐诗/poet.song.41000.json','["地名長柳柳初長，下馬臨泉却坐床。", "客舸傍沙收百丈，野禽窺水競雙翔。"]'),
('40f1eff6-5670-4587-9c32-c90dc16d2ce2','算錢鋪','韋驤','宋','宋诗','song-poetry','','[]','里名勝母曾車止，邑號朝歌墨馭還。',32,'全唐诗/poet.song.41000.json','["里名勝母曾車止，邑號朝歌墨馭還。", "我領漕權來此坐，不惟自哂且赬顔。"]'),
('d2d4bb9e-0a67-4d19-bb4b-b83a4186195c','見性堂','韋驤','宋','宋诗','song-poetry','','[]','由來迷悟盡真如，見性名堂亦謾書。',64,'全唐诗/poet.song.41000.json','["由來迷悟盡真如，見性名堂亦謾書。", "萬變紛紛任交戰，一心了了即安居。", "檻花夭秀烏能浼，庭柏孤高自有餘。", "多謝前人爲留意，使予聊得寓清虚。"]'),
('7b609210-d8fd-4e1d-bf7d-a1cc26ae1cf3','都竹道中','韋驤','宋','宋诗','song-poetry','','[]','陰平纔過萬山重，路指江油棧閣通。',64,'全唐诗/poet.song.41000.json','["陰平纔過萬山重，路指江油棧閣通。", "峰頂雲收餘夕雪，馬蹄塵少带春風。", "一溪水色瑠璃碧，幾塢梅花錦繡紅。", "莫謂奔馳足勞苦，目前佳趣亦無窮。"]'),
('d73bbf89-ba3d-452e-b85b-0fc6bb68974c','過赤崖潭','韋驤','宋','宋诗','song-poetry','','[]','輕軺曉過赤崖潭，莫訝凝眸涉再三。',64,'全唐诗/poet.song.41000.json','["輕軺曉過赤崖潭，莫訝凝眸涉再三。", "百丈澄瀾連底見，千尋翠壁與天參。", "釣絲森蔚迷芳岸，鵝管參差滴秀巖。", "勝概心藏俟能畫，肯教凡筆謾鐫鑱。"]'),
('fe1e88e9-1a28-4eaf-9301-02212ac8b25e','過雪峰亭','韋驤','宋','宋诗','song-poetry','','[]','二月春將半，山高雪未消。',48,'全唐诗/poet.song.41000.json','["二月春將半，山高雪未消。", "危亭在屏障，萬水綴瓊瑶。", "似與塵寰隔，安知雲路遥。", "區區澄按外，暫得駐輕軺。"]'),
('f5d66d79-7443-49c1-b677-eaa9a33cf649','經望星山','韋驤','宋','宋诗','song-poetry','','[]','緣崖陟磴勢凌兢，偏坐銀鞍傍險行。',32,'全唐诗/poet.song.41000.json','["緣崖陟磴勢凌兢，偏坐銀鞍傍險行。", "更向望星山上過，捫參方信不虚名。"]'),
('507e5b4f-c442-4a9a-91da-80540adf95cb','螗啼嶺','韋驤','宋','宋诗','song-poetry','','[]','臲卼肩輿半側身，嶔嶇石磴但無塵。',64,'全唐诗/poet.song.41000.json','["臲卼肩輿半側身，嶔嶇石磴但無塵。", "山行從隸難成列，路轉前驅却向人。", "更瞰江潭尤覺險，獨憐桃李解妝春。", "他時躍馬康莊稳，莫忘欹危蹙頞頻。"]'),
('466e2481-52e2-4774-8b18-9f2fe15ab178','亭溪道曉行','韋驤','宋','宋诗','song-poetry','','[]','白雲起處山櫻發，綠柳垂邊水螘鳴。',32,'全唐诗/poet.song.41000.json','["白雲起處山櫻發，綠柳垂邊水螘鳴。", "唯有曉寒殊未減，重裘還似冒霜行。"]'),
('f83407c3-f2ee-4b9a-b1c0-e64f1052becc','至白水驛輟趨文還益昌','韋驤','宋','宋诗','song-poetry','','[]','輟程趨疾且歸來，莫訝回船在不期。',32,'全唐诗/poet.song.41000.json','["輟程趨疾且歸來，莫訝回船在不期。", "恐失東園桃李色，一年深悔欲何追。"]'),
('f8f26dc8-ba85-4f81-a151-2808599b09ab','和許冲元內翰易元日登塔之遊爲再登','韋驤','宋','宋诗','song-poetry','','[]','浮屠屹屹勢參天，旌騎朝臨又改年。',64,'全唐诗/poet.song.41000.json','["浮屠屹屹勢參天，旌騎朝臨又改年。", "一日再登清興足，舊遊新變異時傳。", "嘉篇却寄踰千里，遺愛相仍沸兩川。", "塵淟剽聞肝膽醒，况陪勝覧即芳筵。"]'),
('a9b0608b-d6b2-4d8e-893b-935d4f549a87','又借前韻爲攀别之作','韋驤','宋','宋诗','song-poetry','','[]','紫詔催還二月天，清臺頒歷涉三年。',64,'全唐诗/poet.song.41000.json','["紫詔催還二月天，清臺頒歷涉三年。", "高文昔冠羣儒首，異政今爲兩蜀傳。", "此日旌旄度危棧，何時舟檝濟長川。", "笳鐃漸遠勞瞻望，猶想飛花傍祖筵。"]'),
('9e7b9727-f445-4a1f-afa9-145a7b6f8b5b','和岑巖起見寄三絕  其一','韋驤','宋','宋诗','song-poetry','','[]','别來凡歷幾重山，又報兼途策馬還。',32,'全唐诗/poet.song.41000.json','["别來凡歷幾重山，又報兼途策馬還。", "而我病軀方覺健，喜時觴酒助談間。"]'),
('4f94c76c-691c-4881-bc86-6131ba217cce','和岑巖起見寄三絕  其二','韋驤','宋','宋诗','song-poetry','','[]','分攜斜日在青山，不意黎明我遽還。',32,'全唐诗/poet.song.41000.json','["分攜斜日在青山，不意黎明我遽還。", "却向益昌迎馬首，由來無定是人間。"]'),
('acff277a-3183-443f-b896-f448e14beec8','和岑巖起見寄三絕  其三','韋驤','宋','宋诗','song-poetry','','[]','百丈江流萬仞山，一車方往一車還。',32,'全唐诗/poet.song.41000.json','["百丈江流萬仞山，一車方往一車還。", "若教說著邯鄲夢，都在胡盧掩口間。"]'),
('dfd9afdc-f5d1-4d0a-8df2-4440a6f0cd48','謝巖起寄鳳團茶','韋驤','宋','宋诗','song-poetry','','[]','北苑先春雲鳳團，封題分寄墨初乾。',64,'全唐诗/poet.song.41000.json','["北苑先春雲鳳團，封題分寄墨初乾。", "未甘金碾消磨了，且作瓊枝愛惜看。", "水異康王烹莫稱，才非盧子咏應難。", "强抽鄙句慚瑶報，佳惠輕酬豈自安。"]'),
('c211a42c-5afa-491e-a628-9a2b8068ca33','至西縣走呈巖起','韋驤','宋','宋诗','song-poetry','','[]','所部雖同邂逅稀，今年差比去年遲。',64,'全唐诗/poet.song.41000.json','["所部雖同邂逅稀，今年差比去年遲。", "蓼圖猶憶當時玩，菊酒還陪此日持。", "衰鬢已斑烏足嘆，壯心徒在竟何施。", "相逢且盡從容興，况是終更欲及期。"]'),
('9be33a3f-81f6-461a-a2b5-91c3a00fccb0','再和巖起以詩答謝惠團茶之句','韋驤','宋','宋诗','song-poetry','','[]','靈芽不減密雲團，十襲清香翠若乾。',64,'全唐诗/poet.song.41000.json','["靈芽不減密雲團，十襲清香翠若乾。", "蕪句聊紓情內動，明珠更得掌中看。", "輕投雅貺公爲易，併獲殊珍我自難。", "報德酬言古人重，斐章不再豈遑安。"]'),
('b9644c07-bd8a-42ed-bef0-d72136dc3a3d','城固道中先寄  其一','韋驤','宋','宋诗','song-poetry','','[]','暌違旬浃似朝晡，勞想清冰映玉壺。',32,'全唐诗/poet.song.41000.json','["暌違旬浃似朝晡，勞想清冰映玉壺。", "謾寄小詩馳鄙意，更能還貺雅篇無。"]'),
('70ddec40-9cde-4617-a6cd-d47df0209af7','城固道中先寄  其二','韋驤','宋','宋诗','song-poetry','','[]','稅鞅行郵日欲晡，漢皋重得造仙壺。',32,'全唐诗/poet.song.41000.json','["稅鞅行郵日欲晡，漢皋重得造仙壺。", "不知揮麈交談外，還許攏弦入聽無。"]'),
('8f504aa6-5c7c-4639-90a6-65111e9527dc','凌晨馬上得惠詩再次元韻  其一','韋驤','宋','宋诗','song-poetry','','[]','詩筒方訝惠音稀，擊鉢來篇果不遲。',64,'全唐诗/poet.song.41000.json','["詩筒方訝惠音稀，擊鉢來篇果不遲。", "定欲擅場專獨勝，豈容遺幗久相持。", "招邀近想融樽滿，往返多慚孺榻施。", "况得鸞弦聲出幌，肯教馬足自稽期。"]'),
('8950a387-eebe-4d19-89ef-cf2dbf3a9ab0','凌晨馬上得惠詩再次元韻  其二','韋驤','宋','宋诗','song-poetry','','[]','建芽精嫩鳳爲團，海錯珍鮮鰒作乾。',64,'全唐诗/poet.song.41000.json','["建芽精嫩鳳爲團，海錯珍鮮鰒作乾。", "遠物方慚容易獻，來篇不似等閒看。", "始忻報玖情何厚，幡覺陽春和獨難。", "寫寄中州傳好事，須教紙價踴長安。"]'),
('65796323-2879-4b5f-9a5e-1730d261490c','凌晨馬上得惠詩再次元韻  其三','韋驤','宋','宋诗','song-poetry','','[]','自今酬唱不宜稀，所恨詩盟結已遲。',64,'全唐诗/poet.song.41000.json','["自今酬唱不宜稀，所恨詩盟結已遲。", "兩陣辭鋒謾交戰，一壇將鉞敢争持。", "宦途何愧爲難進，老境寧當效逆施。", "相遇相期情誼遠，莫臨觴詠数瓜期。"]'),
('2e6dbc46-20f0-4ba7-9840-2e36cf45f42e','聞胡琴一首','韋驤','宋','宋诗','song-poetry','','[]','園林雨過秋蕭索，幅巾談笑情方樂。',96,'全唐诗/poet.song.41000.json','["園林雨過秋蕭索，幅巾談笑情方樂。", "歘然一抹四朱弦，續續清聲透簾幕。", "輕攏慢撚手應心，如出自然非以學。", "露蝉凄咽春鶯囀，變化逡巡動寥廊。", "審音度曲肅衆聽，歌舞滿堂生寂寞。", "自嗟投老飲量衰，一舉爲空金鑿落。"]'),
('fb0d048a-dcab-474c-923a-667e768fec0f','書西縣壁','韋驤','宋','宋诗','song-poetry','','[]','判袂知非遠，馳軺約屢經。',24,'全唐诗/poet.song.41000.json','["判袂知非遠，馳軺約屢經。", "猶於暮雲底，回首漢皋亭。"]'),
('58558787-114c-45cc-abae-c973eabc0d82','聞巖起至以詩先寄  其一','韋驤','宋','宋诗','song-poetry','','[]','寶峰亭下菊鮮鮮，嫵媚秋風似可憐。',32,'全唐诗/poet.song.41000.json','["寶峰亭下菊鮮鮮，嫵媚秋風似可憐。", "欲摘一枝分玉盞，星軺莫惜屢揚鞭。"]'),
('baac793c-00de-49c0-b189-aaf2713635c7','聞巖起至以詩先寄  其二','韋驤','宋','宋诗','song-poetry','','[]','公來稅鞅且盤桓，山國蕭條正早寒。',32,'全唐诗/poet.song.41000.json','["公來稅鞅且盤桓，山國蕭條正早寒。", "雖缺鸞弦翻妙曲，聊憑螘酒助清懽。"]'),
('59a0909f-4ac0-454c-8d7d-e41dd0e5b9be','和道中詠懷','韋驤','宋','宋诗','song-poetry','','[]','酒軼劉伶頌，茶高陸羽經。',24,'全唐诗/poet.song.41000.json','["酒軼劉伶頌，茶高陸羽經。", "庶幾延笑語，何事駐長亭。"]'),
('405884d0-1e46-4f84-bc5b-284a5b51d643','和述志','韋驤','宋','宋诗','song-poetry','','[]','振職提三尺，潛心醉六經。',24,'全唐诗/poet.song.41000.json','["振職提三尺，潛心醉六經。", "高材難淺度，豈止獄平亭。"]'),
('60841d8c-728d-4252-8e88-f85aa0fefee9','和念祖','韋驤','宋','宋诗','song-poetry','','[]','仰服籯金訓，傳家在一經。',24,'全唐诗/poet.song.41000.json','["仰服籯金訓，傳家在一經。", "况當聲教遠，夜柝静戎亭。"]'),
('e7935cbe-ce19-4f4e-a02c-bcd128051dee','和庭橘','韋驤','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','常思洞庭橘，美實冠南方。',120,'全唐诗/poet.song.41000.json','["常思洞庭橘，美實冠南方。", "雪蘤千林謝，金衣萬頃黄。", "輝光依澤國，彷彿在仙鄉。", "沈詠滋迎露，韋詩寄待霜。", "遠邦方渴想，鄰圃得清香。", "未用矜封戶，何如助釂觴。", "分甘音尚阻，抽思韻空長。", "豈必三吴渚，寧煩一葦航。", "搘笻即可到，反掌便堪嘗。", "慰我東南夢，殷勤送斐章。"]'),
('4991f8c8-7905-47a9-a7ce-7f27b05e1be1','又和告成寺','韋驤','宋','宋诗','song-poetry','','[]','嘉陵江勢並山迴，山寺雙扉對水開。',64,'全唐诗/poet.song.41000.json','["嘉陵江勢並山迴，山寺雙扉對水開。", "鑿石千尋維佛屋，參天一舉類仙臺。", "白雲有意頻舒卷，幽鳥無情自往來。", "心境兩忘真未易，登臨便謂出塵埃。"]'),
('d6b2ff04-851f-4eb2-bb2b-ea234ef1fa1e','送益鈴高宣事','韋驤','宋','宋诗','song-poetry','','[]','王孫遠器世功勳，材畧縱横舊出倫。',64,'全唐诗/poet.song.41000.json','["王孫遠器世功勳，材畧縱横舊出倫。", "春事近違文陛側，鈴兵遥指錦江濱。", "贈篇累什皆通貴，去國賒程少故人。", "傾蓋相懽一樽酒，感君離思併如新。"]'),
('1de7e2db-3646-48a5-9cf2-0623db3f0f62','過青山','韋驤','宋','宋诗','song-poetry','','[]','遲曉揚鑣陟峻岡，馬蹄凌厲踏新霜。',64,'全唐诗/poet.song.41000.json','["遲曉揚鑣陟峻岡，馬蹄凌厲踏新霜。", "崔嵬昨日參天碧，蕭索今朝滿目黄。", "墮葉離披疑虎跡，曲蹊盤屈類羊腸。", "按行若也多禆補，敢憚崎嶇道路長。"]'),
('4d4773c0-4be8-43c3-9600-421e9afaf1d1','至蒼溪','韋驤','宋','宋诗','song-poetry','','[]','輶軒寒入蒼溪縣，秀句遐追老杜詩。',64,'全唐诗/poet.song.41000.json','["輶軒寒入蒼溪縣，秀句遐追老杜詩。", "送客泛舟空往事，過峰來橘似當時。", "高材遺興千年在，遠宦覊懷萬里隨。", "索筆謾題行館壁，可能閒料後人思。"]'),
('06cb2717-4ad5-44d2-b3e3-8f24d7b2e1ef','自西水還少憩錦屏山廣壽院','韋驤','宋','宋诗','song-poetry','','[]','按行迴轡閬城南，登陟崎嶇力不堪。',32,'全唐诗/poet.song.41000.json','["按行迴轡閬城南，登陟崎嶇力不堪。", "却坐錦屏休倦跡，暑天冰水沃醺酣。"]'),
('c27b258b-771a-41cd-8270-a1073422af74','雲臺觀','韋驤','宋','宋诗','song-poetry','','[]','緣崖涉澗上雲臺，古觀稀逢車馬來。',64,'全唐诗/poet.song.41000.json','["緣崖涉澗上雲臺，古觀稀逢車馬來。", "翠柏逕深長蔽日，玉魚池淺僅勝杯。", "取桃人去無遺跡，鎖藥爐存絕舊灰。", "唯仰天師凛然像，祗愁雙劍起風雷。"]'),
('33ce95ca-0015-47f0-89ef-3047ca14015c','謝巖起惠支頤二首  其一','韋驤','宋','宋诗','song-poetry','','[]','几杖安身外，於茲用智深。',48,'全唐诗/poet.song.41000.json','["几杖安身外，於茲用智深。", "見貽扶倦頷，捧受識仁心。", "本異支離隱，何妨彦祖欽。", "唯愁說詩善，笑解恐難任。"]'),
('eec192cb-ffb1-48a9-aa05-746ff8c18dce','謝巖起惠支頤二首  其二','韋驤','宋','宋诗','song-poetry','','[]','引髭聊試頗安然，正好憑依學坐禅。',32,'全唐诗/poet.song.41000.json','["引髭聊試頗安然，正好憑依學坐禅。", "兒女環觀齊指笑，朱顔猶未怯雙蓮。"]'),
('5d0b9f5e-cfeb-4639-9df2-bfff9e5a1ff9','和蘇進之見招兼簡岑巖起','韋驤','宋','宋诗','song-poetry','','[]','夫君捧詔獨先來，趨節還先數月回。',64,'全唐诗/poet.song.41000.json','["夫君捧詔獨先來，趨節還先數月回。", "聯事已憂將判袂，列城况是未豐財。", "翻蒙雅餞同膚使，更枉清篇費美才。", "若得星軺少聊緩，吐茵强酒不辭陪。"]'),
('f31082bd-672e-4a50-81b0-b50de91b4395','和子方登朝京樓偶成','韋驤','宋','宋诗','song-poetry','','[]','登樓爲喜乍晴時，欲倚欄杆日已微。',64,'全唐诗/poet.song.41000.json','["登樓爲喜乍晴時，欲倚欄杆日已微。", "頭上雲生還作雨，座間風勁却添衣。", "笑言且共須臾樂，氣象休驚頃刻非。", "應是催詩念前况，果然高唱屬先機。"]'),
('aecdf432-0778-43ae-857e-90de81e0569c','再和','韋驤','宋','宋诗','song-poetry','','[]','樓號朝京人未歸，浮雲蔽日雨霏微。',64,'全唐诗/poet.song.41000.json','["樓號朝京人未歸，浮雲蔽日雨霏微。", "静論國手饒棋路，閒喜官身著道衣。", "心慕孟軻潛養浩，年過蘧瑗久知非。", "隨時觴詠聊同樂，全勝區區競巧機。"]'),
('970065b3-6343-4aae-b50a-12d596b6d4a9','再用前韻奉簡','韋驤','宋','宋诗','song-poetry','','[]','未能形德似支離，行學由來恨力微。',64,'全唐诗/poet.song.41000.json','["未能形德似支離，行學由來恨力微。", "罔利唯羞陟龍斷，可言寧念卧牛衣。", "高材幸遇同憂樂，公論相投壹是非。", "待向遊從廢棋局，區區安用謾藏機。"]'),
('f528b5d3-b584-40f4-8ec8-3758ab0ac679','和答前福守林中散','韋驤','宋','宋诗','song-poetry','','[]','使指頻將念匪宜，閩山何敢憚驅馳。',64,'全唐诗/poet.song.41000.json','["使指頻將念匪宜，閩山何敢憚驅馳。", "薦賢鋭意先推鶚，逐惡雄心肯問貍。", "却愧裁篇爲惠重，况當卧轍欲留時。", "光芒照眼觀華藻，遥想張芝墨滿池。"]'),
('35cc91ce-7362-46ca-8f9e-494323f05667','福州古田天王院撤珠軒','韋驤','宋','宋诗','song-poetry','','[]','過顙因人激躍成，撤珠取類亦虚名。',32,'全唐诗/poet.song.41000.json','["過顙因人激躍成，撤珠取類亦虚名。", "偶觀却憶鍾離意，委地當時事獨清。"]'),
('c7fd71ce-0685-432c-b0f0-574fccd3dc4d','謝公永惠荔枝','韋驤','宋','宋诗','song-poetry','','[]','筠籠遠致色猶鮮，咀嚼瓊英真味全。',32,'全唐诗/poet.song.41000.json','["筠籠遠致色猶鮮，咀嚼瓊英真味全。", "多謝仁人憐病渴，故將靈液爽心㾓。"]'),
('7e997186-338a-4961-a5fc-ad41ba772d9c','和子方夜過卧雲庵絕句','韋驤','宋','宋诗','song-poetry','','[]','自愧銀魚久未成，區區從政謾辛勤。',32,'全唐诗/poet.song.41000.json','["自愧銀魚久未成，區區從政謾辛勤。", "過庵佳句撩幽興，待買青山占白雲。"]'),
('8d4d74f7-cb4b-476e-8fb5-fe1137cb3b9e','曹子方静常庵','韋驤','宋','宋诗','song-poetry','','[]','愛君新作静常庵，况是佳名繼鄭南。',64,'全唐诗/poet.song.41000.json','["愛君新作静常庵，况是佳名繼鄭南。", "晝坐不知人擾擾，夜存長保氣酣酣。", "寓言記述睎莊叟，復命棲時慕老聃。", "標榜粲然輝衆目，幾何立懦與廉貪。"]'),
('64b58840-d52c-4bfa-a30a-c03a95d01094','答曹子方少年弄篇翰一首','韋驤','宋','宋诗','song-poetry','','[]','虚堂隱几坐，忽忽若假寐。',212,'全唐诗/poet.song.41000.json','["虚堂隱几坐，忽忽若假寐。", "颯然清風來，頓爾爽昏思。", "新詩執在手，展讀過三四。", "初言少年弄篇翰，喜道白髪聊自戲。", "次驚老境今且迫，豈甘物役汩其志。", "輕視富貴如浮雲，極論窮通鈞一意。", "高談念平時，健句存遠記。", "請老愧襲常，先期乃吾事。", "君年纔知命，耳順予闕二。", "自此七星霜，投紱去朝市。", "是時取高篇，却託冥鴻寄。", "公方處要途，利達沛材智。", "見詩當不嗔，猶認舊書字。", "其來不待索，應亦念衰瘁。", "君年方如我今日，那肯抽簪餌芝术。", "庶幾得以警幽情，莫忘采真揮勁筆。"]'),
('3046ce68-4bca-4c67-b8b2-cf7ab7cb4e6f','遊武夷山二絕  其一','韋驤','宋','宋诗','song-poetry','','[]','泝溪遊覧絕塵紛，看盡奇峰過所聞。',32,'全唐诗/poet.song.41000.json','["泝溪遊覧絕塵紛，看盡奇峰過所聞。", "昔日幔亭何處是，寂寥空想武夷君。"]'),
('c0ea970f-ed6c-41b4-ad89-3a110dffba93','遊武夷山二絕  其二','韋驤','宋','宋诗','song-poetry','','[]','心愛仙山役世緣，乘軺欲去謾留連。',32,'全唐诗/poet.song.41000.json','["心愛仙山役世緣，乘軺欲去謾留連。", "更祈秋日停羲馭，莫遣回頭怨暝烟。"]'),
('5b56448d-2927-454f-844b-4df172c7158c','寄陳安道同年','韋驤','宋','宋诗','song-poetry','','[]','執别都門四見春，悠悠吳越斷音塵。',64,'全唐诗/poet.song.41000.json','["執别都門四見春，悠悠吳越斷音塵。", "爾來雖幸官居近，所得唯蒙手翰頻。", "折桂交遊三紀外，繫匏蹤跡兩溪濱。", "未能把酒論離闊，聊寄篇章託去鱗。"]'),
('eb22d10b-15d8-47ee-a0ce-ee83b038f854','遊武夷山二首  其一','韋驤','宋','宋诗','song-poetry','','[]','一溪秋水碧溶溶，逆掉扁舟遡晚風。',64,'全唐诗/poet.song.41000.json','["一溪秋水碧溶溶，逆掉扁舟遡晚風。", "卧看峰巒聳奇勢，心疑造化炫殊功。", "賓雲曲斷笙簫遠，機石苔荒組織空。", "仙理冥冥難究詰，抽簪歸隱羡劉公。"]'),
('08eb52d3-6836-49a6-8687-77b7478d77b8','遊武夷山二首  其二','韋驤','宋','宋诗','song-poetry','','[]','融結山川鑿混元，誰爲窟宅遺神仙。',64,'全唐诗/poet.song.41000.json','["融結山川鑿混元，誰爲窟宅遺神仙。", "三千曾會幔亭客，十六仍標洞府天。", "崖有珍苞不緣種，棺遺清骨莫知年。", "披圖昔謂多增飾，至此方知畫未全。"]'),
('fb234909-3e82-4e9a-b6ae-a7110dea643e','遊武夷山寄曹子方','韋驤','宋','宋诗','song-poetry','','[]','訪尋仙跡覧羣峰，詰曲清溪兩槳通。',32,'全唐诗/poet.song.41000.json','["訪尋仙跡覧羣峰，詰曲清溪兩槳通。", "幡念不成秋後約，獨遊還與未來同。"]'),
('9983768c-207f-4e35-aebe-5beb8b7731fd','和蔣穎叔重山館留題','韋驤','宋','宋诗','song-poetry','','[]','清詩題柱幾朝曛，二十餘年伴嶺雲。',32,'全唐诗/poet.song.41000.json','["清詩題柱幾朝曛，二十餘年伴嶺雲。", "今夜泥輪猶宿此，隔溪依舊磬聲聞。"]'),
('6f813c5f-389b-4dd9-8873-1d3c0d5c0845','江墩鋪','韋驤','宋','宋诗','song-poetry','','[]','郊原秋老湛無風，孤坐危亭夕照中。',32,'全唐诗/poet.song.41000.json','["郊原秋老湛無風，孤坐危亭夕照中。", "刈熟人歸荷肩重，嘻嘻笑語話年豐。"]'),
('5e787148-b3cb-4320-821b-6925db84fddc','宿泰寧縣驛','韋驤','宋','宋诗','song-poetry','','[]','紞如五鼓響寒廳，夜艾東窗未肯明。',32,'全唐诗/poet.song.41000.json','["紞如五鼓響寒廳，夜艾東窗未肯明。", "一片灘聲聒幽枕，幾番歸夢不能成。"]'),
('e940ea58-fd1b-470d-b4d2-71988f69df8c','離建寧','韋驤','宋','宋诗','song-poetry','','[]','境窮昭武入長汀，溪側山根指去程。',32,'全唐诗/poet.song.41000.json','["境窮昭武入長汀，溪側山根指去程。", "護險欄干紅繚繞，依稀如傍蜀江行。"]'),
('eca3786f-8e55-48c6-950b-586c0e5d77d9','爛石','韋驤','宋','宋诗','song-poetry','','[]','嵌巖爛石聳溪灣，峻削陶人手不閒。',32,'全唐诗/poet.song.41000.json','["嵌巖爛石聳溪灣，峻削陶人手不閒。", "落在深郊猶及此，斧斤何必嘆牛山。"]'),
('c585fcc1-9231-4cce-8f3a-765fea9a8c39','宿寧化縣鷲峰寺','韋驤','宋','宋诗','song-poetry','','[]','輕軺冒雨勢匆匆，晚入幽溪宿鷲峰。',32,'全唐诗/poet.song.41000.json','["輕軺冒雨勢匆匆，晚入幽溪宿鷲峰。", "一夜泉聲繞清榻，夢回何待曉來鐘。"]'),
('6a7ff0c1-daa4-47d3-ae0e-d4fe14f23507','留題龍地巖','韋驤','宋','宋诗','song-poetry','','[]','應龍何日躍天衢，不識還思舊隱無。',32,'全唐诗/poet.song.41000.json','["應龍何日躍天衢，不識還思舊隱無。", "見說至今遺惠在，每興雲雨救焦枯。"]'),
('6bcb9faf-ad75-4be1-835e-153fba421dcf','臨汀行館十月桃花盛開','韋驤','宋','宋诗','song-poetry','','[]','十月臨汀氣候譌，桃花零落發林阿。',32,'全唐诗/poet.song.41000.json','["十月臨汀氣候譌，桃花零落發林阿。", "也知欲趁春風媚，争奈窮州地暖何。"]'),
('da160004-3a74-47fc-b0d8-dbb8a102d280','宿寧化西隱院','韋驤','宋','宋诗','song-poetry','','[]','郵亭地遠宿禪扃，夜永時寒睡思輕。',64,'全唐诗/poet.song.41000.json','["郵亭地遠宿禪扃，夜永時寒睡思輕。", "簷溜不鳴知雨止，窗櫺半白悟天明。", "更攢百點催兵從，雞送三號起使程。", "自愧區區少禆補，北山文在盍留情。"]'),
('5addbf11-d6e0-488c-90b9-05ceeffc5b5f','過鱗原驛','韋驤','宋','宋诗','song-poetry','','[]','晨餐纔了又遄征，驛榜鱗原以地名。',64,'全唐诗/poet.song.41000.json','["晨餐纔了又遄征，驛榜鱗原以地名。", "山頂寒多雪花重，溪灣流淺玉沙明。", "田疇有穫良農喜，社鼓無聲暴客平。", "奉詔非材幸無事，行中時得肆吟情。"]'),
('80ea0dfd-bc78-41bc-8fb5-66e767be3689','度爛溪','韋驤','宋','宋诗','song-poetry','','[]','獨木爲橋度爛溪，溪傍山石爛如泥。',32,'全唐诗/poet.song.41000.json','["獨木爲橋度爛溪，溪傍山石爛如泥。", "高低採削材如一，祗恐鈞陶意不齊。"]'),
('153c803e-e46f-4312-bc54-2658b22d8e20','十月十二日早按行臨汀遇大雷電而雨','韋驤','宋','宋诗','song-poetry','','[]','傳車十月到長汀，鬰奥猶如暑氣生。',64,'全唐诗/poet.song.41000.json','["傳車十月到長汀，鬰奥猶如暑氣生。", "經夕山川带雲霧，凌晨雷雨動簷楹。", "乍逢旅客殊多怪，慣見邦人悄不驚。", "聊作小詩傳所遇，他年稳坐活平生。"]'),
('40f39a79-69e1-4573-b89c-6fe5997b4afb','晚洲嶺','韋驤','宋','宋诗','song-poetry','','[]','行行晚洲嶺，高若離人寰。',144,'全唐诗/poet.song.41000.json','["行行晚洲嶺，高若離人寰。", "肩輿薄層霄，身在杳靄間。", "朝天及青泥，誰謂蜀道難。", "豈如茲峻陟，不類羊腸盤。", "斗上五千尺，步步須躋攀。", "隆冬猶汗浃，睥睨唯心寒。", "旁霑宿雲潤，下視飛鳥閒。", "恍如陶公夢，插翼衝天關。", "潛慕漢忠臣，叱馭毋盤桓。", "古語固有之，酖毒比宴安。", "君恩思未報，何敢惮險艱。", "臨風一長吟，所嘆兩鬢斑。"]'),
('5ac5275e-c836-46b9-b10c-7a33414e35d9','師子峰','韋驤','宋','宋诗','song-poetry','','[]','欲將師子號奇峰，蹲踞如真倚碧空。',32,'全唐诗/poet.song.41000.json','["欲將師子號奇峰，蹲踞如真倚碧空。", "聞說近山無虎嘯，可非潛伏畏威風。"]'),
('7c62fec5-2f9f-49ac-9aae-0c2eadbe6637','雙溪驛','韋驤','宋','宋诗','song-poetry','','[]','按程頗自覺淹留，朝夕經行處處幽。',32,'全唐诗/poet.song.41000.json','["按程頗自覺淹留，朝夕經行處處幽。", "忻逢古驛雙溪水，追憶東陽八詠樓。"]'),
('80be9c49-4e77-44f3-b119-279aa51817f8','陰山館','韋驤','宋','宋诗','song-poetry','','[]','圜峰聳於前，鳴泉繞其背。',24,'全唐诗/poet.song.41000.json','["圜峰聳於前，鳴泉繞其背。", "若使畫成圖，誰云非傅會。"]'),
('63bc4a0d-d0c1-416e-a45c-596fd775471c','遊寶蓋巖','韋驤','宋','宋诗','song-poetry','','[]','度溪履險得幽巖，欲去徘徊意尚貪。',32,'全唐诗/poet.song.41000.json','["度溪履險得幽巖，欲去徘徊意尚貪。", "吏部祝融峰下句，未宜留此付鐫鑱。"]'),
('50e2edd5-9818-4eae-8443-418e9e3ac018','題館節堂','韋驤','宋','宋诗','song-poetry','','[]','建陽溪水接仙流，溪上新堂氣象幽。',64,'全唐诗/poet.song.41000.json','["建陽溪水接仙流，溪上新堂氣象幽。", "弭節柅輪從便適，觀風問俗得優游。", "凌虛岌岌圍千嶂，據要衝衝控八州。", "白髪書生倦奔走，每憐瀟灑爲遲留。"]'),
('089a027c-dfc8-490d-b636-1ad5e40a5bfb','寄曹子方','韋驤','宋','宋诗','song-poetry','','[]','度溪踰嶺一何勞，霜鬢鬅鬙首屢搔。',64,'全唐诗/poet.song.41000.json','["度溪踰嶺一何勞，霜鬢鬅鬙首屢搔。", "自愧晚年空碌碌，唯逢佳境且陶陶。", "會仙古觀風流遠，館節新堂氣象豪。", "不得與君同嘯傲，强抽荒思引吟毫。"]'),
('2d181c4d-ec5b-45e2-a805-4ed9cfb6344b','再和','韋驤','宋','宋诗','song-poetry','','[]','佳和殊堪渴想勞，幅巾霜鬢遂忘搔。',64,'全唐诗/poet.song.41000.json','["佳和殊堪渴想勞，幅巾霜鬢遂忘搔。", "長言燦燦經三復，至樂融融共一陶。", "遇事未能全吏隱，解頤幸得接詩豪。", "願前瓜代頻酬唱，任秃秋蟾玉兔毫。"]'),
('d2b32f24-5e89-41fb-8c00-6f13243bb6f4','和曹子方','韋驤','宋','宋诗','song-poetry','','[]','遶舍方憐喜鵲鳴，臨風更聽振金聲。',64,'全唐诗/poet.song.41000.json','["遶舍方憐喜鵲鳴，臨風更聽振金聲。", "戅兒遠宦趨庭過，善友新篇擊鉢成。", "荒學謾傳烏足道，嘉辭借譽一何榮。", "鳳毛池上他年貴，謙晦終難掩道耕。"]'),
('3129d49a-be28-42ac-ba65-3753f1d21cad','和子方贈祖夷仲提刑','韋驤','宋','宋诗','song-poetry','','[]','蓬莱爲别幾秋風，倅乘當年服狥公。',64,'全唐诗/poet.song.41000.json','["蓬莱爲别幾秋風，倅乘當年服狥公。", "梁漢曾嗟失高躅，甌閩幸遲擴前功。", "稅車白髪相看喜，把酒黄堂一笑同。", "行見刑清八州境，里言應不詠垣東。"]'),
('382474b8-c918-46f0-90eb-50c1bd8796c2','冬至三日遊水南諸寺','韋驤','宋','宋诗','song-poetry','','[]','曦輪飛上宿雲收，晚出城南趣適幽。',64,'全唐诗/poet.song.41000.json','["曦輪飛上宿雲收，晚出城南趣適幽。", "六寺連延行複道，一溪縈繞瀉寒流。", "世情共喜新陽復，仙境聊成極目遊。", "不以篇章記登覧，此時清興若爲酬。"]'),
('6a84ff45-df17-4207-a197-c79de3f9d61c','次韻和公舒太守長至遊水南僧寺','韋驤','宋','宋诗','song-poetry','','[]','紛華盛麗已心灰，蠟履尋山尚喜陪。',64,'全唐诗/poet.song.41000.json','["紛華盛麗已心灰，蠟履尋山尚喜陪。", "聊藉琴樽樂清景，全勝車馬冒黄埃。", "年登况畢三時務，陽復仍忻七日來。", "更愛啟予傳秀句，使君詩筆富天才。"]'),
('783516b3-5e54-41bb-8105-054c15017194','送曹子方','韋驤','宋','宋诗','song-poetry','','[]','判袂長亭歲律殘，天寒雲靄慘溪山。',64,'全唐诗/poet.song.41000.json','["判袂長亭歲律殘，天寒雲靄慘溪山。", "間關唯恐君兼道，寂寞仍愁我獨還。", "秀句八州神物護，輕軺千里老人攀。", "他時企想音書外，佇聽休聲聳近班。"]'),
('3d543851-759a-4944-8ed1-44a66d83d971','護國院十詠 雷分石','韋驤','宋','宋诗','song-poetry','','[]','聞說豐隆爲剖開，非關星隕自天來。',32,'全唐诗/poet.song.41000.json','["聞說豐隆爲剖開，非關星隕自天來。", "數齊元凱峥嶸勢，不是尋常作削材。"]'),
('9b8ef936-bd16-4d24-8d31-dde4fb7eb97c','護國院十詠 香爐峰','韋驤','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','由來元化作鈞陶，賦象香爐峰勢高。',32,'全唐诗/poet.song.41000.json','["由來元化作鈞陶，賦象香爐峰勢高。", "恰似羌廬山下見，不容太白獨抽毫。"]'),
('3de8aee6-4229-45e7-9d88-a0bd147dfa0c','護國院十詠 天然橋','韋驤','宋','宋诗','song-poetry','','[]','欲渡銀潢上九霄，回頭雲路正迢迢。',32,'全唐诗/poet.song.41000.json','["欲渡銀潢上九霄，回頭雲路正迢迢。", "誰知畧彴由天造，全勝間關履鵲橋。"]'),
('8e2df85e-a7b9-41b3-9989-3d55eeefead3','護國院十詠 玉印峰','韋驤','宋','宋诗','song-poetry','','[]','拂雲蒼翠勢嶔崟，玉印分明带秀林。',32,'全唐诗/poet.song.41000.json','["拂雲蒼翠勢嶔崟，玉印分明带秀林。", "變化固非緣堕鵲，天将寶玩鎮幽深。"]'),
('49e18fed-1a2b-42b4-8e76-9db59bbaf14c','護國院十詠 石鑑峰','韋驤','宋','宋诗','song-poetry','','[]','天悟迷人亦自然，團團石鏡爲高懸。',32,'全唐诗/poet.song.41000.json','["天悟迷人亦自然，團團石鏡爲高懸。", "潛令演若狂心止，忘照回情學坐禪。"]'),
('3fcae234-f60b-41c0-9885-6a6de0f30027','護國院十詠 蟄龍潭','韋驤','宋','宋诗','song-poetry','','[]','蟄龍潭上木陰森，百丈垂絲未度深。',32,'全唐诗/poet.song.41000.json','["蟄龍潭上木陰森，百丈垂絲未度深。", "蟠屈只應如傅說，俟時騰躍作商霖。"]'),
('6b65926b-f499-4365-bbc8-2f3e94b38a9d','護國院十詠 放生池','韋驤','宋','宋诗','song-poetry','','[]','看收数罟買鮮鱗，縱在深池是亦仁。',32,'全唐诗/poet.song.41000.json','["看收数罟買鮮鱗，縱在深池是亦仁。", "但使校人誠子産，自然微物遂天真。"]'),
('8051a098-0dc2-4b6a-ba9d-cd8b4ae187a3','護國院十詠 鳳凰山','韋驤','宋','宋诗','song-poetry','','[]','鳳凰山色似晴光，半入青雲兩翅張。',32,'全唐诗/poet.song.41000.json','["鳳凰山色似晴光，半入青雲兩翅張。", "誰謂太平寧有象，峰巒猶學瑞禽翔。"]'),
('4e2c2590-b17b-4b0c-a1bb-87b5845fa4aa','護國院十詠 鎖翠屏','韋驤','宋','宋诗','song-poetry','','[]','屏名鎖翠勢彎環，境勝全疑出世間。',32,'全唐诗/poet.song.41000.json','["屏名鎖翠勢彎環，境勝全疑出世間。", "枕石眠雲乃其地，誰能先向此中閒。"]'),
('ef0b5837-443c-4532-8f0b-efb7951fe6e2','護國院十詠 仙茆峰','韋驤','宋','宋诗','song-poetry','','[]','餌茆仙去絕遺蹤，屹屹孤峰倚碧空。',32,'全唐诗/poet.song.41000.json','["餌茆仙去絕遺蹤，屹屹孤峰倚碧空。", "空使時人想飈馭，寸心長惑有無中。"]'),
('ea672c08-2404-40c4-9cea-e84c9c836851','次韻推官東庵','韋驤','宋','宋诗','song-poetry','','[]','紫竹交陰處，微行接小軒。',48,'全唐诗/poet.song.41000.json','["紫竹交陰處，微行接小軒。", "轆轤聲在井，薜荔翠依垣。", "自有山林趣，何妨鳥雀喧。", "公餘聊宴坐，方寸得澄源。"]'),
('3460ce22-7a12-4730-901a-12507d3aee46','步雲亭','韋驤','宋','宋诗','song-poetry','','[]','官居瀟灑並城壖，城上危亭勢屹然。',64,'全唐诗/poet.song.41000.json','["官居瀟灑並城壖，城上危亭勢屹然。", "庨豁四簷通日月，回環千里見山川。", "凌虛迥絕尋常地，据要追吟尺五天。", "莫訝白雲隨步起，望中祠宇指梅仙。"]'),
('d5494caf-87a9-4437-b6b9-c18e105b49b4','又和李世美再題步雲亭','韋驤','宋','宋诗','song-poetry','','[]','嶢嶢氣勢壓南閩，彷彿鵬程近紫氛。',64,'全唐诗/poet.song.41000.json','["嶢嶢氣勢壓南閩，彷彿鵬程近紫氛。", "女堞却依丹檻底，翬簷迥與碧霄分。", "融樽有地留清景，阮屐無時蹴亂雲。", "引脰更勞西北望，子牟馳戀繼朝曛。"]'),
('25e566e3-c977-416e-a2d1-231152dd9d47','和世美久雨枕上偶成','韋驤','宋','宋诗','song-poetry','','[]','釡中何慮致魚生，庭下寧論輟運瓴。',64,'全唐诗/poet.song.41000.json','["釡中何慮致魚生，庭下寧論輟運瓴。", "夜厭繁聲驚夢枕，朝愁潤色浥書屏。", "無聊搔首憐垂白，遣興題詩寫殺青。", "此段公居正岑寂，還如舊隱掩柴扃。"]'),
('ae393f43-b63e-475f-97a0-20909756cd8a','又和久雨','韋驤','宋','宋诗','song-poetry','','[]','繼月霖霪勢不停，淙淙高屋似翻瓴。',64,'全唐诗/poet.song.41000.json','["繼月霖霪勢不停，淙淙高屋似翻瓴。", "氣昏亭閣迷仙境，雲闇山川掩畫屏。", "壠麥潛憂化蛾白，溪荷遥想没錢青。", "占晴問蔡師前語，罄折恭於奉鼎扃。"]'),
('53fa7251-b318-4b97-a8d4-3ea8f20ba795','晚晴','韋驤','宋','宋诗','song-poetry','','[]','積雨鎖山城，幡然喜晚晴。',48,'全唐诗/poet.song.41000.json','["積雨鎖山城，幡然喜晚晴。", "園林變新綠，溝澮有餘聲。", "日色間何闊，雲陰否已傾。", "無才希杜賦，短句且紓情。"]'),
('70fb1b7e-48eb-45f7-93ff-1f5f1b9dd51e','紅蕉','韋驤','宋','宋诗','song-poetry','','[]','紅蕉秀南土，對植燕堂陰。',48,'全唐诗/poet.song.41000.json','["紅蕉秀南土，對植燕堂陰。", "每爲開青眼，唯憐吐赤心。", "華丹天賦異，彫瘁歲寒深。", "擬奪蘭荃譽，慇懃約共吟。"]'),
('29c807e1-bcbd-4b49-8a84-caaf3d8128b5','和劉公舒題步雲亭','韋驤','宋','宋诗','song-poetry','','[]','締構岧嶤倚碧空，建安氣象矚清雄。',64,'全唐诗/poet.song.41000.json','["締構岧嶤倚碧空，建安氣象矚清雄。", "自矜遠目窮天末，更喜新篇入彀中。", "壇指昇仙歎梅福，山連夢筆想文通。", "梯雲每到如平地，養勇何須羡北宫。"]'),
('5f8521d5-117c-4f2d-a286-2f72612e3083','五月三日見萱草一枝','韋驤','宋','宋诗','song-poetry','','[]','薄薄初陽曉霧披，庭萱再見似相知。',64,'全唐诗/poet.song.41000.json','["薄薄初陽曉霧披，庭萱再見似相知。", "月臨仲夏纔三日，風折今年第一枝。", "蘤翦兼金黄灼爍，幹瑳圓玉碧參差。", "韶華來歲應如舊，知在何州記此時。"]'),
('499bcf08-79e1-47a2-a523-aa917a159db0','和世美吉祥爲别','韋驤','宋','宋诗','song-poetry','','[]','山驛迢迢畏景舒，星軺不肯少躊躇。',64,'全唐诗/poet.song.41000.json','["山驛迢迢畏景舒，星軺不肯少躊躇。", "先之古寺圖分袂，故約前騶幸柅車。", "霧卷茗甌分啜罷，風收談麈贈言餘。", "雖知暫别非踰月，尚覬郵筒數惠書。"]'),
('f6e1e26b-3353-4f58-afb3-e3139c09f01a','又次韻慶除代','韋驤','宋','宋诗','song-poetry','','[]','一封黄牒下雲頭，受代需時若自謀。',64,'全唐诗/poet.song.41000.json','["一封黄牒下雲頭，受代需時若自謀。", "雖幸有期趨北闕，自慚無術惠南州。", "累年塵土甘祗役，萬里烟霄想告猷。", "猶頼高材見禆助，不教孤跡謾淹留。"]'),
('022236cf-1418-4e8f-8f72-886358280a6f','去冬留題管節堂世美朝請今夏按部過之爲詩見賁輙次韻奉和','韋驤','宋','宋诗','song-poetry','','[]','拙句慚先刻，佳章幸繼遊。',48,'全唐诗/poet.song.41000.json','["拙句慚先刻，佳章幸繼遊。", "褒題踰八字，傳詠入中州。", "舍館仍增麗，時炎倐變秋。", "悠悠想清思，長似建溪流。"]'),
('df3c87d8-4b64-4ff3-9282-483b7d6238fa','世美朝請賢友近按昭武還寵示道中雜詩十三首因成拙句奉呈','韋驤','宋','宋诗','song-poetry','','[]','衝蒙盛暑歷山川，膚使何嘗嘆獨賢。',64,'全唐诗/poet.song.41000.json','["衝蒙盛暑歷山川，膚使何嘗嘆獨賢。", "星騎逡巡一千里，仙才灑落十三篇。", "籠羅絕頂裁詩句，攄發高情破萬緣。", "但恨陽春難繼和，暗投終辨夜光圓。"]'),
('de6f5815-13e6-4402-afcb-d942d6a147f9','荔子','韋驤','宋','宋诗','song-poetry','','[]','閩地高材最傑然，結成丹荔冒炎天。',64,'全唐诗/poet.song.41000.json','["閩地高材最傑然，結成丹荔冒炎天。", "堆盤火齊光芒轉，溜齒瓊漿氣味全。", "玉井蓮房空賦咏，秀江萍實謾流傳。", "更咍蜀品煩馳傳，闇向紅塵動笑妍。"]'),
('31608c0b-5e2e-4d61-8a39-ba1f6a9c5be5','與世美奉詔旨分督决獄甲戌判袂之武陽壬午還宿中興寺而得世美自延平所寄詩因次韻','韋驤','宋','宋诗','song-poetry','','[]','盛暑宵憂動邃旒，敕催諸道决纍囚。',64,'全唐诗/poet.song.41000.json','["盛暑宵憂動邃旒，敕催諸道决纍囚。", "承流宣澤彌兢愓，履險航湍敢滯留。", "南北分馳纔數夕，重輕釋繋已三州。", "高材想盡哀矜意，美疢當從勿藥瘳。"]'),
('c7d3cbe3-2a21-416f-93cc-321be0ed5ee0','八月上澣登步雲亭','韋驤','宋','宋诗','song-poetry','','[]','一日優閒九日忙，步雲亭上共翺翔。',64,'全唐诗/poet.song.41000.json','["一日優閒九日忙，步雲亭上共翺翔。", "地高始覺秋風勁，事隙方知晝景長。", "戲舉禪談一重案，静看茶戰第三湯。", "吾民况有京坻望，遠宦宜從嘯咏忘。"]'),
('37565633-ce83-467d-b37e-3713863b20f1','中秋夜雨','韋驤','宋','宋诗','song-poetry','','[]','秋色中分夜氣清，月華今夕最澄明。',64,'全唐诗/poet.song.41000.json','["秋色中分夜氣清，月華今夕最澄明。", "如何驟雨横來勢，不徇高樓倚望情。", "桂子飄零無處覓，燭花煇燄爲時生。", "莫辭盡醉酬佳節，猶覬餘光接曉晴。"]'),
('ca7deb82-7158-4695-87f7-06fb747d2dc3','公舒朝請得福守所寄荔子佳品二而咏以二詩乃以爲示輙次韻奉和  其一','韋驤','宋','宋诗','song-poetry','','[]','鄰境緘馳荔子丹，黄堂矜詫滿雕盤。',64,'全唐诗/poet.song.41000.json','["鄰境緘馳荔子丹，黄堂矜詫滿雕盤。", "香收殘爇餘龍腦，牋寫新詩掩鳳團。", "咀嚼定嫌瓊液薄，形容更比水精寒。", "强抽滯思聊追和，珍果清吟兩可歡。"]'),
('40addae5-92d2-4e13-a8b6-c4ecdc143055','公舒朝請得福守所寄荔子佳品二而咏以二詩乃以爲示輙次韻奉和  其二','韋驤','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','佛宫奇品號磂黄，黄縠籠珠徑寸光。',64,'全唐诗/poet.song.41000.json','["佛宫奇品號磂黄，黄縠籠珠徑寸光。", "種異却輕萍有實，味甘全勝蔗爲漿。", "南人拭目驚稀見，北客流涎試一嘗。", "翻笑洞庭霜後橘，豈能當暑侑持觴。"]'),
('7eb15a6f-b2dd-4a0a-9456-daec2e98b082','建安郡庠重彩記事','韋驤','宋','宋诗','song-poetry','','[]','泮水秋深爽氣全，簪紳戾止共拳拳。',64,'全唐诗/poet.song.41000.json','["泮水秋深爽氣全，簪紳戾止共拳拳。", "丹青圖寫三千禮，藻繪形容七十賢。", "如堵聿來觀盛集，采芹應有賦新篇。", "諸生好進公卿業，此日風流亦與傳。"]'),
('56a20689-7bbd-4eae-8c87-ca2a4ec618f7','九日示壽隆  其一','韋驤','宋','宋诗','song-poetry','','[]','九日閩中氣尚暄，扶持病體坐家筵。',64,'全唐诗/poet.song.41000.json','["九日閩中氣尚暄，扶持病體坐家筵。", "喜看數朵黄金菊，强引三分白玉船。", "浮世謾論軒冕貴，佳辰難遇子孫圓。", "明年汝對陶公菊，應念欣欣戲綵前。"]'),
('aa084c69-f575-4dd0-8883-6b13f6877f17','九日示壽隆  其二','韋驤','宋','宋诗','song-poetry','','[]','建安山水亦幾希，九日登高著處宜。',64,'全唐诗/poet.song.41000.json','["建安山水亦幾希，九日登高著處宜。", "秋杪風光自瀟灑，老來情味少歡怡。", "舉杯喜見黄花泛，落帽羞将白髪吹。", "佳節不能成酩酊，浪吟小杜昔年詩。"]'),
('368f2f3d-38bf-4dca-ba18-c996e0faf93d','留題南劍州延平閣','韋驤','宋','宋诗','song-poetry','','[]','危閣横空待勝遊，登臨盡道冠南州。',64,'全唐诗/poet.song.41000.json','["危閣横空待勝遊，登臨盡道冠南州。", "面分列嶂環羣秀，坐看雙溪會一流。", "斜納朝暉長易旦，逆消暑氣每先秋。", "更傳寶劍深潭近，半夜寒光射斗牛。"]'),
('0588653e-3bb4-4f8e-9806-e9e6d1d4d991','冷風閣','韋驤','宋','宋诗','song-poetry','','[]','勝概天成所得偏，一来登覧興飄然。',64,'全唐诗/poet.song.41000.json','["勝概天成所得偏，一来登覧興飄然。", "拂雲欄楯塵寰遠，隔水樓臺畫幅全。", "隱隱歸舟搖落日，悠悠飛鳥破孤烟。", "冷風可御非虛目，况是層巒對演仙。"]'),
('eec5c104-346d-47cd-acc2-16d3aa554c74','題尤溪縣林平鋪壁','韋驤','宋','宋诗','song-poetry','','[]','前歲方離蜀道難，崎嶇今日過黄山。',32,'全唐诗/poet.song.41000.json','["前歲方離蜀道難，崎嶇今日過黄山。", "自嗟使事殊無補，祇向塵途歷險難。"]'),
('d800ac42-6a2a-4c6c-b9b5-1d28b750edaf','題黯淡灘','韋驤','宋','宋诗','song-poetry','','[]','慎操舟檝度危灘，脫險從安反掌間。',32,'全唐诗/poet.song.41000.json','["慎操舟檝度危灘，脫險從安反掌間。", "豈似俗流争利達，難防笑貎伏波瀾。"]'),
('d51e0938-1499-4fa3-8a56-1e0d85f2f4c9','將到富沙寄世美同事','韋驤','宋','宋诗','song-poetry','','[]','判袂于今涉五旬，馳驅無復寓書頻。',64,'全唐诗/poet.song.41000.json','["判袂于今涉五旬，馳驅無復寓書頻。", "險途頓失往還倦，高誼却忻朝夕親。", "近事欲蘄祛蔽塞，新吟應許和清純。", "富沙此去無多地，先走詩筒致所陳。"]'),
('e11f86a1-439f-4a85-a898-d74f1a73c915','和劉公舒見示生日詩','韋驤','宋','宋诗','song-poetry','','[]','衰遲何幸枉佳章，遠引吾宗及漢唐。',64,'全唐诗/poet.song.41000.json','["衰遲何幸枉佳章，遠引吾宗及漢唐。", "戶掛桑蓬當日喜，毫揮珠玉此時光。", "欣臨愛景披辭藻，怯向清飈動鬢霜。", "松柏由來交茂悦，願回善頌歲寒芳。"]'),
('0d76df68-cc0e-4239-a102-302ce87a6ff8','和李世美見寄兼送推官宰彭澤','韋驤','宋','宋诗','song-poetry','','[]','北風傳曉角，宿霧鎖寒城。',48,'全唐诗/poet.song.41000.json','["北風傳曉角，宿霧鎖寒城。", "秣馬登途早，將雛振羽輕。", "一經承祖訓，百里儆官成。", "多謝龍門秀，貽詩壮去程。"]'),
('47a0d685-9c66-4419-b05b-d4e1b4222d35','又和道中書事奉懷','韋驤','宋','宋诗','song-poetry','','[]','同日分携去，先期掉鞅迴。',48,'全唐诗/poet.song.41000.json','["同日分携去，先期掉鞅迴。", "馳情隨道遠，殘歲怯春催。", "客舍驚新柳，山城嘆落梅。", "佳篇慰翹望，還馭過王臺。"]'),
('2f014cb0-2162-4383-bb56-e165b89903e7','和劉守正月十日新茶','韋驤','宋','宋诗','song-poetry','','[]','乳霧浮浮啜新茗，祇疑春自壑原來。',64,'全唐诗/poet.song.41000.json','["乳霧浮浮啜新茗，祇疑春自壑原來。", "開筵人日踰三晝，試焙申年第一杯。", "首面光肥香已透，輔車津潤味全回。", "不須七碗清風至，滿盞依稀在楚臺。"]'),
('c8a9e5f3-dc70-46eb-92c5-17a6c55865e1','和正月十七日攜具見約','韋驤','宋','宋诗','song-poetry','','[]','遠宦隨時且自娱，看看受代又脂車。',64,'全唐诗/poet.song.41000.json','["遠宦隨時且自娱，看看受代又脂車。", "燃燈初過忘岑寂，極目相從接緒餘。", "瘴霧催花錦零亂，春風吹鬢雪稀疏。", "追懷古語成新詠，萬事無非酒破除。"]'),
('a6408ca7-e653-429c-a5af-c122915cb6e6','又和','韋驤','宋','宋诗','song-poetry','','[]','著處山川秀可娱，何妨投隙數驅車。',64,'全唐诗/poet.song.41000.json','["著處山川秀可娱，何妨投隙數驅車。", "韶華已過三分一，歲律纔經半月餘。", "北海樽罍雖自滿，東陽篇詠不宜疏。", "惟愁南國春多雨，誰把繁陰爲掃除。"]'),
('ae7b4154-4c13-4231-9a7a-0c1efeef107b','和世美以前韻惠詩','韋驤','宋','宋诗','song-poetry','','[]','東亭清集幸相娱，暮角聲休尚柅車。',64,'全唐诗/poet.song.41000.json','["東亭清集幸相娱，暮角聲休尚柅車。", "冷淡蓮光燈夕後，微茫桂魄雨天餘。", "交談自喜高情合，投老還嗟樂事疏。", "况是離懷起朝夕，好憑樽酒豫驅除。"]'),
('7aff8cfb-c434-4b91-9832-21920527d96b','南園正月二十三日見牡丹因翦分送而公舒太守以詩爲報遂次來韻','韋驤','宋','宋诗','song-poetry','','[]','上元八日冒輕寒，翦送南園兩牡丹。',64,'全唐诗/poet.song.41000.json','["上元八日冒輕寒，翦送南園兩牡丹。", "爲我果能興絕唱，知君不作等閒看。", "香餘琱檻春猶淺，詠入華牋墨未乾。", "更說僧坊曾寄植，縱觀須待解征鞍。"]'),
('04fd6f19-ea81-4af6-9e97-8c00661e1307','和世美行役不與貢第一茶','韋驤','宋','宋诗','song-poetry','','[]','採鳳團龍貢紫宸，今年斗柄僅離寅。',64,'全唐诗/poet.song.41000.json','["採鳳團龍貢紫宸，今年斗柄僅離寅。", "四千里望中天闕，第一番題北苑春。", "拜表盡恭初遣使，乘軺還念未歸人。", "太平歲集梯航獻，山岳何如此效珍。"]'),
('27521832-c22d-4849-9875-63f523c20c32','又和督决囚','韋驤','宋','宋诗','song-poetry','','[]','旰食憂民睿思焦，默懷時雪滯層霄。',64,'全唐诗/poet.song.41000.json','["旰食憂民睿思焦，默懷時雪滯層霄。", "十行新下寛囚詔，諸道交馳奉使軺。", "縲紲稀疏至恩浃，旄倪歡感大鈞調。", "宣揚德澤慚綿弱，但採堯民撃壤謡。"]'),
('a0daf19a-fcaf-44f2-9182-32bcc9b60c51','和劉守以詩約賞南園牡丹','韋驤','宋','宋诗','song-poetry','','[]','閒花浪蕊謾芬敷，滿檻妖韶體自殊。',64,'全唐诗/poet.song.41000.json','["閒花浪蕊謾芬敷，滿檻妖韶體自殊。", "且看淡紅隨分有，須知絕品此中無。", "翦愁魏國掺掺手，辨怯齊門一一竽。", "已掃幽亭待清賞，更煩佳句預相娱。"]'),
('83297273-dfba-4ad1-b83e-eeb190f5abf6','别劉公舒','韋驤','宋','宋诗','song-poetry','','[]','間關杖節使全閩，何幸邦侯遇故人。',64,'全唐诗/poet.song.41000.json','["間關杖節使全閩，何幸邦侯遇故人。", "談笑一樽時得暇，謳歌千里政如春。", "解攜白髪情非昔，贈别清篇思入神。", "却想萍蹤流未遠，會看飛詔趣朱輪。"]'),
('6fb9dd8f-4947-46bc-b2c5-ab3473a795f4','出閩境永豐道中','韋驤','宋','宋诗','song-poetry','','[]','去暮愁行泗州嶺，清晨喜見江東山。',64,'全唐诗/poet.song.41000.json','["去暮愁行泗州嶺，清晨喜見江東山。", "二年巡按勞南走，盡室安全慶北還。", "負弩兵迴喧渡口，插秧人看立田間。", "却嗟奉使無禆補，征返徒添兩鬢斑。"]'),
('8f59f4f6-b995-47cb-a7b8-a8de1339ac12','道中聞鶯','韋驤','宋','宋诗','song-poetry','','[]','棲止垂楊最上枝，綠絲深罩鬰金衣。',32,'全唐诗/poet.song.41000.json','["棲止垂楊最上枝，綠絲深罩鬰金衣。", "也知行客留心聽，弄盡新聲始肯飛。"]'),
('1f8e4bd5-592a-414d-9957-c47eeae76828','水碓','韋驤','宋','宋诗','song-poetry','','[]','杵臼功能自古施，更堪引水代人爲。',32,'全唐诗/poet.song.41000.json','["杵臼功能自古施，更堪引水代人爲。", "誰知滿溢傾欹處，却是臨機效力時。"]'),
('9b9b63cf-1973-4a02-997d-4e0ca98c17cd','滕龍圖挽詞','韋驤','宋','宋诗','song-poetry','','[]','踐歷清華四十年，老成忽逐逝波遷。',64,'全唐诗/poet.song.41000.json','["踐歷清華四十年，老成忽逐逝波遷。", "鹽梅未展和羮效，裘带終淹分閫權。", "忠義長爲古人比，功名固有史臣傳。", "不材曾附風雷末，遠寓哀辭倍泫然。"]'),
('60de1ea9-78b1-484c-9767-5dcda2ff9153','送孫聖微同年赴浙漕  其一','韋驤','宋','宋诗','song-poetry','','[]','當時折桂共雲梯，四十餘年跡久睽。',64,'全唐诗/poet.song.41000.json','["當時折桂共雲梯，四十餘年跡久睽。", "白首爲郎方接武，繡衣出使又分携。", "放船汴水寒猶淺，跋馬都門日欲低。", "遠想清風播仁聞，融融先滿浙東西。"]'),
('3af993fd-e8c1-4751-938e-96df9341681b','送孫聖微同年赴浙漕  其二','韋驤','宋','宋诗','song-poetry','','[]','雄勝東南越與吴，光華使節暫馳驅。',64,'全唐诗/poet.song.41000.json','["雄勝東南越與吴，光華使節暫馳驅。", "比年郡邑多疲俗，今日朝廷用老儒。", "固有風聲鎮媮薄，何妨膏澤慰焦枯。", "公餘且盡登臨興，嚴召終難緩走趨。"]'),
('2f97f599-12c5-4d92-bd3f-2b23862cf27f','張大資挽詞  其一','韋驤','宋','宋诗','song-poetry','','[]','峥嶸儀貎國輝光，曾與明堂作棟梁。',64,'全唐诗/poet.song.41000.json','["峥嶸儀貎國輝光，曾與明堂作棟梁。", "顓面鉅藩方偃息，間生英氣忽飄揚。", "文章絕筆星辰晦，德業遺芳簡冊香。", "不以修齡畀賢傑，傷嗟無處問蒼蒼。"]'),
('963ecf81-2bd0-4f77-8792-ca54bae636fa','張大資挽詞  其二','韋驤','宋','宋诗','song-poetry','','[]','熙載功成鬢未華，蕃宣屢易見褒嘉。',64,'全唐诗/poet.song.41000.json','["熙載功成鬢未華，蕃宣屢易見褒嘉。", "鳳池舊别經年久，鶴馭新乘去路賒。", "哀挽聲悽霜月冷，銘旌影轉曉風斜。", "故山歸葬依先壠，千古悠悠賢世家。"]'),
('c1e31e10-d40f-45ec-b11c-9a20855ccb9c','送莫和中刑部致仕歸吳興','韋驤','宋','宋诗','song-poetry','','[]','司刑華省健精神，容易飛章便乞身。',64,'全唐诗/poet.song.41000.json','["司刑華省健精神，容易飛章便乞身。", "未老先休多有志，似君勇退幾何人。", "安車漸遠京塵路，歸棹仍追霅水春。", "而我區區尚持祿，自慚鄉境謾爲鄰。"]'),
('10e831c3-9224-47c0-b708-bb4182fd9af1','大行太皇太后挽詞  其一','韋驤','宋','宋诗','song-poetry','','[]','德業高千古，憂勤盡九年。',48,'全唐诗/poet.song.41000.json','["德業高千古，憂勤盡九年。", "捲簾将復辟，弛衛忽登仙。", "飲泣均中外，流恩在幅員。", "春風低挽唱，幽咽厚陵邊。"]'),
('96cf65ec-07c6-4133-94db-a8f4d718219a','大行太皇太后挽詞  其二','韋驤','宋','宋诗','song-poetry','','[]','臨朝扶聖治，盛烈掩姜任。',48,'全唐诗/poet.song.41000.json','["臨朝扶聖治，盛烈掩姜任。", "壽享堯齡淺，哀添舜慕深。", "靈衣粲翬翟，謚冊刻球琳。", "仰望軒星晦，悽愁萬國心。"]'),
('1f5ceeb9-9d8d-4136-b899-64d03204e3a7','和劉公儀郎中對雪','韋驤','宋','宋诗','song-poetry','','[]','九陌塵埃變玉沙，雲中雙闕陋仙家。',64,'全唐诗/poet.song.41000.json','["九陌塵埃變玉沙，雲中雙闕陋仙家。", "豐年欲啟三登兆，大巧先裁六出花。", "高卧洛陽逢汲引，雄文梁苑動吁嗟。", "郎闈自愧徒温飽，坐擁炎爐歎歲華。"]'),
('3cdc3f1a-a210-400b-b9f5-56cdc7d9dd71','和劉公儀省宿呈同舍','韋驤','宋','宋诗','song-poetry','','[]','夜宿冰廳愁解衣，南宫正是苦寒時。',64,'全唐诗/poet.song.41000.json','["夜宿冰廳愁解衣，南宫正是苦寒時。", "窗含積雪猶明几，爐撥殘煤始捲帷。", "無所忸怩當俯仰，不須容易嘆衰遲。", "更爲佳句貽同舍，使我揮毫羨色絲。"]'),
('025fdcc9-d707-4a93-9399-2277911f9dcc','次夕宿省再用前韻呈同舍','韋驤','宋','宋诗','song-poetry','','[]','凛烈寒威著寢衣，中臺獨宿夜分時。',64,'全唐诗/poet.song.41000.json','["凛烈寒威著寢衣，中臺獨宿夜分時。", "郎潛已嘆斑馮鬢，幼學空思下董帷。", "直舍孤燈生暈淺，禁垣清漏送聲遲。", "何年追語今宵事，笑向江湖理釣絲。"]'),
('560ce7aa-5e70-493b-8c89-bb60017688b5','再次韻和公儀所示','韋驤','宋','宋诗','song-poetry','','[]','匆匆下馬脱朝衣，夜直儀曹歲晏時。',64,'全唐诗/poet.song.41000.json','["匆匆下馬脱朝衣，夜直儀曹歲晏時。", "香穗縈回清一榻，燭花明媚耀重帷。", "詩成白雪音難和，夢斷黄粱熟已遲。", "見說遲明還剡奏，懇求宫鑰待言絲。"]'),
('ca02f3b9-6978-42a4-a0d9-aa88df4ec938','和公儀索和詩','韋驤','宋','宋诗','song-poetry','','[]','唱酬三峡浪飛花，敏捷曾蒙秀句誇。',64,'全唐诗/poet.song.41000.json','["唱酬三峡浪飛花，敏捷曾蒙秀句誇。", "爲感來篇驚歲暮，因成閣筆待春華。", "見斑固已慚窺豹，失酒當須鍳畫蛇。", "鄙思强抽追險韻，還如策蹇度褒斜。"]'),
('7aaccb5a-5b37-44e1-aba7-10b9651c957c','又和憶小園梅花','韋驤','宋','宋诗','song-poetry','','[]','爲憶新梅發舊枝，勇操吟筆對晴暉。',64,'全唐诗/poet.song.41000.json','["爲憶新梅發舊枝，勇操吟筆對晴暉。", "幽香不到青綾被，冷豔應迷白羽衣。", "忽忽屢經春色改，紛紛或傍笛聲飛。", "祗疑渴想高情劇，頻向冰廳有夢歸。"]'),
('2ac0a93d-5ed2-4d83-9aa4-9fd11150af98','和喻明仲題純粹大師虚一軒詩','韋驤','宋','宋诗','song-poetry','','[]','聞說琳公最佳處，榜題虚一一軒清。',64,'全唐诗/poet.song.41000.json','["聞說琳公最佳處，榜題虚一一軒清。", "逍遥羽客真高隱，曠達星郎肯謾名。", "琴挂無弦藏至樂，爐存微火鎖長生。", "未能投步資閒適，聊和新詩託寄聲。"]'),
('f0ba8991-7373-40aa-9a46-5cba8bff81fc','次韻和陳圖南見喜權金部','韋驤','宋','宋诗','song-poetry','','[]','綠槐經午轉庭陰，投隙相過省闥深。',64,'全唐诗/poet.song.41000.json','["綠槐經午轉庭陰，投隙相過省闥深。", "且喜清談共揮麈，莫嗟白髪各盈簪。", "鄰曹暫幸聯官樂，兼局那辭冗事侵。", "更辱高吟叙情舊，侑歡何必濁醪斟。"]'),
('3d60f430-3cf1-4f3c-a145-5bdc8012bad9','又次韻','韋驤','宋','宋诗','song-poetry','','[]','詩將争功定繹騷，堂堂風格等劉曹。',64,'全唐诗/poet.song.41000.json','["詩將争功定繹騷，堂堂風格等劉曹。", "高情迭唱通三歎，險語相先較一毫。", "酷暑俄驚變瀟灑，噪蟬何敢助雄豪。", "嗟予老拙慵牽强，飬勇終憐不目逃。"]'),
('4d7e331c-54b1-43ae-b16a-84a5d8630645','送孔彦常待制赴宣城','韋驤','宋','宋诗','song-poetry','','[]','宣城從古號名城，新拜除書擁旆旌。',64,'全唐诗/poet.song.41000.json','["宣城從古號名城，新拜除書擁旆旌。", "剡奏屢傳求外補，偃藩暫得遂高情。", "虎符南國先聲重，鷁首秋江去意清。", "最好笳鐃將壓境，敬亭山色遠相迎。"]'),
('0156b911-ea8c-4eb2-9bad-3d27f37f86a3','又和義夫學士用其韻','韋驤','宋','宋诗','song-poetry','','[]','開府南陵氣序秋，翠屏千壘對岑樓。',64,'全唐诗/poet.song.41000.json','["開府南陵氣序秋，翠屏千壘對岑樓。", "力宣膏澤均千里，坐賞溪山冠十州。", "小謝篇章耐吟諷，謫仙蹤跡自風流。", "公餘好盡登臨興，應誚區區宋玉愁。"]'),
('cd350136-67a3-43cb-9a27-3e5a8a0c2e56','胡右丞挽詞','韋驤','宋','宋诗','song-poetry','','[]','右轄辭榮重寄分，却趨召節造天閽。',64,'全唐诗/poet.song.41000.json','["右轄辭榮重寄分，却趨召節造天閽。", "表儀八座方尊德，悃愊連章乞偃藩。", "將見辨嚴離鳳闕，忽傳感疾自鴒原。", "公薨不及期頤壽，至理冥冥豈易論。"]'),
('305017d7-7dc2-439e-a8db-b662b7f043be','鄧左丞開府挽詞','韋驤','宋','宋诗','song-poetry','','[]','術學材猷間世資，進登丞轄僅踰時。',64,'全唐诗/poet.song.41000.json','["術學材猷間世資，進登丞轄僅踰時。", "壽非德稱天何吝，命與心違古所悲。", "一品衰榮加贈典，九重震悼輟班儀。", "靈輿還葬從先壠，嗚咽秋風薤露辭。"]'),
('9b9dc13b-6476-4a38-9544-609b62a73bb7','和盛中叔侍郎齋宿唱酬','韋驤','宋','宋诗','song-poetry','','[]','誰謂南宫夜直頻，宿齋清集迥難親。',64,'全唐诗/poet.song.41000.json','["誰謂南宫夜直頻，宿齋清集迥難親。", "翼朝唯幸窺新什，三紀尤欣叙古人。", "共慶球琳已華國，獨慚樗散謾先春。", "更将鄙句追詩戰，蓋耻弢弓託負薪。"]'),
('822730f5-cb6e-471b-8047-7876cd159fd2','嘗進酒','韋驤','宋','宋诗','song-poetry','','[]','昔年北苑試龍茶，似陟雲霄飲露華。',64,'全唐诗/poet.song.41000.json','["昔年北苑試龍茶，似陟雲霄飲露華。", "今日禮曹嘗御酒，又疑塵跡到仙家。", "自知衮衮官身幸，莫向區區俚耳誇。", "此段出於尸祿外，支離形體更何加。"]'),
('23a52988-a1c5-4d6f-b173-428a293857a4','柵山驛早起','韋驤','宋','宋诗','song-poetry','','[]','柵山孤驛夜寒清，襆被㸐柴坐遲明。',64,'全唐诗/poet.song.41000.json','["柵山孤驛夜寒清，襆被㸐柴坐遲明。", "行旆動時紅日上，肩舁經處白雲生。", "連峰峭怪濃鋪翠，流水盤紆數送聲。", "自喜區區王事外，縱觀佳境有餘情。"]'),
('85f58b46-4cd4-4402-b7c3-a70157e49122','望崖上遺構','韋驤','宋','宋诗','song-poetry','','[]','萬仞蒼崖聳碧空，誰爲危室撼雲中。',32,'全唐诗/poet.song.41000.json','["萬仞蒼崖聳碧空，誰爲危室撼雲中。", "雙扉虚闢無人到，疑是飛仙逞妙工。"]'),
('8ddaea91-6648-4649-be4d-b517d05576f6','四十八渡','韋驤','宋','宋诗','song-poetry','','[]','山盤水轉路岐開，揭厲凡經六八回。',32,'全唐诗/poet.song.41000.json','["山盤水轉路岐開，揭厲凡經六八回。", "若向芳春桃盛發，幾何非自武陵來。"]'),
('5fb56c42-521f-4736-a3fb-bd5abfc735e4','送劉公儀典四明','韋驤','宋','宋诗','song-poetry','','[]','人間離合固尋常，契義稠重豈易忘。',64,'全唐诗/poet.song.41000.json','["人間離合固尋常，契義稠重豈易忘。", "崇政青春同擢第，文昌白首並爲郎。", "東城判袂情懷慘，南國分符興味長。", "唯佇來風慰瞻望，治聲當不減龔黄。"]'),
('c15c9875-8496-4704-889b-6821d093fc33','和何子温郎中家園一首','韋驤','宋','宋诗','song-poetry','','[]','江河清興渺無邊，又睹新詩憶故園。',64,'全唐诗/poet.song.41000.json','["江河清興渺無邊，又睹新詩憶故園。", "仙爪雖欣搔癢背，布音還愧過雷門。", "祇聞松石誇朋舊，應免紛華遺子孫。", "何日幅巾陪燕坐，共將風月快吟魂。"]'),
('7491b48a-c88f-4ecd-bbce-7bdf5c4e4455','自峽之夔過竹竿山','韋驤','宋','宋诗','song-poetry','','[]','行路始知難，覆盆千石間。',48,'全唐诗/poet.song.41000.json','["行路始知難，覆盆千石間。", "爲逃人鮓甕，敢憚竹竿山。", "晚日羣峰碧，春風兩鬢班。", "何時似都護，還度玉門關。"]'),
('ba3da93a-0adc-4772-9fb1-9371a12f6bf1','答宋茂宗詩卷','韋驤','宋','宋诗','song-poetry','','[]','夔府春殘暫息肩，感君佳遺意飄然。',64,'全唐诗/poet.song.41000.json','["夔府春殘暫息肩，感君佳遺意飄然。", "頓忘巇嶮三千路，爲得風騷五十篇。", "山水清音歸老筆，球琳秀氣滿新編。", "雖無健句酬來貺，終日吟哦興自全。"]'),
('ef6a9e16-0fdc-4a67-8142-339f6661464a','宿雲安雲巖寺','韋驤','宋','宋诗','song-poetry','','[]','去國三千里，攜家四十程。',24,'全唐诗/poet.song.41000.json','["去國三千里，攜家四十程。", "雲巖暫投宿，聊使夢魂清。"]'),
('61185aa9-cbe9-4fe6-a863-1bf910c0a1e7','雨中觀白蓮一首','韋驤','宋','宋诗','song-poetry','','[]','終日飄零酷暑平，白蓮池上獨含情。',64,'全唐诗/poet.song.41000.json','["終日飄零酷暑平，白蓮池上獨含情。", "已憐瑩潔添花色，更愛淋浪打葉聲。", "宫女洗妝餘粉澤，水仙欹弁濯瓊瑛。", "漫攜玉盞銜冰酒，氣味須教一等清。"]'),
('2c8d7e22-af78-482d-bd1a-3759ba51e4d3','讀潘閬再過錢塘一絕','韋驤','宋','宋诗','song-poetry','','[]','昔年潘閬足詩情，曾過錢塘眼暫明。',32,'全唐诗/poet.song.41000.json','["昔年潘閬足詩情，曾過錢塘眼暫明。", "今日天涯聞此句，無窮鄉思逐江聲。"]'),
('a77e5763-fb91-4df7-9047-1d5c45e1feda','和答韓循之送行詩','韋驤','宋','宋诗','song-poetry','','[]','歸隱無田計未成，區區叱馭又遄征。',64,'全唐诗/poet.song.41000.json','["歸隱無田計未成，區區叱馭又遄征。", "自慚白首猶尸祿，何補清時漫遠行。", "談麈追思揮玉色，送篇珍重發金聲。", "欲知天末相望處，雲水蒼茫白帝城。"]'),
('6d708d83-121a-48b7-b295-5f946ba6007a','和答劉子先舍人送行詩','韋驤','宋','宋诗','song-poetry','','[]','梯險航深岐路賒，國恩未報敢咨嗟。',64,'全唐诗/poet.song.41000.json','["梯險航深岐路賒，國恩未報敢咨嗟。", "感公秀句渾驚俗，送我孤蹤遠使巴。", "民訟稀疏幾吏隱，官居岑寂似山家。", "舉頭霄漢思賢躅，聊和來篇示拜嘉。"]'),
('708b6c13-a9be-4fa5-8683-a0f031afd35c','明恕齋','韋驤','宋','宋诗','song-poetry','','[]','明恕題標榜，心隨目所瞻。',48,'全唐诗/poet.song.41000.json','["明恕題標榜，心隨目所瞻。", "平反長在念，燕適自無嫌。", "山氣清朝幌，江光射晝簷。", "幾何非吏隱，危坐興難厭。"]'),
('d5663af9-f8e8-452d-89ec-a3d42b42aa81','中秋夜待月不見一首','韋驤','宋','宋诗','song-poetry','','[]','中秋待月異尋常，桂魄如何特晦藏。',64,'全唐诗/poet.song.41000.json','["中秋待月異尋常，桂魄如何特晦藏。", "疑是天心忌盈滿，故將雲影蔽輝光。", "徬徨注目瞻霄漢，冷落呼燈照豆觴。", "須記今宵有餘恨，明年此會莫輕忘。"]'),
('128a9ca9-f2f3-432b-a611-83d469daf856','寄明守劉公儀','韋驤','宋','宋诗','song-poetry','','[]','去年更直宿文昌，今日暌違各一方。',64,'全唐诗/poet.song.41000.json','["去年更直宿文昌，今日暌違各一方。", "遐想四明安坐府，肯思三峽險乘航。", "恨無羽翼親談席，應有笙歌簇燕堂。", "舊好未宜因遠廢，郵筒時且寄篇章。"]'),
('679b60f5-a02f-4488-bc4a-2f33479c705a','九日','韋驤','宋','宋诗','song-poetry','','[]','重九蕭條秋已深，登高更在蜀江潯。',64,'全唐诗/poet.song.41000.json','["重九蕭條秋已深，登高更在蜀江潯。", "黄花未肯趁時吐，白酒祇如常日斟。", "絕塞煙雲長滿目，故園風物愈關心。", "須憑酩酊酬佳節，追感齊山不浪吟。"]'),
('3ddae2ce-00fd-4813-bda0-ce5c3dff0b69','宿縉雲僧舍一首','韋驤','宋','宋诗','song-poetry','','[]','石磴躋攀上縉雲，九峰蒼翠與天鄰。',64,'全唐诗/poet.song.41000.json','["石磴躋攀上縉雲，九峰蒼翠與天鄰。", "巖崖佛屋疑神助，煙靄禪扃絕世塵。", "此日乘軺宿寒夜，他年屈指數青春。", "山僧莫笑匆匆去，尋勝能來有幾人。"]'),
('c67199d7-6be9-4672-b3f4-ff86bbdc2561','過温湯寺一絕','韋驤','宋','宋诗','song-poetry','','[]','一竇飛泉煖似湯，池魚無數自洋洋。',32,'全唐诗/poet.song.41000.json','["一竇飛泉煖似湯，池魚無數自洋洋。", "不須遶寺尋碑刻，知是南平古道場。"]'),
('eaca9cb6-1f83-434a-8c7e-96e2206be600','武龍道中','韋驤','宋','宋诗','song-poetry','','[]','四十年前前進士，三千里外外官人。',32,'全唐诗/poet.song.41000.json','["四十年前前進士，三千里外外官人。", "手提邦憲平冤抑，敢不公心報大鈞。"]'),
('242ab57e-a88c-4ef8-b68e-4a2141c5b22d','放船一首','韋驤','宋','宋诗','song-poetry','','[]','崢嶸歲垂盡，泛鷁下岷江。',144,'全唐诗/poet.song.41000.json','["崢嶸歲垂盡，泛鷁下岷江。", "鳴櫓風聲壯，搖旌日影雙。", "巨灘何累累，急鼓促韸韸。", "語疾軀生翼，論危頸縮腔。", "栖遲憑漆几，睥睨近紗窗。", "解纜侵朝霧，休程傍晚矼。", "童山連岌岌，古木競摐摐。", "岑絕行荒縣，間關按列邦。", "俗書慵注目，薄酒倦開缸。", "仙跡徒追羡，名篇乃素降。", "有誰陪亹亹，竟夕聽淙淙。", "幽興將詩遣，還嗟語意厖。"]'),
('3c625250-457f-4049-806f-cecb11611d7d','正月二日飲茂宗官舍一首','韋驤','宋','宋诗','song-poetry','','[]','然燈數百照青樽，香穗縈回酒半醺。',32,'全唐诗/poet.song.41000.json','["然燈數百照青樽，香穗縈回酒半醺。", "却怪預爲元夕態，撩人鄉思亂紛紛。"]'),
('cdcce296-347a-4a09-9531-3236afb95ec6','咏八仙 撚鼻','韋驤','宋','宋诗','song-poetry','','[]','道氣本冲融，胡爲撚鼻中。',24,'全唐诗/poet.song.41000.json','["道氣本冲融，胡爲撚鼻中。", "知無願言嚏，聊以快吾衷。"]'),
('7c129259-f844-48d2-9698-96a414370cb3','咏八仙 爬背','韋驤','宋','宋诗','song-poetry','','[]','刻成纖手利，癢背可施功。',24,'全唐诗/poet.song.41000.json','["刻成纖手利，癢背可施功。", "豈待麻姑爪，攜持意自通。"]'),
('8bf26c53-4ca4-49bd-a97a-37f97adb379b','咏八仙 呵欠','韋驤','宋','宋诗','song-poetry','','[]','引手如雙翼，俄然一欠伸。',24,'全唐诗/poet.song.41000.json','["引手如雙翼，俄然一欠伸。", "須臾端顧盼，别是好精神。"]'),
('8a4f26d6-0180-4ff1-b823-27d538a5f71e','咏八仙 櫛髪','韋驤','宋','宋诗','song-poetry','','[]','搔首意不滿，聊憑象櫛功。',24,'全唐诗/poet.song.41000.json','["搔首意不滿，聊憑象櫛功。", "高情唯自適，豈恤鬢如蓬。"]'),
('b7f01496-347e-4619-9633-4198a76ddde1','咏八仙 鼓琴','韋驤','宋','宋诗','song-poetry','','[]','萬事不關心，悠悠在一琴。',24,'全唐诗/poet.song.41000.json','["萬事不關心，悠悠在一琴。", "非山亦非水，何必問知音。"]'),
('63d92d3f-4856-44ac-9612-edc400734444','咏八仙 吹簫','韋驤','宋','宋诗','song-poetry','','[]','內樂本無聲，吹簫且任情。',24,'全唐诗/poet.song.41000.json','["內樂本無聲，吹簫且任情。", "於兹代長嘯，自是一般清。"]'),
('a95d629f-a16d-46de-a71d-63f7f5e44856','咏八仙 横笛','韋驤','宋','宋诗','song-poetry','','[]','不是樂繁音，吹揚興自深。',24,'全唐诗/poet.song.41000.json','["不是樂繁音，吹揚興自深。", "數盃醇酎罷，更學水龍吟。"]'),
('6790c8a3-ca4a-4f96-b315-d9520525cc63','咏八仙 撚耳','韋驤','宋','宋诗','song-poetry','','[]','撚耳意陽陽，林泉白晝長。',24,'全唐诗/poet.song.41000.json','["撚耳意陽陽，林泉白晝長。", "市朝聲自遠，聰聽又何妨。"]'),
('3dca1a1f-12c6-4060-a0c6-e3b33a3f7eed','丁承受放目亭一首','韋驤','宋','宋诗','song-poetry','','[]','擇地爲亭智思全，飛甍如翼插蒼煙。',64,'全唐诗/poet.song.41000.json','["擇地爲亭智思全，飛甍如翼插蒼煙。", "身栖一哄喧聲外，目逆千山秀色邊。", "臘雪春葩饒映带，峽雲江月每流連。", "所嗟此境藏夔府，不入當年子美篇。"]'),
('02d9cf7c-31f2-4568-b16c-948a6e2cd72e','人日太寧道中一首','韋驤','宋','宋诗','song-poetry','','[]','改年三日立青春，涉七風光日日新。',64,'全唐诗/poet.song.41000.json','["改年三日立青春，涉七風光日日新。", "列岫漸生千靄媚，幽禽初弄小聲勻。", "籃輿度嶺官兵汗，紅旆穿林野雉馴。", "白髪自憐猶遠使，何時歸棹浙江濱。"]'),
('4b4c4690-8f2e-4bc1-bf56-3e840c2a6b9f','白帝祠一絕','韋驤','宋','宋诗','song-poetry','','[]','瞿塘峽口江聲急，古木陰中白帝祠。',32,'全唐诗/poet.song.41000.json','["瞿塘峽口江聲急，古木陰中白帝祠。", "猶有餘靈憑險阻，往來舟楫禱安危。"]'),
('0666b0cf-f142-448c-be1a-3a2836c57ff4','奉節道中望羣山有雪','韋驤','宋','宋诗','song-poetry','','[]','臘去春來只數朝，遠山殘雪未全消。',64,'全唐诗/poet.song.41000.json','["臘去春來只數朝，遠山殘雪未全消。", "崑岡玉出清光瑩，滄海潮横白浪遥。", "天外畫圖終日展，雲端仙佩許誰邀。", "長途極目添幽興，更折寒梅渡野橋。"]'),
('d7fda51c-6c27-4d3d-9617-f3c3783647d4','和劉公儀見寄','韋驤','宋','宋诗','song-poetry','','[]','崎嶇巴峽走單車，瀟灑鄞江想載旟。',64,'全唐诗/poet.song.41000.json','["崎嶇巴峽走單車，瀟灑鄞江想載旟。", "馳款比追前日好，開緘忽奉去年書。", "篇章互及情皆見，蹤跡相暌義不疏。", "但使鱗鴻勿虛過，何須臨紙恨躊躇。"]'),
('74f93683-6634-45b9-92af-dd95ea6a8e89','忠州木蓮花二絕','韋驤','宋','宋诗','song-poetry','','[]','喬木開花似水蓮，畫圖遠自昔人傳。',64,'全唐诗/poet.song.41000.json','["喬木開花似水蓮，畫圖遠自昔人傳。", "化工既許殊凡品，落在遐方亦可憐。", "綠葉枝頭灼爍紅，尚疑輕易比芙蓉。", "根苗不自污泥出，只合移栽近佛宫。"]'),
('1e82f3a8-b328-411d-a316-0f5ff6002f14','寄明守劉公儀','韋驤','宋','宋诗','song-poetry','','[]','海角天涯相去遥，郵筒還往勢迢迢。',64,'全唐诗/poet.song.41000.json','["海角天涯相去遥，郵筒還往勢迢迢。", "兩篇佳咏兼金重，三復長吟萬慮銷。", "已向宦途驚聚散，休將桂籍論榮彫。", "承誇倒載清歡數，使我流涎鄉思搖。"]'),
('66920860-c492-45b1-b2a4-7221ef90aa81','擺繡雞  其一','韋驤','宋','宋诗','song-poetry','','[]','異質本難馴，金籠擺繡頻。',48,'全唐诗/poet.song.41000.json','["異質本難馴，金籠擺繡頻。", "文華真出類，舒卷速如神。", "怒角雙枝翠，垂緌九葉新。", "燕堂春晝永，注目屢逡巡。"]');
